-- Poems batch 431
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('yuding-9','唐享昊天樂：第八','武則天','唐','御定全唐诗','yuding','','[]','奠璧郊壇昭大禮，鏘金拊石表虔誠。',32,'御定全唐詩/json/005.json','["奠璧郊壇昭大禮，鏘金拊石表虔誠。", "始奏承雲娛帝賞，複歌調露暢韶英。"]'),
('yuding-10','唐享昊天樂：第九','武則天','唐','御定全唐诗','yuding','','[]','荷恩承顧托，執契恭臨撫。廟略靜邊荒，天兵曜神武。',48,'御定全唐詩/json/005.json','["荷恩承顧托，執契恭臨撫。廟略靜邊荒，天兵曜神武。", "有截資先化，無為遵舊矩。禎符降昊穹，大業光寰宇。"]'),
('yuding-11','唐享昊天樂：第十','武則天','唐','御定全唐诗','yuding','','[]','肅肅祀典，邕邕禮秩。三獻已周，九成斯畢。',40,'御定全唐詩/json/005.json','["肅肅祀典，邕邕禮秩。三獻已周，九成斯畢。", "爰撤其俎，載遷其實。或升或降，惟誠惟質。"]'),
('yuding-12','唐享昊天樂：第十一','武則天','唐','御定全唐诗','yuding','','[]','禮終肆類，樂闋九成。仰惟明德，敢薦非馨。',40,'御定全唐詩/json/005.json','["禮終肆類，樂闋九成。仰惟明德，敢薦非馨。", "顧慚菲奠，久馳雲輧。瞻荷靈澤，悚戀兼盈。"]'),
('yuding-13','唐享昊天樂：第十二','武則天','唐','御定全唐诗','yuding','','[]','式乾路，辟天扉。回日馭，動雲衣。',32,'御定全唐詩/json/005.json','["式乾路，辟天扉。回日馭，動雲衣。", "登金闕，入紫微。望仙駕，仰恩徽。"]'),
('yuding-14','唐明堂樂章：外辦將出','武則天','唐','御定全唐诗','yuding','','[]','總章陳昔典，衢室禮惟神。巨集規則天地，神用葉陶鈞。',49,'御定全唐詩/json/005.json','["總章陳昔典，衢室禮惟神。巨集規則天地，神用葉陶鈞。", "負扆三春旦，充庭萬宇賓。顧己誠虛薄，空慚馭兆人。"]'),
('yuding-15','唐明堂樂章：皇帝行','武則天','唐','御定全唐诗','yuding','','[]','仰膺歷數，俯順謳歌。遠安邇肅，俗阜時和。',40,'御定全唐詩/json/005.json','["仰膺歷數，俯順謳歌。遠安邇肅，俗阜時和。", "化光玉鏡，訟息金科。方興典禮，永戢干戈。"]'),
('yuding-16','唐明堂樂章：皇嗣出入升降','武則天','唐','御定全唐诗','yuding','','[]','至人光俗，大孝通神。謙以表性，恭惟立身。',40,'御定全唐詩/json/005.json','["至人光俗，大孝通神。謙以表性，恭惟立身。", "洪規載啟，茂典方陳。譽隆三善，祥開萬春。"]'),
('yuding-17','唐明堂樂章：迎送王公','武則天','唐','御定全唐诗','yuding','','[]','千官肅事，萬國朝宗。載延百辟，爰集三宮。',40,'御定全唐詩/json/005.json','["千官肅事，萬國朝宗。載延百辟，爰集三宮。", "君臣德合，魚水斯同。睿圖方永，周曆長隆。"]'),
('yuding-18','唐明堂樂章：登歌','武則天','唐','御定全唐诗','yuding','','[]','禮崇宗祀，志表嚴禋。笙鏞合奏，文物惟新。',40,'御定全唐詩/json/005.json','["禮崇宗祀，志表嚴禋。笙鏞合奏，文物惟新。", "敬遵茂典，敢擇良辰。絜誠斯著，奠謁方申。"]'),
('yuding-19','唐明堂樂章：配饗','武則天','唐','御定全唐诗','yuding','','[]','笙鏞間玉宇，文物昭清輝。晬影臨芳奠，休光下太微。',36,'御定全唐詩/json/005.json','["笙鏞間玉宇，文物昭清輝。晬影臨芳奠，休光下太微。", "孝思期有感，明絜庶無違。"]'),
('yuding-20','唐明堂樂章：宮音','武則天','唐','御定全唐诗','yuding','','[]','履艮包群望，居中冠百靈。萬方資廣運，庶品荷財成。',48,'御定全唐詩/json/005.json','["履艮包群望，居中冠百靈。萬方資廣運，庶品荷財成。", "神功諒匪測，盛德實難名。藻奠申誠敬，恭祀表惟馨。"]'),
('yuding-21','唐明堂樂章：角音','武則天','唐','御定全唐诗','yuding','','[]','出震位，開平秩。扇條風，乘甲乙。',32,'御定全唐詩/json/005.json','["出震位，開平秩。扇條風，乘甲乙。", "龍德盛，鳥星出。薦珪篚，陳誠實。"]'),
('yuding-22','唐明堂樂章：征音','武則天','唐','御定全唐诗','yuding','','[]','赫赫離精禦炎陸，滔滔熾景開隆暑。',32,'御定全唐詩/json/005.json','["赫赫離精禦炎陸，滔滔熾景開隆暑。", "冀延神鑒俯蘭尊，式表虔襟陳桂俎。"]'),
('yuding-23','唐明堂樂章：商音','武則天','唐','御定全唐诗','yuding','','[]','律中夷則，序應收成。功宣建武，義表惟明。',40,'御定全唐詩/json/005.json','["律中夷則，序應收成。功宣建武，義表惟明。", "爰申禮奠，庶展翹誠。九秋是式，百穀斯盈。"]'),
('yuding-24','唐明堂樂章：羽音','武則天','唐','御定全唐诗','yuding','','[]','葭律肇啟隆冬，蘋藻攸陳饗祭。',28,'御定全唐詩/json/005.json','["葭律肇啟隆冬，蘋藻攸陳饗祭。", "黃鐘既陳玉燭，紅粒方殷稔歲。"]'),
('yuding-25','唐大饗拜洛樂章：昭和','武則天','唐','御定全唐诗','yuding','','[]','九玄眷命，三聖基隆。奉成先旨，明台畢功。',40,'御定全唐詩/json/005.json','["九玄眷命，三聖基隆。奉成先旨，明台畢功。", "宗祀展敬，冀表深衷。永昌帝業，式播淳風。"]'),
('yuding-26','唐大饗拜洛樂章：致和','武則天','唐','御定全唐诗','yuding','','[]','神功不測兮運陰陽，包藏萬宇兮孕八荒。',36,'御定全唐詩/json/005.json','["神功不測兮運陰陽，包藏萬宇兮孕八荒。", "天符既出兮帝業昌，願臨明祀兮降禎祥。"]'),
('yuding-27','唐大饗拜洛樂章：咸和','武則天','唐','御定全唐诗','yuding','','[]','坎澤祠容備舉，坤壇祭典爰申。靈眷遙行秘躅，',28,'御定全唐詩/json/005.json','["坎澤祠容備舉，坤壇祭典爰申。靈眷遙行秘躅，", "方期交際懸應。"]'),
('yuding-28','唐大饗拜洛樂章：九和','武則天','唐','御定全唐诗','yuding','','[]','祗荷坤德，欽若干靈。慚惕罔置，興居匪寧。',40,'御定全唐詩/json/005.json','["祗荷坤德，欽若干靈。慚惕罔置，興居匪寧。", "恭崇禮則，肅奉儀形。惟憑展敬，敢薦非馨。"]'),
('yuding-29','唐大饗拜洛樂章：拜洛','武則天','唐','御定全唐诗','yuding','','[]','菲躬承睿顧，薄德忝坤儀。幹幹遵後命，翼翼奉先規。',48,'御定全唐詩/json/005.json','["菲躬承睿顧，薄德忝坤儀。幹幹遵後命，翼翼奉先規。", "撫俗勤雖切，還淳化尚虧。未能弘至道，何以契明祇。"]'),
('yuding-30','唐大饗拜洛樂章：顯和','武則天','唐','御定全唐诗','yuding','','[]','顧德有慚虛菲，明祇屢降禎符。汜水初呈秘象，',21,'御定全唐詩/json/005.json','["顧德有慚虛菲，明祇屢降禎符。汜水初呈秘象，"]'),
('yuding-31','唐大饗拜洛樂章：昭和','武則天','唐','御定全唐诗','yuding','','[]','舒雲致養，合大資生。德以恒固，功由永貞。',40,'御定全唐詩/json/005.json','["舒雲致養，合大資生。德以恒固，功由永貞。", "升歌薦序，垂幣翹誠。虹開玉照，鳳引金聲。"]'),
('yuding-32','唐大饗拜洛樂章：敬和','武則天','唐','御定全唐诗','yuding','','[]','蘭俎既升，蘋羞可薦。金石載設，咸英已變。',40,'御定全唐詩/json/005.json','["蘭俎既升，蘋羞可薦。金石載設，咸英已變。", "林澤斯總，山川是遍。敢用敷誠，實惟忘倦。"]'),
('yuding-33','唐大饗拜洛樂章：齊和','武則天','唐','御定全唐诗','yuding','','[]','沉潛演貺分三極，廣大凝禎總萬方。',32,'御定全唐詩/json/005.json','["沉潛演貺分三極，廣大凝禎總萬方。", "既薦羽旌文化啟，還呈幹戚武威揚。"]'),
('yuding-34','唐大饗拜洛樂章：德和','武則天','唐','御定全唐诗','yuding','','[]','夕惕同龍契，晨兢當鳳扆。崇儒習舊規，偃伯循先旨。',48,'御定全唐詩/json/005.json','["夕惕同龍契，晨兢當鳳扆。崇儒習舊規，偃伯循先旨。", "絕壤飛冠蓋，遐區麗山水。幸承三聖餘，忻屬千年始。"]'),
('yuding-35','唐大饗拜洛樂章：禋和','武則天','唐','御定全唐诗','yuding','','[]','百禮崇容，千官肅事。靈降舞兆，神凝有粹。',40,'御定全唐詩/json/005.json','["百禮崇容，千官肅事。靈降舞兆，神凝有粹。", "奠享咸周，威儀畢備。奏夏登列，歌雍撤肆。"]'),
('yuding-36','唐大饗拜洛樂章：通和','武則天','唐','御定全唐诗','yuding','','[]','皇皇靈眷，穆穆神心。暫動凝質，還歸積陰。',40,'御定全唐詩/json/005.json','["皇皇靈眷，穆穆神心。暫動凝質，還歸積陰。", "功玄樞紐，理寂高深。銜恩佩德，聳志翹襟。"]'),
('yuding-37','唐大饗拜洛樂章：歸和','武則天','唐','御定全唐诗','yuding','','[]','言旋雲洞兮躡煙塗，永寧中宇兮安下都。',36,'御定全唐詩/json/005.json','["言旋雲洞兮躡煙塗，永寧中宇兮安下都。", "包涵動植兮順榮枯，長貽寶貺兮贊璿圖。"]'),
('yuding-38','唐大饗拜洛樂章：歸和','武則天','唐','御定全唐诗','yuding','','[]','調雲闋兮神座興，驂雲駕兮儼將升。',32,'御定全唐詩/json/005.json','["調雲闋兮神座興，驂雲駕兮儼將升。", "騰絳霄兮垂景祜，翹丹懇兮荷休征。"]'),
('yuding-39','唐武氏享先廟樂章','武則天','唐','御定全唐诗','yuding','','[]','先德謙撝冠昔，嚴規節素超今。奉國忠誠每竭，',42,'御定全唐詩/json/005.json','["先德謙撝冠昔，嚴規節素超今。奉國忠誠每竭，", "既迫王公屢請，方乃俯遂群心。有限無由展敬，"]'),
('yuding-40','早春夜宴','武則天','唐','御定全唐诗','yuding','','[]','九春開上節，千門敞夜扉。蘭燈吐新焰，桂魄朗圓輝。',48,'御定全唐詩/json/005.json','["九春開上節，千門敞夜扉。蘭燈吐新焰，桂魄朗圓輝。", "送酒惟須滿，流杯不用稀。務使霞漿興，方乘泛洛歸。"]'),
('yuding-41','游九龍潭','武則天','唐','御定全唐诗','yuding','','[]','山窗游玉女，澗戶對瓊峰。岩頂翔雙鳳，潭心倒九龍。',48,'御定全唐詩/json/005.json','["山窗游玉女，澗戶對瓊峰。岩頂翔雙鳳，潭心倒九龍。", "酒中浮竹葉，杯上寫芙蓉。故驗家山賞，惟有風入松。"]'),
('yuding-42','贈胡天師','武則天','唐','御定全唐诗','yuding','','[]','高人葉高志，山服往山家。迢迢間風月，去去隔煙霞。',48,'御定全唐詩/json/005.json','["高人葉高志，山服往山家。迢迢間風月，去去隔煙霞。", "碧岫窺玄洞，玉灶煉丹砂。今日星津上，延首望靈槎。"]'),
('yuding-43','從駕幸少林寺','武則天','唐','御定全唐诗','yuding','','[]','陪鑾游禁苑，侍賞出蘭闈。雲偃攢峰蓋，霞低插浪旗。',120,'御定全唐詩/json/005.json','["陪鑾游禁苑，侍賞出蘭闈。雲偃攢峰蓋，霞低插浪旗。", "日宮疏澗戶，月殿啟岩扉。金輪轉金地，香閣曳香衣。", "鐸吟輕吹發，幡搖薄霧霏。昔遇焚芝火，山紅連野飛。", "花台無半影，蓮塔有全輝。實賴能仁力，攸資善世威。", "慈緣興福緒，於此罄歸依。風枝不可靜，泣血竟何追。"]'),
('yuding-44','石淙','武則天','唐','御定全唐诗','yuding','','[]','三山十洞光玄籙，玉嶠金巒鎮紫微。均露均霜標勝壤，',40,'御定全唐詩/json/005.json','["三山十洞光玄籙，玉嶠金巒鎮紫微。均露均霜標勝壤，", "且駐歡筵賞仁智，雕鞍薄晚雜塵飛。"]'),
('yuding-45','臘日宣詔幸上苑','武則天','唐','御定全唐诗','yuding','','[]','明朝游上苑，火急報春知。花須連夜發，莫待曉風吹。',24,'御定全唐詩/json/005.json','["明朝游上苑，火急報春知。花須連夜發，莫待曉風吹。"]'),
('yuding-46','如意娘','武則天','唐','御定全唐诗','yuding','','[]','看朱成碧思紛紛，憔悴支離為憶君。',32,'御定全唐詩/json/005.json','["看朱成碧思紛紛，憔悴支離為憶君。", "不信比來長下淚，開箱驗取石榴裙。"]'),
('yuding-47','制袍字賜狄仁傑','武則天','唐','御定全唐诗','yuding','','[]','敷政術，守清勤。升顯位，勵相臣。',16,'御定全唐詩/json/005.json','["敷政術，守清勤。升顯位，勵相臣。"]'),
('yuding-48','擬小山篇','徐賢妃','唐','御定全唐诗','yuding','','[]','仰幽岩而流盼，撫桂枝以凝想。',28,'御定全唐詩/json/005.json','["仰幽岩而流盼，撫桂枝以凝想。", "將千齡兮此遇，荃何為兮獨往。"]'),
('yuding-49','長門怨','徐賢妃','唐','御定全唐诗','yuding','','[]','舊愛柏梁台，新寵昭陽殿。守分辭芳輦，含情泣團扇。',48,'御定全唐詩/json/005.json','["舊愛柏梁台，新寵昭陽殿。守分辭芳輦，含情泣團扇。", "一朝歌舞榮，夙昔詩書賤。頹恩誠已矣，覆水難重薦。"]'),
('yuding-50','秋風函谷應詔','徐賢妃','唐','御定全唐诗','yuding','','[]','秋風起函穀，勁氣動河山。偃松千嶺上，雜雨二陵間。',48,'御定全唐詩/json/005.json','["秋風起函穀，勁氣動河山。偃松千嶺上，雜雨二陵間。", "低雲愁廣隰，落日慘重關。此時飄紫氣，應驗真人還。"]'),
('yuding-51','賦得北方有佳人','徐賢妃','唐','御定全唐诗','yuding','','[]','由來稱獨立，本自號傾城。柳葉眉間發，桃花臉上生。',60,'御定全唐詩/json/005.json','["由來稱獨立，本自號傾城。柳葉眉間發，桃花臉上生。", "腕搖金釧響，步轉玉環鳴。纖腰宜寶襪，紅衫豔織成。", "懸知一顧重，別覺舞腰輕。"]'),
('yuding-52','進太宗','徐賢妃','唐','御定全唐诗','yuding','','[]','朝來臨鏡臺，妝罷暫裴回。千金始一笑，一召詎能來。',24,'御定全唐詩/json/005.json','["朝來臨鏡臺，妝罷暫裴回。千金始一笑，一召詎能來。"]'),
('yuding-53','奉和聖制立春日侍宴內殿出翦彩花應制','上官昭容','唐','御定全唐诗','yuding','','[]','密葉因裁吐，新花逐翦舒。攀條雖不謬，摘蕊詎知虛。',48,'御定全唐詩/json/005.json','["密葉因裁吐，新花逐翦舒。攀條雖不謬，摘蕊詎知虛。", "春至由來發，秋還未肯疏。借問桃將李，相亂欲何如。"]'),
('yuding-54','九月九日上幸慈恩寺登浮圖，群臣上菊花壽酒','上官昭容','唐','御定全唐诗','yuding','','[]','帝裏重陽節，香園萬乘來。卻邪萸入佩，獻壽菊傳杯。',48,'御定全唐詩/json/005.json','["帝裏重陽節，香園萬乘來。卻邪萸入佩，獻壽菊傳杯。", "塔類承天湧，門疑待佛開。睿詞懸日月，長得仰昭回。"]'),
('yuding-55','彩書怨','上官昭容','唐','御定全唐诗','yuding','','[]','葉下洞庭初，思君萬里餘。露濃香被冷，月落錦屏虛。',48,'御定全唐詩/json/005.json','["葉下洞庭初，思君萬里餘。露濃香被冷，月落錦屏虛。", "欲奏江南曲，貪封薊北書。書中無別意，惟悵久離居。"]'),
('yuding-56','駕幸三會寺應制','上官昭容','唐','御定全唐诗','yuding','','[]','釋子談經處，軒臣刻字留。故台遺老識，殘簡聖皇求。',72,'御定全唐詩/json/005.json','["釋子談經處，軒臣刻字留。故台遺老識，殘簡聖皇求。", "駐蹕懷千古，開襟望九州。四山緣塞合，二水夾城流。", "宸翰陪瞻仰，天杯接獻酬。太平詞藻盛，長願紀鴻休。"]'),
('yuding-57','駕幸新豐溫泉宮獻詩三首','上官昭容','唐','御定全唐诗','yuding','','[]','三冬季月景龍年，萬乘觀風出灞川。',96,'御定全唐詩/json/005.json','["三冬季月景龍年，萬乘觀風出灞川。", "遙看電躍龍為馬，回矚霜原玉作田。", "鸞旗掣曳拂空回，羽騎驂驔躡景來。", "隱隱驪山雲外聳，迢迢禦帳日邊開。", "翠幕珠幃敞月營，金罍玉斝泛蘭英。", "歲歲年年常扈蹕，長長久久樂升平。"]'),
('yuding-58','游長寧公主流杯池二十五首','上官昭容','唐','御定全唐诗','yuding','','[]','逐仙賞，展幽情，逾昆閬，邁蓬瀛。',541,'御定全唐詩/json/005.json','["逐仙賞，展幽情，逾昆閬，邁蓬瀛。", "游魯館，陟秦台。汙山壁，愧瓊瑰。", "檀欒竹影，飆f2松聲。不煩歌吹，自足娛情。", "仰循茅宇，俯眄喬枝。煙霞問訊，風月相知。", "枝條鬱鬱，文質彬彬。山林作伴，松桂為鄰。", "清波洶湧，碧樹冥蒙。莫怪留步，因攀桂叢。", "莫論圓嶠，休說方壺。何如魯館，即是仙都。", "玉環騰遠創，金埒荷殊榮。弗玩珠璣飾，仍留仁智情。", "鑿山便作室，憑樹即為楹。公輸與班爾，從此遂韜聲。", "登山一長望，正遇九春初。結駟填街術，閭閻滿邑居。", "鬥雪梅先吐，驚風柳未舒。直愁斜日落，不畏酒尊虛。", "霽曉氣清和，披襟賞薜蘿。玳瑁凝春色，琉璃漾水波。", "跂石聊長嘯，攀松乍短歌。除非物外者，誰就此經過。", "暫爾遊山第，淹留惜未歸。霞窗明月滿，澗戶白雲飛。", "書引藤為架，人將薜作衣。此真攀玩所，臨睨賞光輝。", "放曠出煙雲，蕭條自不群。漱流清意府，隱幾避囂氛。", "石畫妝苔色，風梭織水文。山室何為貴，唯餘蘭桂熏。", "策杖臨霞岫，危步下霜蹊。志逐深山靜，途隨曲澗迷。", "漸覺心神逸，俄看雲霧低。莫怪人題樹，只為賞幽棲。", "攀藤招逸客，偃桂協幽情。水中看樹影，風裏聽松聲。", "攜琴侍叔夜，負局訪安期。不應題石壁，為記賞山時。", "泉石多仙趣，岩壑寫奇形。欲知堪悅耳，唯聽水泠泠。", "岩壑恣登臨，瑩目複怡心。風篁類長笛，流水當鳴琴。", "懶步天臺路，惟登地肺山。幽岩仙桂滿，今日恣情攀。"]'),
('yuding-59','句','上官昭容','唐','御定全唐诗','yuding','','[]','勢如連璧友，心似臭蘭人。',12,'御定全唐詩/json/005.json','["勢如連璧友，心似臭蘭人。"]'),
('yuding-60','贈張雲容舞','楊玉環','唐','御定全唐诗','yuding','','[]','羅袖動香香不已，紅蕖嫋嫋秋煙裏。',32,'御定全唐詩/json/005.json','["羅袖動香香不已，紅蕖嫋嫋秋煙裏。", "輕雲嶺上乍搖風，嫩柳池邊初拂水。"]'),
('yuding-61','謝賜珍珠','江妃','唐','御定全唐诗','yuding','','[]','桂葉雙眉久不描，殘妝和淚汙紅綃。',32,'御定全唐詩/json/005.json','["桂葉雙眉久不描，殘妝和淚汙紅綃。", "長門盡日無梳洗，何必珍珠慰寂寥。"]'),
('yuding-0','黃台瓜辭','李賢','唐','御定全唐诗','yuding','','[]','種瓜黃台下，瓜熟子離離。一摘使瓜好，再摘使瓜稀。',36,'御定全唐詩/json/006.json','["種瓜黃台下，瓜熟子離離。一摘使瓜好，再摘使瓜稀。", "三摘猶自可，摘絕抱蔓歸。"]'),
('yuding-1','奉和同太子監守違戀','李元嘉','唐','御定全唐诗','yuding','','[]','幹象開層構，離明啟少陽。卜征從獻吉，守器屬元良。',84,'御定全唐詩/json/006.json','["幹象開層構，離明啟少陽。卜征從獻吉，守器屬元良。", "逖矣淩周誦，遙哉掩漢莊。好士傾南洛，多才盛北場。", "地分丹鷲嶺，途間白雲鄉。儲誠虔曉夕，宸愛積炎涼。", "珠璧連霄漢，萬物仰重光。"]'),
('yuding-2','奉和聖制過溫湯','李貞','唐','御定全唐诗','yuding','','[]','鳳輦騰宸駕，驪籞次幹遊。坎德疏溫液，山隈派暖流。',60,'御定全唐詩/json/006.json','["鳳輦騰宸駕，驪籞次幹遊。坎德疏溫液，山隈派暖流。", "寒氛空外擁，蒸氣沼中浮。林凋帷影散，雲斂蓋陰收。", "霜郊暢玄覽，參差落景遒。"]'),
('yuding-3','石橋','李禕','唐','御定全唐诗','yuding','','[]','別有經行所，迥跨重巒側。粵因求瘼餘，倏想尋真域。',120,'御定全唐詩/json/006.json','["別有經行所，迥跨重巒側。粵因求瘼餘，倏想尋真域。", "放情恣披拂，杖策聊□□。□□□□□，□□□□色。", "亂幡霧中見，雁塔雲間識。薄煙冪遠郊，遙峰沒歸翼。", "仙橋危石架，幽洞乘□□。□□□□□，□□□易測。", "二教無先後，一相平而直。冀茲捐俗心，永懷依妙力。"]'),
('yuding-0','虛池驛題屏風','宜芬公主','唐','御定全唐诗','yuding','','[]','出嫁辭鄉國，由來此別難。聖恩愁遠道，行路泣相看。',48,'御定全唐詩/json/007.json','["出嫁辭鄉國，由來此別難。聖恩愁遠道，行路泣相看。", "沙塞容顏盡，邊隅粉黛殘。妾心何所斷，他日望長安。"]'),
('yuding-1','嘲陸暢','宋若華','唐','御定全唐诗','yuding','','[]','十二層樓倚翠空，鳳鸞相對立梧桐。',32,'御定全唐詩/json/007.json','["十二層樓倚翠空，鳳鸞相對立梧桐。", "雙成走報監門衛，莫使吳歈入漢宮。"]'),
('yuding-2','奉和禦制麟德殿宴百僚應制','宋若昭','唐','御定全唐诗','yuding','','[]','垂衣臨八極，肅穆四門通。自是無為化，非關輔弼功。',72,'御定全唐詩/json/007.json','["垂衣臨八極，肅穆四門通。自是無為化，非關輔弼功。", "修文招隱伏，尚武殄妖凶。德炳韶光熾，恩沾雨露濃。", "衣冠陪禦宴，禮樂盛朝宗。萬壽稱觴舉，千年信一同。"]'),
('yuding-3','奉和禦制麟德殿宴百官','宋若憲','唐','御定全唐诗','yuding','','[]','端拱承休命，時清荷聖皇。四聰聞受諫，五服遠朝王。',72,'御定全唐詩/json/007.json','["端拱承休命，時清荷聖皇。四聰聞受諫，五服遠朝王。", "景媚鶯初囀，春殘日更長。命筵多濟濟，盛樂複鏘鏘。", "酆鎬誰將敵，橫汾未可方。願齊山嶽壽，祉福永無疆。"]'),
('yuding-4','奉和麟德殿宴百僚應制','鮑君徽','唐','御定全唐诗','yuding','','[]','睿澤先寰海，功成展武韶。戈鋋清外壘，文物盛中朝。',72,'御定全唐詩/json/007.json','["睿澤先寰海，功成展武韶。戈鋋清外壘，文物盛中朝。", "聖祚山河固，宸章日月昭。玉筵鸞鵠集，仙管鳳凰調。", "禦柳新低綠，宮鶯乍囀嬌。願將億兆慶，千祀奉神堯。"]'),
('yuding-5','關山月','鮑君徽','唐','御定全唐诗','yuding','','[]','高高秋月明，北照遼陽城。塞迥光初滿，風多暈更生。',72,'御定全唐詩/json/007.json','["高高秋月明，北照遼陽城。塞迥光初滿，風多暈更生。", "征人望鄉思，戰馬聞鼙驚。朔風悲邊草，胡沙暗虜營。", "霜凝匣中劍，風憊原上旌。早晚謁金闕，不聞刁鬥聲。"]'),
('yuding-6','惜花吟','鮑君徽','唐','御定全唐诗','yuding','','[]','枝上花，花下人，可憐顏色俱青春。昨日看花花灼灼，',48,'御定全唐詩/json/007.json','["枝上花，花下人，可憐顏色俱青春。昨日看花花灼灼，", "鶯歌蝶舞韶光長，紅爐煮茗松花香。妝成罷吟恣遊後，"]'),
('yuding-7','東亭茶宴','鮑君徽','唐','御定全唐诗','yuding','','[]','閑朝向曉出簾櫳，茗宴東亭四望通。遠眺城池山色裏，',40,'御定全唐詩/json/007.json','["閑朝向曉出簾櫳，茗宴東亭四望通。遠眺城池山色裏，", "坐久此中無限興，更憐團扇起清風。"]'),
('yuding-8','夜夢','蕭妃','唐','御定全唐诗','yuding','','[]','昨日夢君歸，賤妾下鳴機。極知意氣薄，不著去時衣。',36,'御定全唐詩/json/007.json','["昨日夢君歸，賤妾下鳴機。極知意氣薄，不著去時衣。", "故言如夢裏，賴得雁書飛。"]'),
('yuding-0','詠燈','李昪','唐','御定全唐诗','yuding','','[]','一點分明值萬金，開時惟怕冷風侵。',32,'御定全唐詩/json/008.json','["一點分明值萬金，開時惟怕冷風侵。", "主人若也勤挑撥，敢向尊前不盡心。"]'),
('yuding-1','遊後湖賞蓮花','李璟','唐','御定全唐诗','yuding','','[]','蓼花蘸水火不滅，水鳥驚魚銀梭投。滿目荷花千萬頃，',24,'御定全唐詩/json/008.json','["蓼花蘸水火不滅，水鳥驚魚銀梭投。滿目荷花千萬頃，"]'),
('yuding-2','保大五年元日大雪同太弟景遂汪王景逷齊王景逵進士李建勳中書徐鉉勤政殿學士張義方登樓賦','李璟','唐','御定全唐诗','yuding','','[]','珠簾高卷莫輕遮，往往相逢隔歲華。春氣昨宵飄律管，',40,'御定全唐詩/json/008.json','["珠簾高卷莫輕遮，往往相逢隔歲華。春氣昨宵飄律管，", "坐有賓朋尊有酒，可憐清味屬儂家。"]'),
('yuding-3','句','李璟','唐','御定全唐诗','yuding','','[]','靈槎思浩蕩，老鶴倚崆峒。',40,'御定全唐詩/json/008.json','["靈槎思浩蕩，老鶴倚崆峒。", "蒼苔迷古道，紅葉亂朝霞。", "棲鳳枝梢猶軟弱，化龍形狀已依稀。"]'),
('yuding-4','九月十日偶書','李煜','唐','御定全唐诗','yuding','','[]','晚雨秋陰酒乍醒，感時心緒杳難平。黃花冷落不成豔，',40,'御定全唐詩/json/008.json','["晚雨秋陰酒乍醒，感時心緒杳難平。黃花冷落不成豔，", "自從雙鬢斑斑白，不學安仁卻自驚。"]'),
('yuding-5','秋鶯','李煜','唐','御定全唐诗','yuding','','[]','殘鶯何事不知秋，橫過幽林尚獨遊。老舌百般傾耳聽，',40,'御定全唐詩/json/008.json','["殘鶯何事不知秋，橫過幽林尚獨遊。老舌百般傾耳聽，", "莫更留連好歸去，露華淒冷蓼花愁。"]'),
('yuding-6','病起題山舍壁','李煜','唐','御定全唐诗','yuding','','[]','山舍初成病乍輕，杖藜巾褐稱閒情。爐開小火深回暖，',40,'御定全唐詩/json/008.json','["山舍初成病乍輕，杖藜巾褐稱閒情。爐開小火深回暖，", "誰能役役塵中累，貪合魚龍構強名。"]'),
('yuding-7','送鄧王二十弟從益牧宣城','李煜','唐','御定全唐诗','yuding','','[]','且維輕舸更遲遲，別酒重傾惜解攜。浩浪侵愁光蕩漾，',40,'御定全唐詩/json/008.json','["且維輕舸更遲遲，別酒重傾惜解攜。浩浪侵愁光蕩漾，", "咫尺煙江幾多地，不須懷抱重淒淒。"]'),
('yuding-8','渡中江望石城泣下','李煜','唐','御定全唐诗','yuding','','[]','江南江北舊家鄉，三十年來夢一場。吳苑宮闈今冷落，',40,'御定全唐詩/json/008.json','["江南江北舊家鄉，三十年來夢一場。吳苑宮闈今冷落，", "兄弟四人三百口，不堪閑坐細思量。"]'),
('yuding-9','挽辭','李煜','唐','御定全唐诗','yuding','','[]','珠碎眼前珍，花凋世外春。未銷心裏恨，又失掌中身。',96,'御定全唐詩/json/008.json','["珠碎眼前珍，花凋世外春。未銷心裏恨，又失掌中身。", "玉笥猶殘藥，香奩已染塵。前哀將後感，無淚可沾巾。", "豔質同芳樹，浮危道略同。正悲春落實，又苦雨傷叢。", "穠麗今何在，飄零事已空。沉沉無問處，千載謝東風。"]'),
('yuding-10','悼詩','李煜','唐','御定全唐诗','yuding','','[]','永念難消釋，孤懷痛自嗟。雨深秋寂莫，愁引病增加。',48,'御定全唐詩/json/008.json','["永念難消釋，孤懷痛自嗟。雨深秋寂莫，愁引病增加。", "咽絕風前思，昏蒙眼上花。空王應念我，窮子正迷家。"]'),
('yuding-11','感懷','李煜','唐','御定全唐诗','yuding','','[]','又見桐花發舊枝，一樓煙雨暮淒淒。',64,'御定全唐詩/json/008.json','["又見桐花發舊枝，一樓煙雨暮淒淒。", "憑闌惆悵人誰會，不覺潸然淚眼低。", "層城無複見嬌姿，佳節纏哀不自持。", "空有當年舊煙月，芙蓉城上哭蛾眉。"]'),
('yuding-12','梅花','李煜','唐','御定全唐诗','yuding','','[]','殷勤移植地，曲檻小欄邊。共約重芳日，還憂不盛妍。',72,'御定全唐詩/json/008.json','["殷勤移植地，曲檻小欄邊。共約重芳日，還憂不盛妍。", "阻風開步障，乘月溉寒泉。誰料花前後，蛾眉卻不全。", "失卻煙花主，東君自不知。清香更何用，猶發去年枝。"]'),
('yuding-13','書靈筵手巾','李煜','唐','御定全唐诗','yuding','','[]','浮生共憔悴，壯歲失嬋娟。汗手遺香漬，痕眉染黛煙。',24,'御定全唐詩/json/008.json','["浮生共憔悴，壯歲失嬋娟。汗手遺香漬，痕眉染黛煙。"]'),
('yuding-14','書琵琶背','李煜','唐','御定全唐诗','yuding','','[]','侁自肩如削，難勝數縷絛。天香留鳳尾，餘暖在檀槽。',24,'御定全唐詩/json/008.json','["侁自肩如削，難勝數縷絛。天香留鳳尾，餘暖在檀槽。"]'),
('yuding-15','病中感懷','李煜','唐','御定全唐诗','yuding','','[]','憔悴年來甚，蕭條益自傷。風威侵病骨，雨氣咽愁腸。',48,'御定全唐詩/json/008.json','["憔悴年來甚，蕭條益自傷。風威侵病骨，雨氣咽愁腸。", "夜鼎唯煎藥，朝髭半染霜。前緣竟何似，誰與問空王。"]'),
('yuding-16','病中書事','李煜','唐','御定全唐诗','yuding','','[]','病身堅固道情深，宴坐清香思自任。月照靜居唯搗藥，',40,'御定全唐詩/json/008.json','["病身堅固道情深，宴坐清香思自任。月照靜居唯搗藥，", "賴問空門知氣味，不然煩惱萬塗侵。"]'),
('yuding-17','賜宮人慶奴','李煜','唐','御定全唐诗','yuding','','[]','風情漸老見春羞，到處消魂感舊遊。',32,'御定全唐詩/json/008.json','["風情漸老見春羞，到處消魂感舊遊。", "多謝長條似相識，強垂煙態拂人頭。"]'),
('yuding-18','題金樓子後','李煜','唐','御定全唐诗','yuding','','[]','牙籤萬軸裹紅綃，王粲書同付火燒。',32,'御定全唐詩/json/008.json','["牙籤萬軸裹紅綃，王粲書同付火燒。", "不于祖龍留面目，遺篇那得到今朝。"]'),
('yuding-19','句','李煜','唐','御定全唐诗','yuding','','[]','迢迢牽牛星，杳在河之陽。粲粲黃姑女，耿耿遙相望。',208,'御定全唐詩/json/008.json','["迢迢牽牛星，杳在河之陽。粲粲黃姑女，耿耿遙相望。", "鶯狂應有恨，蝶舞已無多。", "揖讓月在手，動搖風滿懷。", "病態如衰弱，厭厭向五年。", "衰顏一病難牽複，曉殿君臨頗自羞。", "冷笑秦皇經遠略，靜憐姬滿苦時巡。", "鬢從今日添新白，菊是去年依舊黃。", "萬古到頭歸一死，醉鄉葬地有高原。", "人生不滿百，剛作千年畫。", "日映仙雲薄，秋高天碧深。", "烏照始潛輝，龍燭便爭秉。", "凝珠滿露枝。", "遊颺日已西，肅穆寒初至。", "九重開扇鵠，四牖炳燈魚。", "羽觴無算酌。", "傾碗更為壽，深卮遞酬賓。"]'),
('yuding-20','薔薇詩一首十八韻呈東海侍郎徐鉉','李從善','唐','御定全唐诗','yuding','','[]','綠影覆幽池，芳菲四月時。管弦朝夕興，組繡百千枝。',217,'御定全唐詩/json/008.json','["綠影覆幽池，芳菲四月時。管弦朝夕興，組繡百千枝。", "盛引牆看遍，高煩架屢移。露輕濡彩筆，蜂誤拂吟髭。", "日照玲瓏幔，風搖翡翠帷。早紅飄蘚地，狂蔓掛蛛絲。", "嫩刺牽衣細，新條窣草垂。晚香難暫舍，嬌自態相窺。", "深淺分前後，榮華互盛衰。尊前留客久，月下欲歸遲。", "何處繁臨砌，誰家密映籬。絳羅房燦爛，碧玉葉參差。", "分得殷勤種，開來遠近知。晶熒歌袖袂，柔弱舞腰支。", "膏麝誰將比，庭萱自合嗤。勻妝低水鑒，泣淚滴煙rG。", "畫擬憑梁廣，名宜亞楚姬。寄君十八韻，思拙愧新奇。"]'),
('yuding-21','觀棋','李從謙','唐','御定全唐诗','yuding','','[]','竹林二君子，盡日竟沉吟。相對終無語，爭先各有心。',48,'御定全唐詩/json/008.json','["竹林二君子，盡日竟沉吟。相對終無語，爭先各有心。", "恃強斯有失，守分固無侵。若算機籌處，滄滄海未深。"]'),
('yuding-22','贈別唐太師道襲','李建','唐','御定全唐诗','yuding','','[]','丱歲便將為肘腋，二紀何曾離一日。更深猶尚立案前，',40,'御定全唐詩/json/008.json','["丱歲便將為肘腋，二紀何曾離一日。更深猶尚立案前，", "褒斜舊地委勳賢，從此生靈永泰息。"]'),
('yuding-23','幸秦川上梓潼山','李衍','唐','御定全唐诗','yuding','','[]','喬岩簇冷煙，幽徑上寒天。下瞰峨眉嶺，上窺華嶽巔。',48,'御定全唐詩/json/008.json','["喬岩簇冷煙，幽徑上寒天。下瞰峨眉嶺，上窺華嶽巔。", "驅馳非取樂，按幸為憂邊。此去如登陟，歌樓路幾千。"]'),
('yuding-24','題劍門','李衍','唐','御定全唐诗','yuding','','[]','緩轡逾雙劍，行行躡石棱。作千尋壁壘，為萬祀依憑。',48,'御定全唐詩/json/008.json','["緩轡逾雙劍，行行躡石棱。作千尋壁壘，為萬祀依憑。", "道德雖無取，江山粗可矜。回看城闕路，雲疊樹層層。"]'),
('yuding-25','過白衛嶺和韓昭','李衍','唐','御定全唐诗','yuding','','[]','先朝神武力開邊，畫斷封疆四五千。前望隴山屯劍戟，',40,'御定全唐詩/json/008.json','["先朝神武力開邊，畫斷封疆四五千。前望隴山屯劍戟，", "想到隗宮尋勝處，正應鶯語暮春天。"]'),
('yuding-26','宮詞','李衍','唐','御定全唐诗','yuding','','[]','輝輝赫赫浮玉雲，宣華池上月華新。',32,'御定全唐詩/json/008.json','["輝輝赫赫浮玉雲，宣華池上月華新。", "月華如水浸宮殿，有酒不醉真癡人。"]'),
('yuding-27','醉妝詞','李衍','唐','御定全唐诗','yuding','','[]','者邊走，那邊走，只是尋花柳。',28,'御定全唐詩/json/008.json','["者邊走，那邊走，只是尋花柳。", "那邊走，者邊走，莫厭金杯酒。"]'),
('yuding-28','句','李衍','唐','御定全唐诗','yuding','','[]','不緣朝闕去，好此結茅廬。',12,'御定全唐詩/json/008.json','["不緣朝闕去，好此結茅廬。"]'),
('yuding-29','巡衣錦軍制還鄉歌','錢鏐','唐','御定全唐诗','yuding','','[]','三節還鄉兮掛錦衣，碧天朗朗兮愛日暉。',72,'御定全唐詩/json/008.json','["三節還鄉兮掛錦衣，碧天朗朗兮愛日暉。", "功成道上兮列旌旗，父老遠來兮相追隨。", "家山鄉眷兮會時稀，今朝設宴兮觥散飛。", "鬥牛無孛兮民無欺，吳越一王兮駟馬歸。"]'),
('yuding-30','沒了期歌','錢鏐','唐','御定全唐诗','yuding','','[]','沒了期，沒了期，營基才了又倉基。',32,'御定全唐詩/json/008.json','["沒了期，沒了期，營基才了又倉基。", "沒了期，沒了期，春衣才了又冬衣。"]'),
('yuding-31','句','錢鏐','唐','御定全唐诗','yuding','','[]','須將一片地，付與有心人。',44,'御定全唐詩/json/008.json','["須將一片地，付與有心人。", "黃河信有澄清日，後代應難繼此才。", "傳語龍王並水府，錢塘借與築錢城。"]'),
('yuding-32','宮中作','錢俶','唐','御定全唐诗','yuding','','[]','廊廡周遭翠幕遮，禁林深處絕喧嘩。界開日影憐窗紙，',40,'御定全唐詩/json/008.json','["廊廡周遭翠幕遮，禁林深處絕喧嘩。界開日影憐窗紙，", "謝公未是深沉量，猶把輸贏局上誇。"]'),
('yuding-33','避暑摩訶池上作','孟昶','唐','御定全唐诗','yuding','','[]','冰肌玉骨清無汗，水殿風來暗香暖。簾開明月獨窺人，',40,'御定全唐詩/json/008.json','["冰肌玉骨清無汗，水殿風來暗香暖。簾開明月獨窺人，", "屈指西風幾時來，只恐流年暗中換。"]'),
('yuding-34','批葉翹諫書紙尾','王繼鵬','唐','御定全唐诗','yuding','','[]','春色曾看紫陌頭，亂紅飛盡不禁愁。',32,'御定全唐詩/json/008.json','["春色曾看紫陌頭，亂紅飛盡不禁愁。", "人情自厭芳華歇，一葉隨風落禦溝。"]'),
('yuding-0','丈人觀','徐氏','唐','御定全唐诗','yuding','','[]','早與元妃慕至化，同躋靈嶽訪真仙。當時信有壺中景，',40,'御定全唐詩/json/009.json','["早與元妃慕至化，同躋靈嶽訪真仙。當時信有壺中景，", "惟慚未致華胥理，徒蔔升平萬萬年。"]'),
('yuding-1','玄都觀','徐氏','唐','御定全唐诗','yuding','','[]','千尋綠嶂夾流溪，登眺因知海嶽低。瀑布迸舂青石碎，',40,'御定全唐詩/json/009.json','["千尋綠嶂夾流溪，登眺因知海嶽低。瀑布迸舂青石碎，", "莫道穹天無路到，此山便是碧雲梯。"]'),
('yuding-2','丈人觀謁先帝禦容','徐氏','唐','御定全唐诗','yuding','','[]','聖帝歸梧野，躬來謁聖顏。旋登三徑路，似陟九嶷山。',48,'御定全唐詩/json/009.json','["聖帝歸梧野，躬來謁聖顏。旋登三徑路，似陟九嶷山。", "日照堆嵐迥，雲橫積翠間。期修封禪禮，方俟再躋攀。"]'),
('yuding-3','題金華宮','徐氏','唐','御定全唐诗','yuding','','[]','再到金華頂，玄都訪道回。雲披分景象，黛鎖顯樓臺。',48,'御定全唐詩/json/009.json','["再到金華頂，玄都訪道回。雲披分景象，黛鎖顯樓臺。", "雨滌前山淨，風吹去路開。翠屏夾流水，何必羨蓬萊。"]'),
('yuding-4','丹景山至德寺','徐氏','唐','御定全唐诗','yuding','','[]','周回雲水游丹景，因與真妃眺上方。晴日曉升金晃曜，',40,'御定全唐詩/json/009.json','["周回雲水游丹景，因與真妃眺上方。晴日曉升金晃曜，", "虔煠六銖宜鑄祝，惟祈聖祉保遐昌。"]'),
('yuding-5','題彭州陽平化','徐氏','唐','御定全唐诗','yuding','','[]','尋真遊勝境，巡禮到陽平。水遠波瀾碧，山高氣象清。',48,'御定全唐詩/json/009.json','["尋真遊勝境，巡禮到陽平。水遠波瀾碧，山高氣象清。", "殿嚴孫氏貌，碑暗系師名。夜月登壇醮，松風森磬聲。"]'),
('yuding-6','三學山夜看聖燈','徐氏','唐','御定全唐诗','yuding','','[]','虔禱遊靈境，元妃夙志同。玉香焚靜夜，銀燭炫遼空。',96,'御定全唐詩/json/009.json','["虔禱遊靈境，元妃夙志同。玉香焚靜夜，銀燭炫遼空。", "泉漱雲根月，鐘敲檜杪風。印金標聖跡，飛石顯神功。", "滿望天涯極，平臨日腳紅。猿來齋石上，僧集講筵中。", "頓作超三界，渾疑證六通。願成修偃化，社稷保延洪。"]'),
('yuding-7','題天回驛','徐氏','唐','御定全唐诗','yuding','','[]','周遊靈境散幽情，千里江山暫得行。',32,'御定全唐詩/json/009.json','["周遊靈境散幽情，千里江山暫得行。", "所恨風光看未足，卻驅金翠入龜城。"]'),
('yuding-8','丈人觀','徐氏','唐','御定全唐诗','yuding','','[]','獲陪翠輦喜殊常，同涉仙壇豈厭長。',32,'御定全唐詩/json/009.json','["獲陪翠輦喜殊常，同涉仙壇豈厭長。", "不羨乘鸞入煙霧，此中便是五雲鄉。"]'),
('yuding-9','玄都觀','徐氏','唐','御定全唐诗','yuding','','[]','登尋丹壑到玄都，接日紅霞照座隅。',32,'御定全唐詩/json/009.json','["登尋丹壑到玄都，接日紅霞照座隅。", "即向周回岩下看，似看曾進畫圖無。"]'),
('yuding-10','游丈人觀謁先帝禦容','徐氏','唐','御定全唐诗','yuding','','[]','共謁禦容儀，還同在禁闈。笙歌喧寶殿，彩仗耀金徽。',48,'御定全唐詩/json/009.json','["共謁禦容儀，還同在禁闈。笙歌喧寶殿，彩仗耀金徽。", "清淚沾羅袂，紅霞拂繡衣。九疑山水遠，無路繼湘妃。"]'),
('yuding-11','題金華宮','徐氏','唐','御定全唐诗','yuding','','[]','碧煙紅霧漾人衣，宿霧蒼苔石徑危。風巧解吹松上曲，',40,'御定全唐詩/json/009.json','["碧煙紅霧漾人衣，宿霧蒼苔石徑危。風巧解吹松上曲，", "好把身心清淨處，角冠霞帔事希夷。"]'),
('yuding-12','和題丹景山至德寺','徐氏','唐','御定全唐诗','yuding','','[]','丹景山頭宿梵宮，玉輪金輅駐虛空。軍持無水注寒碧，',40,'御定全唐詩/json/009.json','["丹景山頭宿梵宮，玉輪金輅駐虛空。軍持無水注寒碧，", "我家帝子傳王業，積善終期四海同。"]'),
('yuding-13','題彭州陽平化','徐氏','唐','御定全唐诗','yuding','','[]','雲浮翠輦屆陽平，真似驂鸞到上清。風起半厓聞虎嘯，',40,'御定全唐詩/json/009.json','["雲浮翠輦屆陽平，真似驂鸞到上清。風起半厓聞虎嘯，", "長恐前身居此境，玉皇教向錦城生。"]'),
('yuding-14','三學山夜看聖燈','徐氏','唐','御定全唐诗','yuding','','[]','聖燈千萬炬，旋向碧空生。細雨濕不暗，好風吹更明。',48,'御定全唐詩/json/009.json','["聖燈千萬炬，旋向碧空生。細雨濕不暗，好風吹更明。", "磬敲金地響，僧唱梵天聲。若說無心法，此光如有情。"]'),
('yuding-15','題天回驛','徐氏','唐','御定全唐诗','yuding','','[]','翠驛紅亭近玉京，夢魂猶是在青城。',32,'御定全唐詩/json/009.json','["翠驛紅亭近玉京，夢魂猶是在青城。", "比來出看江山景，卻被江山看出行。"]'),
('yuding-0','郊廟歌辭：祀圜丘樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','上靈眷命膺會昌，盛德殷薦葉辰良。',32,'御定全唐詩/json/010.json','["上靈眷命膺會昌，盛德殷薦葉辰良。", "景福降兮聖德遠，玄化穆兮天曆長。"]'),
('yuding-1','郊廟歌辭：祀圜丘樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','穆穆我後，道應千齡。登三處大，得一居貞。',40,'御定全唐詩/json/010.json','["穆穆我後，道應千齡。登三處大，得一居貞。", "禮惟崇德，樂以和聲。百神仰止，天下文明。"]'),
('yuding-2','郊廟歌辭：祀圜丘樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','闓陽播氣，甄曜垂明。有赫圜宰，深仁曲成。',40,'御定全唐詩/json/010.json','["闓陽播氣，甄曜垂明。有赫圜宰，深仁曲成。", "日麗蒼璧，煙開紫營。聿遵幹享，式降鴻禎。"]'),
('yuding-3','郊廟歌辭：祀圜丘樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','欽惟大帝，載仰皇穹。始命田燭，爰啟郊宮。',40,'御定全唐詩/json/010.json','["欽惟大帝，載仰皇穹。始命田燭，爰啟郊宮。", "雲門駭聽，雷鼓鳴空。神其介祀，景祚斯融。"]'),
('yuding-4','郊廟歌辭：祀圜丘樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','八音斯奏，三獻畢陳。寶祚惟永，暉光日新。',20,'御定全唐詩/json/010.json','["八音斯奏，三獻畢陳。寶祚惟永，暉光日新。"]'),
('yuding-5','郊廟歌辭：祀圜丘樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','疊璧凝影皇壇路，編珠流彩帝郊前。',32,'御定全唐詩/json/010.json','["疊璧凝影皇壇路，編珠流彩帝郊前。", "已奏黃鐘歌大呂，還符寶曆祚昌年。"]'),
('yuding-6','郊廟歌辭：祀圜丘樂章：凱安','不詳','唐','御定全唐诗','yuding','','[]','昔在炎運終，中華亂無象。酆郊赤烏見，邙山黑雲上。',48,'御定全唐詩/json/010.json','["昔在炎運終，中華亂無象。酆郊赤烏見，邙山黑雲上。", "大賚下周車，禁暴開殷網。幽明同葉贊，鼎祚齊天壤。"]'),
('yuding-7','郊廟歌辭：祀圜丘樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','歌奏畢兮禮獻終，六龍馭兮神將升。',32,'御定全唐詩/json/010.json','["歌奏畢兮禮獻終，六龍馭兮神將升。", "明德感兮非黍稷，降福簡兮祚休征。"]'),
('yuding-8','郊廟歌辭：郊天舊樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','蘋蘩禮著，黍稷誠微。音盈鳳管，彩駐龍旗。',40,'御定全唐詩/json/010.json','["蘋蘩禮著，黍稷誠微。音盈鳳管，彩駐龍旗。", "洪歆式就，介福攸歸。送樂有闋，靈馭遄飛。"]'),
('yuding-9','郊廟歌辭：武后大享昊天樂章','不詳','唐','御定全唐诗','yuding','','[]','大陰凝至化，真耀蘊軒儀。德邁娥台敞，仁高姒幄披。',455,'御定全唐詩/json/010.json','["大陰凝至化，真耀蘊軒儀。德邁娥台敞，仁高姒幄披。", "捫天遂啟極，夢日乃升曦。", "瞻紫極，望玄穹。翹至懇，罄深衷。", "聽雖遠，誠必通。垂厚澤，降雲宮。", "幹儀混成沖邃，天道下濟高明。闓陽晨披紫闕，", "丹襟式敷衷懇，玄鑒庶察微誠。", "巍巍睿業廣，赫赫聖基隆。菲德承先顧，禎符萃眇躬。", "銘開武岩側，圖薦洛川中。微誠詎幽感，景命忽昭融。", "有懷慚紫極，無以謝玄穹。", "朝壇霧卷，曙嶺煙沉。爰設筐幣，式表誠心。", "筵輝麗璧，樂暢和音。仰惟靈鑒，俯察翹襟。", "昭昭上帝，穆穆下臨。禮崇備物，樂奏鏘金。", "蘭羞委薦，桂醑盈斟。敢希明德，聿罄莊心。", "樽浮九醞，禮備三周。陳誠菲奠，契福神猷。", "奠璧郊壇昭大禮，鏘金拊石表虔誠。", "始奏承雲娛帝賞，複歌調露暢韶英。", "荷恩承顧托，執契恭臨撫。廟略靜邊荒，天兵耀神武。", "有截資先化，無為遵舊矩。禎符降昊穹，大業光寰宇。", "肅肅祀典，邕邕禮秩。三獻已周，九成斯畢。", "爰撤其俎，載遷其實。或升或降，唯誠唯質。", "禮終肆類，樂闋九成。仰惟明德，敢薦非馨。", "顧慚菲奠，久駐雲輧。瞻荷靈澤，悚戀兼盈。", "式乾路，辟天扉。回日馭，動雲衣。", "登金闕，入紫微。望仙駕，仰恩徽。"]'),
('yuding-10','中宗祀昊天樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','天之歷數歸睿唐，顧惟菲德欽昊蒼。',32,'御定全唐詩/json/010.json','["天之歷數歸睿唐，顧惟菲德欽昊蒼。", "撰吉日兮表殷薦，冀神鑒兮降闓陽。"]'),
('yuding-11','中宗祀昊天樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','恭臨寶位，肅奉瑤圖。恒思解網，每軫泣辜。',40,'御定全唐詩/json/010.json','["恭臨寶位，肅奉瑤圖。恒思解網，每軫泣辜。", "德慚巢燧，化劣唐虞。期我良弼，式贊嘉謨。"]'),
('yuding-12','中宗祀昊天樂章：告謝','不詳','唐','御定全唐诗','yuding','','[]','得一流玄澤，通三禦紫宸。遠葉千齡運，遐銷九域塵。',48,'御定全唐詩/json/010.json','["得一流玄澤，通三禦紫宸。遠葉千齡運，遐銷九域塵。", "絕瑞駢闐集，殊祥絡繹臻。登年慶棲畝，稔歲賀盈囷。"]'),
('yuding-13','中宗祀昊天樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','悠哉廣覆，大矣曲成。九玄著象，七曜貞明。',40,'御定全唐詩/json/010.json','["悠哉廣覆，大矣曲成。九玄著象，七曜貞明。", "珪璧是奠，醞酎斯盈。作樂崇德，爰暢咸英。"]'),
('yuding-14','中宗祀昊天樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','郊壇展敬，嚴配因心。孤竹簫管，空桑瑟琴。',40,'御定全唐詩/json/010.json','["郊壇展敬，嚴配因心。孤竹簫管，空桑瑟琴。", "肅穆大禮，鏗鏘八音。恭惟上帝，希降靈歆。"]'),
('yuding-15','中宗祀昊天樂章：福和','不詳','唐','御定全唐诗','yuding','','[]','九成爰奏，三獻式陳。欽承景福，恭托明禋。',20,'御定全唐詩/json/010.json','["九成爰奏，三獻式陳。欽承景福，恭托明禋。"]'),
('yuding-16','中宗祀昊天樂章：中宮助祭升壇','不詳','唐','御定全唐诗','yuding','','[]','坤元光至德，柔訓闡皇風。芣苡芳聲遠，螽斯美化隆。',48,'御定全唐詩/json/010.json','["坤元光至德，柔訓闡皇風。芣苡芳聲遠，螽斯美化隆。", "睿範超千載，嘉猷備六宮。肅恭陪盛典，欽若薦禋宗。"]'),
('yuding-17','中宗祀昊天樂章：亞獻','不詳','唐','御定全唐诗','yuding','','[]','三靈降饗，三後配神。虔敷藻奠，敬展郊禋。',20,'御定全唐詩/json/010.json','["三靈降饗，三後配神。虔敷藻奠，敬展郊禋。"]'),
('yuding-18','中宗祀昊天樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','已陳粢盛敷嚴祀，更奏笙鏞協雅聲。',32,'御定全唐詩/json/010.json','["已陳粢盛敷嚴祀，更奏笙鏞協雅聲。", "璿圖寶曆欣甯謐，晏俗淳風樂太平。"]'),
('yuding-19','中宗祀昊天樂章：凱安','不詳','唐','御定全唐诗','yuding','','[]','堂堂聖祖興，赫赫昌基泰。戎車盟津偃，玉帛塗山會。',48,'御定全唐詩/json/010.json','["堂堂聖祖興，赫赫昌基泰。戎車盟津偃，玉帛塗山會。", "舜日啟祥暉，堯雲卷征旆。風猷被有截，聲教覃無外。"]'),
('yuding-20','明皇祀圜丘樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','至矣丕構，烝哉太平。授犧膺籙，複禹繼明。',40,'御定全唐詩/json/010.json','["至矣丕構，烝哉太平。授犧膺籙，複禹繼明。", "草木仁化，鳧鷖頌聲。祀宗陳德，無愧斯誠。"]'),
('yuding-21','明皇祀圜丘樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','郊壇齋帝，禮樂祀天。丹青寰宇，宮征山川。',40,'御定全唐詩/json/010.json','["郊壇齋帝，禮樂祀天。丹青寰宇，宮征山川。", "神祇畢降，行止重旋。融融穆穆，納祉洪延。"]'),
('yuding-22','明皇祀圜丘樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','止奏潛聆，登儀宿囀。太玉躬奉，參鐘首奠。',40,'御定全唐詩/json/010.json','["止奏潛聆，登儀宿囀。太玉躬奉，參鐘首奠。", "簠簋聿升，犧牲遞薦。昭事顒若，存存以伣。"]'),
('yuding-23','明皇祀圜丘樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','爛雲普洽，律風無外。千品其凝，九賓斯會。',40,'御定全唐詩/json/010.json','["爛雲普洽，律風無外。千品其凝，九賓斯會。", "禋尊晉燭，純犧滌汰。玄覆攸廣，鴻休汪濊。"]'),
('yuding-24','明皇祀圜丘樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','六變爰闋，八階載虔。佑我皇祚，于萬斯年。',20,'御定全唐詩/json/010.json','["六變爰闋，八階載虔。佑我皇祚，于萬斯年。"]'),
('yuding-25','明皇祀圜丘樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','于赫聖祖，龍飛晉陽。底定萬國，奄有四方。',40,'御定全唐詩/json/010.json','["于赫聖祖，龍飛晉陽。底定萬國，奄有四方。", "功格上下，道冠農黃。郊天配享，德合無疆。"]'),
('yuding-26','明皇祀圜丘樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','崇崇泰畤，肅肅嚴禋。粢盛既潔，金石畢陳。',40,'御定全唐詩/json/010.json','["崇崇泰畤，肅肅嚴禋。粢盛既潔，金石畢陳。", "上帝來享，介福爰臻。受厘合祉，寶祚維新。"]'),
('yuding-27','明皇祀圜丘樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','祝史正辭，人神葉慶。福以德招，享以誠應。',40,'御定全唐詩/json/010.json','["祝史正辭，人神葉慶。福以德招，享以誠應。", "六變雲備，百禮斯浹。祀事孔明。祚流萬葉。"]'),
('yuding-28','明皇祀圜丘樂章：凱安','不詳','唐','御定全唐诗','yuding','','[]','馨香惟後德，明命光天保。肅和崇聖靈，陳信表皇道。',36,'御定全唐詩/json/010.json','["馨香惟後德，明命光天保。肅和崇聖靈，陳信表皇道。", "玉戚初蹈厲，金匏既靜好。"]'),
('yuding-29','明皇祀圜丘樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','大號成命，思文配天。神光肸蚃，龍駕言旋。',40,'御定全唐詩/json/010.json','["大號成命，思文配天。神光肸蚃，龍駕言旋。", "眇眇閶闔，昭昭上玄。俾昌而大。於斯萬年。"]'),
('yuding-30','明皇祀圜丘樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','六成既闋，三薦雲終。神心具醉，聖敬愈崇。',40,'御定全唐詩/json/010.json','["六成既闋，三薦雲終。神心具醉，聖敬愈崇。", "受厘皇邸，回蹕帷宮。穰穰之福，永永無窮。"]'),
('yuding-31','封泰山樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','款泰壇，柴泰清。受天命，報天成。',208,'御定全唐詩/json/010.json','["款泰壇，柴泰清。受天命，報天成。", "竦皇心，薦樂聲。志上達，歌下迎。", "億上帝，臨下庭。騎日月，陪列星。", "嘉祝信，大糦馨。澹神心，醉皇靈。", "相百辟，貢八荒。九歌敘，萬舞翔。", "肅振振，鏗皇皇。帝欣欣，福穰穰。", "高在上，道光明。物資始，德難名。", "承眷命，牧蒼生。寰宇謐，太階平。", "天道無親，至誠與鄰。山川遍禮，宮征維新。", "玉帛非盛，聰明會真。正斯一德，通乎百神。", "饗帝饗親，維孝維聖。緝熙懿德，敷揚成命。", "華夷志同，笙鏞禮盛。明靈降止，感此誠敬。"]'),
('yuding-32','封泰山樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','孝敬中發，和容外彰。騰華照宇，如升太陽。',40,'御定全唐詩/json/010.json','["孝敬中發，和容外彰。騰華照宇，如升太陽。", "貞璧就奠，玄靈垂光。禮樂具舉，濟濟洋洋。"]'),
('yuding-33','封泰山樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','奠祖配天，承天享帝。百靈咸秩，四海來祭。',40,'御定全唐詩/json/010.json','["奠祖配天，承天享帝。百靈咸秩，四海來祭。", "植我蒼璧，布我玄制。華日裴回，神煙容裔。"]'),
('yuding-34','封泰山樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','俎豆有馥，粢盛潔豐。亦有和羹，既戒既平。',40,'御定全唐詩/json/010.json','["俎豆有馥，粢盛潔豐。亦有和羹，既戒既平。", "鐘鼓管磬，肅唱和鳴。皇皇後祖，來我思成。"]'),
('yuding-35','封泰山樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','烝烝我後，享獻惟夤。躬酌鬱鬯，跪奠明神。',40,'御定全唐詩/json/010.json','["烝烝我後，享獻惟夤。躬酌鬱鬯，跪奠明神。", "孝莫孝乎，配上帝親。敬莫敬乎，教天下臣。"]'),
('yuding-36','封泰山樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','皇祖嚴配，配享皇天。皇皇降嘏，天子萬年。',20,'御定全唐詩/json/010.json','["皇祖嚴配，配享皇天。皇皇降嘏，天子萬年。"]'),
('yuding-37','封泰山樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','六鐘翕協六變成，八佾倘佯八風生。',32,'御定全唐詩/json/010.json','["六鐘翕協六變成，八佾倘佯八風生。", "樂九韶兮人神感，美七德兮天地清。"]'),
('yuding-38','封泰山樂章：凱安','不詳','唐','御定全唐诗','yuding','','[]','烈祖順三靈，文宗威四海。黃鉞誅群盜，朱旗掃多罪。',48,'御定全唐詩/json/010.json','["烈祖順三靈，文宗威四海。黃鉞誅群盜，朱旗掃多罪。", "戢兵天下安，約法人心改。大哉幹羽意，長見風雲在。"]'),
('yuding-39','封泰山樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','樂已終，煙燎上。懷靈惠，結皇想。',32,'御定全唐詩/json/010.json','["樂已終，煙燎上。懷靈惠，結皇想。", "歸風疾，回風爽。百福來，眾神往。"]'),
('yuding-40','祈谷樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','履艮斯繩，居中體正。龍運垂祉，昭符啟聖。',40,'御定全唐詩/json/010.json','["履艮斯繩，居中體正。龍運垂祉，昭符啟聖。", "式事嚴禋，聿懷嘉慶。惟帝永錫，時皇休命。"]'),
('yuding-41','祈谷樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','殷薦乘春，太壇臨曙。八簋盈和，六瑚登禦。',40,'御定全唐詩/json/010.json','["殷薦乘春，太壇臨曙。八簋盈和，六瑚登禦。", "嘉稷匪歆，德馨斯飫。祝嘏無易，靈心有豫。"]'),
('yuding-42','祈谷樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','玉帛犧牲申敬享，金絲戚羽盛音容。',32,'御定全唐詩/json/010.json','["玉帛犧牲申敬享，金絲戚羽盛音容。", "庶俾億齡禔景福，長欣萬宇洽時邕。"]'),
('yuding-43','明堂樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','象天禦宇，乘時布政。嚴配申虔，宗禋展敬。',40,'御定全唐詩/json/010.json','["象天禦宇，乘時布政。嚴配申虔，宗禋展敬。", "樽罍盈列，樹羽交映。玉幣通誠，祚隆皇聖。"]'),
('yuding-44','明堂樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','八牖晨披，五精朝奠。霧凝璿篚，風清金縣。',40,'御定全唐詩/json/010.json','["八牖晨披，五精朝奠。霧凝璿篚，風清金縣。", "神滌備全，明粢豐衍。載絜彝俎，陳誠以薦。"]'),
('yuding-45','明堂樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','禦扆合宮承寶曆，席圖重館奉明靈。',32,'御定全唐詩/json/010.json','["禦扆合宮承寶曆，席圖重館奉明靈。", "偃武修文九圍泰，沉烽靜柝八荒寧。"]'),
('yuding-46','武后明堂樂章：外辦將出','不詳','唐','御定全唐诗','yuding','','[]','總章陳昔典，衢室禮惟神。巨集規則天地，神用葉陶鈞。',49,'御定全唐詩/json/010.json','["總章陳昔典，衢室禮惟神。巨集規則天地，神用葉陶鈞。", "負扆三春旦，充庭萬宇賓。顧己誠虛薄，空慚億兆人。"]'),
('yuding-47','武后明堂樂章：皇帝行','不詳','唐','御定全唐诗','yuding','','[]','仰膺歷數，俯順謳歌。遠安邇肅，俗阜時和。',40,'御定全唐詩/json/010.json','["仰膺歷數，俯順謳歌。遠安邇肅，俗阜時和。", "化光玉鏡，訟息金科。方興典禮，永戢干戈。"]'),
('yuding-48','武后明堂樂章：皇嗣出入升降','不詳','唐','御定全唐诗','yuding','','[]','至人光俗，大孝通神。謙以表性，恭惟立身。',40,'御定全唐詩/json/010.json','["至人光俗，大孝通神。謙以表性，恭惟立身。", "洪規載啟，茂典方陳。譽隆三善，祥開萬春。"]'),
('yuding-49','武后明堂樂章：迎送王公','不詳','唐','御定全唐诗','yuding','','[]','千官肅事，萬國朝宗。載延百辟，爰集三宮。',40,'御定全唐詩/json/010.json','["千官肅事，萬國朝宗。載延百辟，爰集三宮。", "君臣德合，魚水斯同。睿圖方永，周曆長隆。"]'),
('yuding-50','武后明堂樂章：登歌','不詳','唐','御定全唐诗','yuding','','[]','禮崇宗祀，志表嚴禋。笙鏞合奏，文物維新。',40,'御定全唐詩/json/010.json','["禮崇宗祀，志表嚴禋。笙鏞合奏，文物維新。", "敬遵茂典，敢擇良辰。絜誠斯著，奠謁方申。"]'),
('yuding-51','武后明堂樂章：配饗','不詳','唐','御定全唐诗','yuding','','[]','笙鏞間玉宇，文物昭清暉。睟影臨芳奠，休光下太微。',36,'御定全唐詩/json/010.json','["笙鏞間玉宇，文物昭清暉。睟影臨芳奠，休光下太微。", "孝思期有感，明絜庶無違。"]'),
('yuding-52','武后明堂樂章：宮音','不詳','唐','御定全唐诗','yuding','','[]','履艮包群望，居中冠百靈。萬方資廣運，庶品荷財成。',48,'御定全唐詩/json/010.json','["履艮包群望，居中冠百靈。萬方資廣運，庶品荷財成。", "神功諒匪測，盛德實難名。藻奠申誠敬，恭祀表惟馨。"]'),
('yuding-53','武后明堂樂章：角音','不詳','唐','御定全唐诗','yuding','','[]','出震位，開平秩。扇條風，乘甲乙。',32,'御定全唐詩/json/010.json','["出震位，開平秩。扇條風，乘甲乙。", "龍德盛，鳥星出。薦珪篚，陳誠實。"]'),
('yuding-54','武后明堂樂章：征音','不詳','唐','御定全唐诗','yuding','','[]','赫赫離精禦炎陸，滔滔熾景開隆暑。',32,'御定全唐詩/json/010.json','["赫赫離精禦炎陸，滔滔熾景開隆暑。", "冀延神鑒俯蘭樽，式表虔襟陳桂俎。"]'),
('yuding-55','武后明堂樂章：商音','不詳','唐','御定全唐诗','yuding','','[]','律中夷則，序應收成。功宣建武，義表惟明。',40,'御定全唐詩/json/010.json','["律中夷則，序應收成。功宣建武，義表惟明。", "爰申禮奠，庶展翹誠。九秋是式，百穀斯盈。"]'),
('yuding-56','武后明堂樂章：羽音','不詳','唐','御定全唐诗','yuding','','[]','葭律肇啟隆冬，蘋藻攸陳饗祭。',28,'御定全唐詩/json/010.json','["葭律肇啟隆冬，蘋藻攸陳饗祭。", "黃鐘既陳玉燭，紅粒方殷稔歲。"]'),
('yuding-57','雩祀樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','朱鳥開辰，蒼龍啟映。大帝昭饗，群生展敬。',40,'御定全唐詩/json/010.json','["朱鳥開辰，蒼龍啟映。大帝昭饗，群生展敬。", "禮備懷柔，功宣舞詠。旬液應序，年祥協慶。"]'),
('yuding-58','雩祀樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','紺筵分彩，寶圖吐絢。風管晨凝，雲歌曉囀。',40,'御定全唐詩/json/010.json','["紺筵分彩，寶圖吐絢。風管晨凝，雲歌曉囀。", "肅事蘭羞，虔申桂奠。百谷斯登，萬箱攸薦。"]'),
('yuding-59','雩祀樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','鳳曲登歌調令序，龍雩集舞泛祥風。',32,'御定全唐詩/json/010.json','["鳳曲登歌調令序，龍雩集舞泛祥風。", "彩旞雲回昭睿德，朱幹電發表神功。"]'),
('yuding-60','雩祀樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','鳥緯遷序，龍星見辰。純陽在律，明德崇禋。',40,'御定全唐詩/json/010.json','["鳥緯遷序，龍星見辰。純陽在律，明德崇禋。", "五方降帝，萬宇安人。恭以致享，肅以迎神。"]'),
('yuding-61','雩祀樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','祀遵經設，享緣誠舉。獻畢於樽，徹臨於俎。',40,'御定全唐詩/json/010.json','["祀遵經設，享緣誠舉。獻畢於樽，徹臨於俎。", "舞止幹戚，樂停柷敔。歌以送神，神還其所。"]'),
('yuding-0','郊廟歌辭：五郊樂章：黃帝宮音','不詳','唐','御定全唐诗','yuding','','[]','黃中正位，含章居貞。既長六律，兼和五聲。',40,'御定全唐詩/json/011.json','["黃中正位，含章居貞。既長六律，兼和五聲。", "畢陳萬舞，乃薦斯牲。神其下降，永祚休平。"]'),
('yuding-1','郊廟歌辭：五郊樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','眇眇方輿，蒼蒼圜蓋。至哉樞紐，宅中圖大。',40,'御定全唐詩/json/011.json','["眇眇方輿，蒼蒼圜蓋。至哉樞紐，宅中圖大。", "氣調四序，風和萬籟。祚我明德，時雍道泰。"]'),
('yuding-2','郊廟歌辭：五郊樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','金縣夕肆，玉俎朝陳。饗薦黃道，芬流紫宸。',40,'御定全唐詩/json/011.json','["金縣夕肆，玉俎朝陳。饗薦黃道，芬流紫宸。", "乃誠乃敬，載享載禋。崇薦斯在，惟皇是賓。"]'),
('yuding-3','郊廟歌辭：五郊樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','禦征乘宮出郊甸，安歌率舞遞將迎。',32,'御定全唐詩/json/011.json','["禦征乘宮出郊甸，安歌率舞遞將迎。", "自有雲門符帝賞，猶持雷鼓答天成。"]'),
('yuding-4','郊廟歌辭：五郊樂章：青帝角音','不詳','唐','御定全唐诗','yuding','','[]','鶴雲旦起，鳥星昏集。律候新風，陽開初蟄。',40,'御定全唐詩/json/011.json','["鶴雲旦起，鳥星昏集。律候新風，陽開初蟄。", "至德可饗，行潦斯挹。錫以無疆，蒸人乃粒。"]'),
('yuding-5','郊廟歌辭：五郊樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','玄鳥司春，蒼龍登歲。節物變柳，光風轉蕙。',40,'御定全唐詩/json/011.json','["玄鳥司春，蒼龍登歲。節物變柳，光風轉蕙。", "瑤席降神，朱弦饗帝。誠備祝嘏，禮殫珪幣。"]'),
('yuding-6','郊廟歌辭：五郊樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','大樂稀音，至誠簡禮。文物棣棣，聲明濟濟。',40,'御定全唐詩/json/011.json','["大樂稀音，至誠簡禮。文物棣棣，聲明濟濟。", "六變有成，三登無體。乃眷豐潔，恩覃愷悌。"]'),
('yuding-7','郊廟歌辭：五郊樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','笙歌鑰舞屬年韶，鷺鼓鳧鐘展時豫。',32,'御定全唐詩/json/011.json','["笙歌鑰舞屬年韶，鷺鼓鳧鐘展時豫。", "調露初迎綺春節，承雲遽踐蒼霄馭。"]'),
('yuding-8','郊廟歌辭：五郊樂章：赤帝征音','不詳','唐','御定全唐诗','yuding','','[]','青陽告謝，朱明戒序。延長是祈，敬陳椒醑。',40,'御定全唐詩/json/011.json','["青陽告謝，朱明戒序。延長是祈，敬陳椒醑。", "博碩斯薦，笙鏞備舉。庶盡肅恭，非馨稷黍。"]'),
('yuding-9','郊廟歌辭：五郊樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','離位克明，火中宵見。峰雲暮起，景風晨扇。',40,'御定全唐詩/json/011.json','["離位克明，火中宵見。峰雲暮起，景風晨扇。", "木槿初榮，含桃可薦。芬馥百品，鏗鏘三變。"]'),
('yuding-10','郊廟歌辭：五郊樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','昭昭丹陸，奕奕炎方。禮陳牲幣，樂備篪簧。',40,'御定全唐詩/json/011.json','["昭昭丹陸，奕奕炎方。禮陳牲幣，樂備篪簧。", "瓊羞溢俎，玉醑浮觴。恭惟正直，歆此馨香。"]'),
('yuding-11','郊廟歌辭：五郊樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','千里溫風飄絳羽，十枝炎景剩朱幹。',32,'御定全唐詩/json/011.json','["千里溫風飄絳羽，十枝炎景剩朱幹。", "陳觴薦俎歌三獻，拊石摐金會七盤。"]'),
('yuding-12','郊廟歌辭：五郊樂章：白帝商音','不詳','唐','御定全唐诗','yuding','','[]','白藏應節，天高氣清。歲功既阜，庶類收成。',40,'御定全唐詩/json/011.json','["白藏應節，天高氣清。歲功既阜，庶類收成。", "萬方靜謐，九土和平。馨香是薦，受祚聰明。"]'),
('yuding-13','郊廟歌辭：五郊樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','金行在節，素靈居正。氣肅霜嚴，林凋草勁。',40,'御定全唐詩/json/011.json','["金行在節，素靈居正。氣肅霜嚴，林凋草勁。", "豺祭隼擊，潦收川鏡。九谷已登，萬箱流詠。"]'),
('yuding-14','郊廟歌辭：五郊樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','律應西成，氣躔南呂。珪幣咸列，笙竽備舉。',40,'御定全唐詩/json/011.json','["律應西成，氣躔南呂。珪幣咸列，笙竽備舉。", "苾苾蘭羞，芬芬桂醑。式資宴貺，用調霜序。"]'),
('yuding-15','郊廟歌辭：五郊樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','璿儀氣爽驚緹鑰，玉呂灰飛含素商。',32,'御定全唐詩/json/011.json','["璿儀氣爽驚緹鑰，玉呂灰飛含素商。", "鳴鞞奏管芳羞薦，會舞安歌葆眊揚。"]'),
('yuding-16','郊廟歌辭：五郊樂章：黑帝羽音','不詳','唐','御定全唐诗','yuding','','[]','嚴冬季月，星回風厲。享祀報功，方祚來歲。',20,'御定全唐詩/json/011.json','["嚴冬季月，星回風厲。享祀報功，方祚來歲。"]'),
('yuding-17','郊廟歌辭：五郊樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','律回玉管，星周金度。次極陽烏，紀窮陰兔。',40,'御定全唐詩/json/011.json','["律回玉管，星周金度。次極陽烏，紀窮陰兔。", "火林霰雪，陽泉凝冱。八蠟已登，三農息務。"]'),
('yuding-18','郊廟歌辭：五郊樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','陽月斯紀，應鐘在候。載潔牲牷，爰登俎豆。',40,'御定全唐詩/json/011.json','["陽月斯紀，應鐘在候。載潔牲牷，爰登俎豆。", "既高既遠，無聲無臭。靜言格思，惟神保佑。"]'),
('yuding-19','郊廟歌辭：五郊樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','執鑰持羽初終曲，朱幹玉戚始分行。',32,'御定全唐詩/json/011.json','["執鑰持羽初終曲，朱幹玉戚始分行。", "七德九功咸已暢，明靈降福具穰穰。"]'),
('yuding-20','郊廟歌辭：五郊樂章：黃郊迎神','不詳','唐','御定全唐诗','yuding','','[]','朱明季序，黃郊王辰。厚以載物，甘以養人。',40,'御定全唐詩/json/011.json','["朱明季序，黃郊王辰。厚以載物，甘以養人。", "毓金為體，稟火成身。宮音式奏，奏以迎神。"]'),
('yuding-21','郊廟歌辭：五郊樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','春末冬暮，徂夏杪秋。土王四月，時季一周。',40,'御定全唐詩/json/011.json','["春末冬暮，徂夏杪秋。土王四月，時季一周。", "黍稷已享，籩豆宜收。送神有樂，神其賜休。"]'),
('yuding-22','郊廟歌辭：五郊樂章：青郊迎神','不詳','唐','御定全唐诗','yuding','','[]','緹幕移候，青郊啟蟄。淑景遲遲，和風習習。',40,'御定全唐詩/json/011.json','["緹幕移候，青郊啟蟄。淑景遲遲，和風習習。", "璧玉宵備，旌旄曙立。張樂以迎，帝神其入。"]'),
('yuding-23','郊廟歌辭：五郊樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','文物流彩，聲明動色。人竭其恭，靈昭其飭。',40,'御定全唐詩/json/011.json','["文物流彩，聲明動色。人竭其恭，靈昭其飭。", "歆薦不已，垂禎無極。送禮有章，惟神還軾。"]'),
('yuding-24','郊廟歌辭：五郊樂章：赤郊迎神','不詳','唐','御定全唐诗','yuding','','[]','青陽節謝，朱明候改。靡草凋華，含桃流彩。',40,'御定全唐詩/json/011.json','["青陽節謝，朱明候改。靡草凋華，含桃流彩。", "簴列鐘磬，筵陳脯醢。樂以迎神，神其如在。"]'),
('yuding-25','郊廟歌辭：五郊樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','炎精式降，蒼生攸仰。羞列豆籩，酒陳犧象。',40,'御定全唐詩/json/011.json','["炎精式降，蒼生攸仰。羞列豆籩，酒陳犧象。", "昭祀有應，冥期不爽。送樂張音，惟靈之往。"]'),
('yuding-26','郊廟歌辭：五郊樂章：白郊迎神','不詳','唐','御定全唐诗','yuding','','[]','序移玉律，節應金商。天嚴殺氣，吹警秋方。',40,'御定全唐詩/json/011.json','["序移玉律，節應金商。天嚴殺氣，吹警秋方。", "槱燎既積，稷奠並芳。樂以迎奏，庶降神光。"]'),
('yuding-27','郊廟歌辭：五郊樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','祀遵五禮，時屬三秋。人懷肅敬，靈降禎休。',40,'御定全唐詩/json/011.json','["祀遵五禮，時屬三秋。人懷肅敬，靈降禎休。", "奠歆旨酒，薦享珍羞。載張送樂，神其上游。"]'),
('yuding-28','郊廟歌辭：五郊樂章：黑郊迎神','不詳','唐','御定全唐诗','yuding','','[]','玄英戒序，黑郊臨候。掌禮陳彝，司筵執豆。',40,'御定全唐詩/json/011.json','["玄英戒序，黑郊臨候。掌禮陳彝，司筵執豆。", "寒氛斂色，冱泉凝漏。樂以迎神，八音斯奏。"]'),
('yuding-29','郊廟歌辭：五郊樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','北郊時冽，南陸輝處。奠本虔誠，獻彌恭慮。',40,'御定全唐詩/json/011.json','["北郊時冽，南陸輝處。奠本虔誠，獻彌恭慮。", "上延祉福，下承歡豫。廣樂送神，神其整馭。"]'),
('yuding-30','郊廟歌辭：朝日樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','惟聖格天，惟明饗日。帝郊肆類，王宮戒吉。',40,'御定全唐詩/json/011.json','["惟聖格天，惟明饗日。帝郊肆類，王宮戒吉。", "珪奠春舒，鐘歌曉溢。禮雲克備，斯文有秩。"]'),
('yuding-31','郊廟歌辭：朝日樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','晨儀式薦，明祀惟光。神物爰止，靈暉載揚。',40,'御定全唐詩/json/011.json','["晨儀式薦，明祀惟光。神物爰止，靈暉載揚。", "玄端肅事，紫幄興祥。福履攸假，于昭允王。"]'),
('yuding-32','郊廟歌辭：朝日樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','崇牙樹羽延調露，旋宮扣律掩承雲。',32,'御定全唐詩/json/011.json','["崇牙樹羽延調露，旋宮扣律掩承雲。", "誕敷懿德昭神武，載集豐功表睿文。"]'),
('yuding-33','郊廟歌辭：朝日樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','太陽朝序，王宮有儀。蟠桃彩駕，細柳光馳。',40,'御定全唐詩/json/011.json','["太陽朝序，王宮有儀。蟠桃彩駕，細柳光馳。", "軒祥表合，漢曆彰奇。禮和樂備，神其降斯。"]'),
('yuding-34','郊廟歌辭：朝日樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','五齊兼酌，百羞具陳。樂終廣奏，禮畢崇禋。',40,'御定全唐詩/json/011.json','["五齊兼酌，百羞具陳。樂終廣奏，禮畢崇禋。", "明鑒萬宇，照臨兆人。永流洪慶，式動曦輪。"]'),
('yuding-35','郊廟歌辭：夕月樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','測妙為神，通微曰聖。坎祀貽則，郊禋展敬。',40,'御定全唐詩/json/011.json','["測妙為神，通微曰聖。坎祀貽則，郊禋展敬。", "璧薦登光，金歌動映。以載嘉德，以流曾慶。"]'),
('yuding-36','郊廟歌辭：夕月樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','朏晨爭舉，天宗禮辟。夜典涼秋，陰明湛夕。',92,'御定全唐詩/json/011.json','["朏晨爭舉，天宗禮辟。夜典涼秋，陰明湛夕。", "有z0斯旨，有牲斯碩。穆穆其暉，穰穰是積。卷11_3《郊廟歌辭。夕月樂章。舒和》", "合吹八風金奏動，分容萬舞玉鞘驚。", "詞昭茂典光前列，夕曜乘功表盛明。"]'),
('yuding-37','郊廟歌辭：祀九宮貴神樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','於昭上穹，臨下有光。羽翼五佐，周流八荒。',240,'御定全唐詩/json/011.json','["於昭上穹，臨下有光。羽翼五佐，周流八荒。", "誰其饗之，時文對揚。虞經夏典，茲禮未遑。", "黑帝旋馭，青躔導日。金籙上玄，玉堂初吉。", "鉤陳夕次，鑾和先蹕。藹藹群靈，昭昭咸秩。", "帝臨中壇，受厘元神。皇靈萃止，羽旄肅陳。", "攝提運衡，招搖移輪。光光宇宙，電耀雷震。", "夜如何其，明星煌煌。天清容衛，露結壇場。", "樹羽幢幢，佩玉鏘鏘。凝精駐目，瞻望神光。", "九位既肅，萬靈畢會。天門啟扃，日馭飛蓋。", "煥兮棽離，儐兮暗靄。如山之福，惟聖時對。", "崇崇泰壇，靈具臨兮。鏗鍠大樂，振動心兮。", "神之降矣，卿雲鬱兮。神之至止，清風肅兮。"]'),
('yuding-38','郊廟歌辭：祀九宮貴神樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','帝在靈壇，大明登光。天回雲粹，穆穆皇皇。',40,'御定全唐詩/json/011.json','["帝在靈壇，大明登光。天回雲粹，穆穆皇皇。", "金奏九夏，圭陳八薌。曠哉動植，如熙春陽。"]'),
('yuding-39','郊廟歌辭：祀九宮貴神樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','歌工既奏，神位既秩。天符眾星，運行太一。',40,'御定全唐詩/json/011.json','["歌工既奏，神位既秩。天符眾星，運行太一。", "聲和十管，氣應中律。肅肅明廷，介茲元吉。"]'),
('yuding-40','郊廟歌辭：祀九宮貴神樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','俎豆有踐，黃流在尊。九宮之祀，三代莫存。',40,'御定全唐詩/json/011.json','["俎豆有踐，黃流在尊。九宮之祀，三代莫存。", "樂變六宮，壇開八門。聖皇昭對，佑我黎元。"]'),
('yuding-41','郊廟歌辭：祀九宮貴神樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','時文哲後，肅事嚴禋。馨我明德，享於貴神。',40,'御定全唐詩/json/011.json','["時文哲後，肅事嚴禋。馨我明德，享於貴神。", "大庖載盈，旨酒斯醇。精意所屬，期於利人。"]'),
('yuding-42','郊廟歌辭：祀九宮貴神樂章：福和','不詳','唐','御定全唐诗','yuding','','[]','祀既雲畢，明靈告旋。禮洽和應，神歆福延。',40,'御定全唐詩/json/011.json','["祀既雲畢，明靈告旋。禮洽和應，神歆福延。", "動植咸若，陰陽不愆。錫茲純嘏，天子萬年。"]'),
('yuding-43','郊廟歌辭：祀九宮貴神樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','羽鑰既闋幹戚陳，八音克諧六變新。',32,'御定全唐詩/json/011.json','["羽鑰既闋幹戚陳，八音克諧六變新。", "愉貴神兮般以樂，保皇祚兮萬斯春。"]'),
('yuding-44','郊廟歌辭：祀九宮貴神樂章：凱安','不詳','唐','御定全唐诗','yuding','','[]','盛德陳萬舞，威棱暢九垓。風雲交律候，日月麗昭回。',48,'御定全唐詩/json/011.json','["盛德陳萬舞，威棱暢九垓。風雲交律候，日月麗昭回。", "行慶休祥發，乘和春氣來。百神肅臨享，蕩蕩天門開。"]'),
('yuding-45','郊廟歌辭：祀九宮貴神樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','精意嚴恭，明祠豐潔。獻酬既備，俎豆斯撤。',40,'御定全唐詩/json/011.json','["精意嚴恭，明祠豐潔。獻酬既備，俎豆斯撤。", "日麗天儀，風和樂節。事光祀典，福覃有截。"]'),
('yuding-46','郊廟歌辭：祀九宮貴神樂章：豫和','不詳','唐','御定全唐诗','yuding','','[]','享申百禮，慶洽百靈。上排閶闔，洞入杳冥。',40,'御定全唐詩/json/011.json','["享申百禮，慶洽百靈。上排閶闔，洞入杳冥。", "奠玉高壇，燔柴廣庭。神之降福，萬國咸寧。"]'),
('yuding-47','郊廟歌辭：祀風師樂章：迎神','包佶','唐','御定全唐诗','yuding','','[]','太皞禦氣，句芒肇功。蒼龍青旗，爰候祥風。',40,'御定全唐詩/json/011.json','["太皞禦氣，句芒肇功。蒼龍青旗，爰候祥風。", "律以和應，神以感通。鼎俎修蚃，時惟禮崇。"]'),
('yuding-48','郊廟歌辭：祀風師樂章：奠幣登歌','包佶','唐','御定全唐诗','yuding','','[]','旨酒告絜，青蘋應候。禮陳瑤幣，樂獻金奏。',40,'御定全唐詩/json/011.json','["旨酒告絜，青蘋應候。禮陳瑤幣，樂獻金奏。", "彈弦自昔，解凍惟舊。仰瞻肸蚃，群祥來湊。"]'),
('yuding-49','郊廟歌辭：祀風師樂章：迎俎酌獻','包佶','唐','御定全唐诗','yuding','','[]','德盛昭臨，迎拜巽方。爰候發生，式薦馨香。',40,'御定全唐詩/json/011.json','["德盛昭臨，迎拜巽方。爰候發生，式薦馨香。", "酌醴具舉，工歌載揚。神歆六律，恩降百祥。"]'),
('yuding-50','郊廟歌辭：祀風師樂章：亞獻終獻','包佶','唐','御定全唐诗','yuding','','[]','膋薌備，玉帛陳。風動物，樂感神。',32,'御定全唐詩/json/011.json','["膋薌備，玉帛陳。風動物，樂感神。", "三獻終，百神臻。草木榮，天下春。"]'),
('yuding-51','郊廟歌辭：祀風師樂章：送神','包佶','唐','御定全唐诗','yuding','','[]','微穆敷華能應節，飄揚發彩宜行慶。送迎靈駕神心享，',40,'御定全唐詩/json/011.json','["微穆敷華能應節，飄揚發彩宜行慶。送迎靈駕神心享，", "永望翠蓋逐流雲，自茲率土調春令。"]'),
('yuding-52','郊廟歌辭：祀雨師樂章：迎神','包佶','唐','御定全唐诗','yuding','','[]','陟降左右，誠達幽圜。作解之功，樂惟有年。',40,'御定全唐詩/json/011.json','["陟降左右，誠達幽圜。作解之功，樂惟有年。", "雲輧戾止，灑霧飄煙。惟馨展禮，爰列豆籩。"]'),
('yuding-53','郊廟歌辭：祀雨師樂章：奠幣登歌','包佶','唐','御定全唐诗','yuding','','[]','歲正朱明，禮布元制。惟樂能感，與神合契。',40,'御定全唐詩/json/011.json','["歲正朱明，禮布元制。惟樂能感，與神合契。", "陰霧離披，靈馭搖裔。膏澤之慶，期於稔歲。"]'),
('yuding-54','郊廟歌辭：祀雨師樂章：迎俎酌獻','包佶','唐','御定全唐诗','yuding','','[]','陽開幽蟄，躬奉鬱鬯。禮備節應，震來靈降。',40,'御定全唐詩/json/011.json','["陽開幽蟄，躬奉鬱鬯。禮備節應，震來靈降。", "動植求聲，飛沉允望。時康氣茂，惟神之貺。"]'),
('yuding-55','郊廟歌辭：祀雨師樂章：亞獻終獻','包佶','唐','御定全唐诗','yuding','','[]','奠既備，獻將終。神行令，瑞飛空。',32,'御定全唐詩/json/011.json','["奠既備，獻將終。神行令，瑞飛空。", "迎幹德，祈歲功。乘煙燎，儼從風。"]'),
('yuding-56','郊廟歌辭：祀雨師樂章：送神','包佶','唐','御定全唐诗','yuding','','[]','整駕升車望寥廓，垂陰薦祉蕩昏氛。饗時靈貺僾如在。',64,'御定全唐詩/json/011.json','["整駕升車望寥廓，垂陰薦祉蕩昏氛。饗時靈貺僾如在。", "樂罷餘聲遙可聞。飲福陳誠禮容備，撤俎終獻曙光分。", "跪拜臨壇結空想，年年應節候油雲。"]'),
('yuding-0','郊廟歌辭：祭方丘樂章：順和','不詳','唐','御定全唐诗','yuding','','[]','萬方資以化，交泰屬升平。易從業惟簡，得一道斯寧。',48,'御定全唐詩/json/012.json','["萬方資以化，交泰屬升平。易從業惟簡，得一道斯寧。", "具儀光玉帛，送舞變咸英。黍稷良非貴，明德信惟馨。"]'),
('yuding-1','郊廟歌辭：祭方丘樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','至矣坤德，皇哉地祇。開元統紐，合大承規。',40,'御定全唐詩/json/012.json','["至矣坤德，皇哉地祇。開元統紐，合大承規。", "九宮肅列，六典相儀。永言配命，長保無虧。"]'),
('yuding-2','郊廟歌辭：祭方丘樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','柔而能方，直而能敬。載厚以德，大亨以正。',40,'御定全唐詩/json/012.json','["柔而能方，直而能敬。載厚以德，大亨以正。", "有滌斯牷，有馨斯盛。介茲景福，祚我休慶。"]'),
('yuding-3','郊廟歌辭：祭方丘樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','玉幣牲牷分薦享，羽旄幹戚遞成容。',32,'御定全唐詩/json/012.json','["玉幣牲牷分薦享，羽旄幹戚遞成容。", "一德惟寧兩儀泰，三才保合四時邕。"]'),
('yuding-4','郊廟歌辭：祭方丘樂章：順和','不詳','唐','御定全唐诗','yuding','','[]','陰祇協贊，厚載方貞。牲幣具舉，簫管備成。',40,'御定全唐詩/json/012.json','["陰祇協贊，厚載方貞。牲幣具舉，簫管備成。", "其禮惟肅，其德惟明。神之聽矣，式鑒虔誠。"]'),
('yuding-5','郊廟歌辭：武后大享拜洛樂章：昭和','不詳','唐','御定全唐诗','yuding','','[]','九玄眷命，三聖基隆。奉承先旨，明台畢功。',40,'御定全唐詩/json/012.json','["九玄眷命，三聖基隆。奉承先旨，明台畢功。", "宗祀展敬，冀表深衷。永昌帝業，式播淳風。"]'),
('yuding-6','郊廟歌辭：武后大享拜洛樂章：致和','不詳','唐','御定全唐诗','yuding','','[]','神功不測兮運陰陽，包藏萬宇兮孕八荒。',36,'御定全唐詩/json/012.json','["神功不測兮運陰陽，包藏萬宇兮孕八荒。", "天符既出兮帝業昌，願臨明祀兮降禎祥。"]'),
('yuding-7','郊廟歌辭：武后大享拜洛樂章：咸和','不詳','唐','御定全唐诗','yuding','','[]','坎澤祠容備舉，坤壇祭典爰申。靈眷遙行秘躅，',28,'御定全唐詩/json/012.json','["坎澤祠容備舉，坤壇祭典爰申。靈眷遙行秘躅，", "方期交際懸應。"]'),
('yuding-8','郊廟歌辭：武后大享拜洛樂章：九和','不詳','唐','御定全唐诗','yuding','','[]','祗荷坤德，欽若干靈。慚惕罔置，興居匪寧。',40,'御定全唐詩/json/012.json','["祗荷坤德，欽若干靈。慚惕罔置，興居匪寧。", "恭崇禮則，肅奉儀形。惟憑展敬，敢薦非馨。"]'),
('yuding-9','郊廟歌辭：武后大享拜洛樂章：顯和','不詳','唐','御定全唐诗','yuding','','[]','菲躬承睿顧，薄德忝坤儀。幹幹遵後命，翼翼奉先規。',48,'御定全唐詩/json/012.json','["菲躬承睿顧，薄德忝坤儀。幹幹遵後命，翼翼奉先規。", "撫俗勤雖切，還淳化尚虧。未能弘至道，何以契明祇。"]'),
('yuding-10','郊廟歌辭：武后大享拜洛樂章：顯和','不詳','唐','御定全唐诗','yuding','','[]','顧德有慚虛菲，明祇屢降禎符。汜水初呈秘象，',21,'御定全唐詩/json/012.json','["顧德有慚虛菲，明祇屢降禎符。汜水初呈秘象，"]'),
('yuding-11','郊廟歌辭：武后大享拜洛樂章：昭和','不詳','唐','御定全唐诗','yuding','','[]','舒陰致養，合大資生。德以恒固，功由永貞。',40,'御定全唐詩/json/012.json','["舒陰致養，合大資生。德以恒固，功由永貞。", "升歌薦序，垂幣翹誠。虹開玉照，鳳引金聲。"]'),
('yuding-12','郊廟歌辭：武后大享拜洛樂章：敬和','不詳','唐','御定全唐诗','yuding','','[]','蘭俎既升，蘋羞可薦。金石載設，咸英已變。',40,'御定全唐詩/json/012.json','["蘭俎既升，蘋羞可薦。金石載設，咸英已變。", "林澤斯總，山川是遍。敢用敷誠，實惟忘倦。"]'),
('yuding-13','郊廟歌辭：武后大享拜洛樂章：齊和','不詳','唐','御定全唐诗','yuding','','[]','沈潛演貺分三極，廣大凝禎總萬方。',32,'御定全唐詩/json/012.json','["沈潛演貺分三極，廣大凝禎總萬方。", "既薦羽旌文化啟，還呈幹戚武威揚。"]'),
('yuding-14','郊廟歌辭：武后大享拜洛樂章：德和','不詳','唐','御定全唐诗','yuding','','[]','夕惕司龍契，晨兢當鳳扆。崇儒習舊規，偃伯循先旨。',48,'御定全唐詩/json/012.json','["夕惕司龍契，晨兢當鳳扆。崇儒習舊規，偃伯循先旨。", "絕壤飛冠蓋，遐區麗山水。幸承三聖餘，忻屬千年始。"]'),
('yuding-15','郊廟歌辭：武后大享拜洛樂章：禋和','不詳','唐','御定全唐诗','yuding','','[]','百禮崇容，千官肅事。靈降無兆，神凝有粹。',40,'御定全唐詩/json/012.json','["百禮崇容，千官肅事。靈降無兆，神凝有粹。", "奠享咸周，威儀畢備。奏夏登列，歌雍徹肆。"]'),
('yuding-16','郊廟歌辭：武后大享拜洛樂章：通和','不詳','唐','御定全唐诗','yuding','','[]','皇皇靈眷，穆穆神心。暫動凝質，還歸積陰。',40,'御定全唐詩/json/012.json','["皇皇靈眷，穆穆神心。暫動凝質，還歸積陰。", "功玄樞紐，理寂高深。銜恩佩德，聳志翹襟。"]'),
('yuding-17','郊廟歌辭：武后大享拜洛樂章：歸和','不詳','唐','御定全唐诗','yuding','','[]','言旋雲洞兮躡煙途，永寧中宇兮安下都。',36,'御定全唐詩/json/012.json','["言旋雲洞兮躡煙途，永寧中宇兮安下都。", "包涵動植兮順榮枯，長貽寶貺兮贊璿圖。"]'),
('yuding-18','郊廟歌辭：武后大享拜洛樂章：又歸和','不詳','唐','御定全唐诗','yuding','','[]','調雲闋兮神座興，驂雲駕兮儼將升。',32,'御定全唐詩/json/012.json','["調雲闋兮神座興，驂雲駕兮儼將升。", "騰絳霄兮垂景佑，翹丹懇兮荷休征。"]'),
('yuding-19','郊廟歌辭：祭方丘樂章：順和','不詳','唐','御定全唐诗','yuding','','[]','坤厚載物，德柔垂祉。九域咸雍，四溟為紀。',40,'御定全唐詩/json/012.json','["坤厚載物，德柔垂祉。九域咸雍，四溟為紀。", "敬因良節，虔修陰祀。廣樂式張，靈其降止。"]'),
('yuding-20','郊廟歌辭：祭方丘樂章：金奏','不詳','唐','御定全唐诗','yuding','','[]','坤元至德，品物資生。神凝博厚，道協高明。',40,'御定全唐詩/json/012.json','["坤元至德，品物資生。神凝博厚，道協高明。", "列鎮五嶽，環流四瀛。于何不載，萬寶斯成。"]'),
('yuding-21','郊廟歌辭：祭方丘樂章：順和','不詳','唐','御定全唐诗','yuding','','[]','樂備金石，禮光尊俎。大享爰終，洪休是舉。',40,'御定全唐詩/json/012.json','["樂備金石，禮光尊俎。大享爰終，洪休是舉。", "雨零感節，雲飛應序。纓紱載辭，皇靈具舉。"]'),
('yuding-22','郊廟歌辭：祭汾陰樂章：順和','韓思複','唐','御定全唐诗','yuding','','[]','大樂和暢，殷薦明神。一降通感，八變必臻。',40,'御定全唐詩/json/012.json','["大樂和暢，殷薦明神。一降通感，八變必臻。", "有求斯應，無德不親。降靈醉止，休征萬人。"]'),
('yuding-23','郊廟歌辭：祭汾陰樂章：太簇角','盧從願','唐','御定全唐诗','yuding','','[]','坤元載物，陽樂發生。播殖資始，品匯咸亨。',40,'御定全唐詩/json/012.json','["坤元載物，陽樂發生。播殖資始，品匯咸亨。", "列俎棋布，方壇砥平。神歆禋祀，後德惟明。"]'),
('yuding-24','郊廟歌辭：祭汾陰樂章：姑洗征','劉晃','唐','御定全唐诗','yuding','','[]','大君出震，有事郊禋。齋戒既肅，馨香畢陳。',40,'御定全唐詩/json/012.json','["大君出震，有事郊禋。齋戒既肅，馨香畢陳。", "樂和禮備，候暖風春。恭惟降福，實賴明神。"]'),
('yuding-25','郊廟歌辭：祭汾陰樂章：南呂羽','韓休','唐','御定全唐诗','yuding','','[]','于穆浚哲，維清緝熙。肅事昭配，永言孝思。',40,'御定全唐詩/json/012.json','["于穆浚哲，維清緝熙。肅事昭配，永言孝思。", "滌濯靜嘉，馨香在茲。神之聽之，用受福厘。"]'),
('yuding-26','郊廟歌辭：祭汾陰樂章：太和','王晙','唐','御定全唐诗','yuding','','[]','于穆聖皇，六葉重光。太原刻頌，後土疏場。',40,'御定全唐詩/json/012.json','["于穆聖皇，六葉重光。太原刻頌，後土疏場。", "寶鼎呈符，歊雲孕祥。禮樂備矣，降福穰穰。"]'),
('yuding-27','郊廟歌辭：祭汾陰樂章：肅和','崔玄童','唐','御定全唐诗','yuding','','[]','聿修嚴配，展事禋宗。祥符寶鼎，禮備黃琮。',40,'御定全唐詩/json/012.json','["聿修嚴配，展事禋宗。祥符寶鼎，禮備黃琮。", "祝詞以信，明德惟聰。介茲景福，永永無窮。"]'),
('yuding-28','郊廟歌辭：祭汾陰樂章：雍和','賈曾','唐','御定全唐诗','yuding','','[]','蠲我饎餴，絜我膋薌。有豆孔碩，為羞既臧。',40,'御定全唐詩/json/012.json','["蠲我饎餴，絜我膋薌。有豆孔碩，為羞既臧。", "至誠無昧，精意惟芳。神其醉止，欣欣樂康。"]'),
('yuding-29','郊廟歌辭：祭汾陰樂章：壽和','蘇頲','唐','御定全唐诗','yuding','','[]','禮物斯具，樂章乃陳。誰其作主，皇考聖真。',40,'御定全唐詩/json/012.json','["禮物斯具，樂章乃陳。誰其作主，皇考聖真。", "對越在天，聖明佐神。窅然汾上，厚澤如春。"]'),
('yuding-30','郊廟歌辭：祭汾陰樂章：舒和','何鸞','唐','御定全唐诗','yuding','','[]','樂奏雲闋，禮章載虔。禋宗於地，昭假於天。',40,'御定全唐詩/json/012.json','["樂奏雲闋，禮章載虔。禋宗於地，昭假於天。", "惟馨薦矣，既醉歆焉。神之降福，永永萬年。"]'),
('yuding-31','郊廟歌辭：祭汾陰樂章：凱安','蔣挺','唐','御定全唐诗','yuding','','[]','維歲之吉，維辰之良。聖君紱冕，肅事壇場。',40,'御定全唐詩/json/012.json','["維歲之吉，維辰之良。聖君紱冕，肅事壇場。", "大禮已備，大樂斯張。神其醉止，降福無疆。"]'),
('yuding-32','郊廟歌辭：祭汾陰樂章：順和','源光裕','唐','御定全唐诗','yuding','','[]','方丘既膳，嘉饗載謐。齊敬畢誠，陶匏貴質。',40,'御定全唐詩/json/012.json','["方丘既膳，嘉饗載謐。齊敬畢誠，陶匏貴質。", "秀畢豐薦，芳俎盈實。永永福流，其升如日。"]'),
('yuding-33','郊廟歌辭：禪社首樂章：順和','不詳','唐','御定全唐诗','yuding','','[]','至哉含柔德，萬物資以生。常順稱厚載，流謙通變盈。',48,'御定全唐詩/json/012.json','["至哉含柔德，萬物資以生。常順稱厚載，流謙通變盈。", "聖心事能察，增廣陳厥誠。黃祇僾如在，泰折俟咸亨。"]'),
('yuding-34','郊廟歌辭：禪社首樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','肅我成命，于昭黃祇。裘冕而祀，陟降在斯。',40,'御定全唐詩/json/012.json','["肅我成命，于昭黃祇。裘冕而祀，陟降在斯。", "五音克備，八音聿施。緝熙肆靖，厥心匪離。"]'),
('yuding-35','郊廟歌辭：禪社首樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','黃祇是祗，我其夙夜。寅畏誠絜，匪遑寧舍。',40,'御定全唐詩/json/012.json','["黃祇是祗，我其夙夜。寅畏誠絜，匪遑寧舍。", "禮以琮玉，薦厥茅藉。念茲降康，胡寧克暇。"]'),
('yuding-36','郊廟歌辭：禪社首樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','夙夜宥密，不敢寧宴。五齊既陳，八音在縣。',40,'御定全唐詩/json/012.json','["夙夜宥密，不敢寧宴。五齊既陳，八音在縣。", "粢盛以潔，房俎斯薦。惟德惟馨，尚茲克遍。"]'),
('yuding-37','郊廟歌辭：禪社首樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','惟以明發，有懷載殷。樂盈而反，禮順其禋。',40,'御定全唐詩/json/012.json','["惟以明發，有懷載殷。樂盈而反，禮順其禋。", "立清以獻，薦欲是親。于穆不已，裒對斯臻。"]'),
('yuding-38','郊廟歌辭：禪社首樂章：福和','不詳','唐','御定全唐诗','yuding','','[]','穆穆天子，告成岱宗。大裘如濡，執珽有顒。',40,'御定全唐詩/json/012.json','["穆穆天子，告成岱宗。大裘如濡，執珽有顒。", "樂以平志，禮以和容。上帝臨我，雲胡肅邕。"]'),
('yuding-39','郊廟歌辭：禪社首樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','昭昭有唐，天俾萬國。列祖應命，四宗順則。',40,'御定全唐詩/json/012.json','["昭昭有唐，天俾萬國。列祖應命，四宗順則。", "申錫無疆，宗我同德。曾孫繼序，享神配極。"]'),
('yuding-40','郊廟歌辭：禪社首樂章：靈具醉','不詳','唐','御定全唐诗','yuding','','[]','靈具醉，杳熙熙。靈將往，眇禗禗。',32,'御定全唐詩/json/012.json','["靈具醉，杳熙熙。靈將往，眇禗禗。", "顧明德，吐正辭。爛遺光，流禎祺。"]'),
('yuding-41','郊廟歌辭：祭神州樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','大矣坤儀，至哉神縣。包含日域，牢籠月竁。',40,'御定全唐詩/json/012.json','["大矣坤儀，至哉神縣。包含日域，牢籠月竁。", "露絜三清，風調六變。皇祇介祉，式歆恭薦。"]'),
('yuding-42','郊廟歌辭：祭神州樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','泰折嚴享，陰郊展敬。禮以導神，樂以和性。',40,'御定全唐詩/json/012.json','["泰折嚴享，陰郊展敬。禮以導神，樂以和性。", "黝牲在列，黃琮俯映。九土既平，萬邦貽慶。"]'),
('yuding-43','郊廟歌辭：祭神州樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','坤道降祥和庶品，靈心載德厚群生。',32,'御定全唐詩/json/012.json','["坤道降祥和庶品，靈心載德厚群生。", "水土既調三極泰，文武畢備九區平。"]'),
('yuding-44','郊廟歌辭：祭神州樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','黃輿厚載，赤寰歸德。含育九區，保安萬國。',40,'御定全唐詩/json/012.json','["黃輿厚載，赤寰歸德。含育九區，保安萬國。", "誠敬無怠，禋祀有則。樂以迎神，其儀不忒。"]'),
('yuding-45','郊廟歌辭：祭神州樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','神州陰祀，洪恩廣濟。草樹沾和，飛沉沐惠。',40,'御定全唐詩/json/012.json','["神州陰祀，洪恩廣濟。草樹沾和，飛沉沐惠。", "禮修鼎俎，奠歆瑤幣。送樂有章，靈軒其逝。"]'),
('yuding-46','郊廟歌辭：祭太社樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','後土凝德，神功協契。九域底平，兩儀交際。',40,'御定全唐詩/json/012.json','["後土凝德，神功協契。九域底平，兩儀交際。", "戊期應序，陰墉展幣。靈車少留，俯歆樽桂。"]'),
('yuding-47','郊廟歌辭：祭太社樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','美報崇本，嚴恭展事。受露疏壇，承風啟地。',40,'御定全唐詩/json/012.json','["美報崇本，嚴恭展事。受露疏壇，承風啟地。", "絜粢登俎，醇犧入饋。介福遠流，群生畢遂。"]'),
('yuding-48','郊廟歌辭：祭太社樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','神道發生敷九稼，陰極乘仁暢八埏。',32,'御定全唐詩/json/012.json','["神道發生敷九稼，陰極乘仁暢八埏。", "緯武經文隆景化，登祥薦祉啟豐年。"]'),
('yuding-49','郊廟歌辭：祭太社樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','烈山有子，後土有臣。播種百穀，濟育兆人。',40,'御定全唐詩/json/012.json','["烈山有子，後土有臣。播種百穀，濟育兆人。", "春官緝禮，宗伯司禋。戊為吉日，迎享茲辰。"]'),
('yuding-50','郊廟歌辭：祭太社樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','吉祥式就，酬功載畢。親地尊天，禮文經術。',40,'御定全唐詩/json/012.json','["吉祥式就，酬功載畢。親地尊天，禮文經術。", "貺征令序，福流初日。神馭爰歸，祠官其出。"]'),
('yuding-51','郊廟歌辭：蠟百神樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','序迫歲陰，日躔星紀。爰稽茂典，聿崇清祀。',40,'御定全唐詩/json/012.json','["序迫歲陰，日躔星紀。爰稽茂典，聿崇清祀。", "綺幣霞舒，瑞珪虹起。百禩垂裕，萬靈薦祉。"]'),
('yuding-52','郊廟歌辭：蠟百神樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','緹鑰勁序，玄英晚候。姬蠟開儀，豳歌入奏。',40,'御定全唐詩/json/012.json','["緹鑰勁序，玄英晚候。姬蠟開儀，豳歌入奏。", "蕙馥雕俎，蘭芬玉酎。大享明祇，永綏多佑。"]'),
('yuding-53','郊廟歌辭：蠟百神樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','經緯兩儀文化洽，削平方域武功成。',32,'御定全唐詩/json/012.json','["經緯兩儀文化洽，削平方域武功成。", "瑤弦自樂乾坤泰，玉戚長歡區宇寧。"]'),
('yuding-54','郊廟歌辭：蠟百神樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','八蠟開祭，萬物合祀。上極天維，下窮坤紀。',40,'御定全唐詩/json/012.json','["八蠟開祭，萬物合祀。上極天維，下窮坤紀。", "鼎俎流芬，樽彝薦美。有靈有祇，咸希來止。"]'),
('yuding-55','郊廟歌辭：蠟百神樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','十旬歡洽，一日祠終。澄彝拂俎，報德酬功。',40,'御定全唐詩/json/012.json','["十旬歡洽，一日祠終。澄彝拂俎，報德酬功。", "慮虔容肅，禮縟儀豐。神其降祉，整馭隨風。"]'),
('yuding-56','郊廟歌辭：享先農樂章：咸和','不詳','唐','御定全唐诗','yuding','','[]','粒食伊始，農之所先。古今攸賴，是曰人天。',40,'御定全唐詩/json/012.json','["粒食伊始，農之所先。古今攸賴，是曰人天。", "耕斯帝籍，播厥公田。式崇明祀，神其福焉。"]'),
('yuding-57','郊廟歌辭：享先農樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','樽彝既列，瑚簋方薦。歌工載登，幣禮斯奠。',40,'御定全唐詩/json/012.json','["樽彝既列，瑚簋方薦。歌工載登，幣禮斯奠。", "肅肅享祀，顒顒纓弁。神之聽之，福流寰縣。"]'),
('yuding-58','郊廟歌辭：享先農樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','前夕視牲，質明奉俎。沐芳整弁，其儀式序。',40,'御定全唐詩/json/012.json','["前夕視牲，質明奉俎。沐芳整弁，其儀式序。", "盛禮畢陳，嘉樂備舉。歆我懿德，非馨稷黍。"]'),
('yuding-59','郊廟歌辭：享先農樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','羽鑰低昂文綴已，幹戚蹈厲武行初。',32,'御定全唐詩/json/012.json','["羽鑰低昂文綴已，幹戚蹈厲武行初。", "望歲祈農神所聽，延祥介福豈雲虛。"]'),
('yuding-60','郊廟歌辭：享先農樂章：咸和','不詳','唐','御定全唐诗','yuding','','[]','三推禮就，萬庾祈凝。夤賓志遠，藨袞惟興。',40,'御定全唐詩/json/012.json','["三推禮就，萬庾祈凝。夤賓志遠，藨袞惟興。", "降歆肅薦，垂佑祗膺。送神有樂，神其上升。"]'),
('yuding-61','郊廟歌辭：享先蠶樂章：永和','不詳','唐','御定全唐诗','yuding','','[]','芳春開令序，韶苑暢和風。惟靈申廣佑，利物表神功。',48,'御定全唐詩/json/012.json','["芳春開令序，韶苑暢和風。惟靈申廣佑，利物表神功。", "綺會周天宇，黼黻藻寰中。庶幾承慶節，歆奠下帷宮。"]'),
('yuding-62','郊廟歌辭：享先蠶樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','明靈光至德，深功掩百神。祥源應節啟，福緒逐年新。',48,'御定全唐詩/json/012.json','["明靈光至德，深功掩百神。祥源應節啟，福緒逐年新。", "萬宇承恩覆，七廟佇恭禋。于茲申至懇，方期遠慶臻。"]'),
('yuding-63','郊廟歌辭：享先蠶樂章：展敬','不詳','唐','御定全唐诗','yuding','','[]','霞莊列寶衛，雲集動和聲。金卮薦綺席，玉幣委芳庭。',48,'御定全唐詩/json/012.json','["霞莊列寶衛，雲集動和聲。金卮薦綺席，玉幣委芳庭。", "因心罄丹款，先己勵蒼生。所冀延明福，于茲享至誠。"]'),
('yuding-64','郊廟歌辭：享先蠶樂章：絜誠','不詳','唐','御定全唐诗','yuding','','[]','桂筵開玉俎，蘭圃薦瓊芳。八音調鳳曆，三獻奉鸞觴。',48,'御定全唐詩/json/012.json','["桂筵開玉俎，蘭圃薦瓊芳。八音調鳳曆，三獻奉鸞觴。", "絜粢申大享，庭宇冀降祥。神其覃有慶，契福永無疆。"]'),
('yuding-65','郊廟歌辭：享先蠶樂章：昭慶','不詳','唐','御定全唐诗','yuding','','[]','仙壇禮既畢，神駕儼將升。佇屬深祥起，方期庶績凝。',48,'御定全唐詩/json/012.json','["仙壇禮既畢，神駕儼將升。佇屬深祥起，方期庶績凝。", "虔誠資宇內，務本勖黎蒸。靈心昭備享，率土洽休征。"]'),
('yuding-66','郊廟歌辭：釋奠文宣王樂章：誠和','不詳','唐','御定全唐诗','yuding','','[]','聖道日用，神幾不測。金石以陳，弦歌載陟。',40,'御定全唐詩/json/012.json','["聖道日用，神幾不測。金石以陳，弦歌載陟。", "爰釋其菜，匪馨於稷。來顧來享，是宗是極。"]'),
('yuding-67','郊廟歌辭：釋奠文宣王樂章：承和','不詳','唐','御定全唐诗','yuding','','[]','萬國以貞光上嗣，三善茂德表重輪。',32,'御定全唐詩/json/012.json','["萬國以貞光上嗣，三善茂德表重輪。", "視膳寢門尊要道，高辟崇賢引正人。"]'),
('yuding-68','郊廟歌辭：釋奠文宣王樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','粵惟上聖，有縱自天。傍周萬物，俯應千年。',40,'御定全唐詩/json/012.json','["粵惟上聖，有縱自天。傍周萬物，俯應千年。", "舊章允著，嘉贄孔虔。王化茲首，儒風是宣。"]'),
('yuding-69','郊廟歌辭：釋奠文宣王樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','堂獻瑤篚，庭敷璆縣。禮備其容，樂和其變。',40,'御定全唐詩/json/012.json','["堂獻瑤篚，庭敷璆縣。禮備其容，樂和其變。", "肅肅親享，雍雍執奠。明德惟馨，蘋蘩可薦。"]'),
('yuding-70','郊廟歌辭：釋奠文宣王樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','隼集龜開昭聖烈，龍蹲鳳跱肅神儀。',32,'御定全唐詩/json/012.json','["隼集龜開昭聖烈，龍蹲鳳跱肅神儀。", "尊儒敬業宏圖闡，緯武經文盛德施。"]'),
('yuding-71','郊廟歌辭：享孔子廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','通吳表聖，問老探真。三千弟子，五百賢人。',40,'御定全唐詩/json/012.json','["通吳表聖，問老探真。三千弟子，五百賢人。", "億齡規法，萬載嗣禋。潔誠以祭，奏樂迎神。"]'),
('yuding-72','郊廟歌辭：享孔子廟樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','醴溢犧象，羞陳俎豆。魯壁類聞，泗川如覯。',40,'御定全唐詩/json/012.json','["醴溢犧象，羞陳俎豆。魯壁類聞，泗川如覯。", "裏校覃福，胄筵承佑。雅樂清音，送神具奏。"]'),
('yuding-73','郊廟歌辭：釋奠武成王樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','蔔畋不從，兆發非熊。乃傾荒政，爰佐一戎。',50,'御定全唐詩/json/012.json','["蔔畋不從，兆發非熊。乃傾荒政，爰佐一戎。", "盛烈載垂，命祀惟崇。日練上戊，宿嚴閟宮。", "迎奏嘉至，感而遂通。"]'),
('yuding-74','郊廟歌辭：釋奠武成王樂章：奠幣登歌','不詳','唐','御定全唐诗','yuding','','[]','管磬升，膻薌集。上公進，嘉幣執。信以通，僾如及。',48,'御定全唐詩/json/012.json','["管磬升，膻薌集。上公進，嘉幣執。信以通，僾如及。", "恢帝功，錫後邑。四維張，百度立。綿億載，邈難挹。"]'),
('yuding-75','郊廟歌辭：釋奠武成王樂章：迎俎酌獻','不詳','唐','御定全唐诗','yuding','','[]','五齊潔，九牢碩。梡橛循，罍斝滌。進具物，揚鴻績。',48,'御定全唐詩/json/012.json','["五齊潔，九牢碩。梡橛循，罍斝滌。進具物，揚鴻績。", "和奏發，高靈寂。虔告終，繁祉錫。昭秩祀，永無易。"]'),
('yuding-76','郊廟歌辭：釋奠武成王樂章：亞獻終獻','不詳','唐','御定全唐诗','yuding','','[]','貳觴以獻，三變其終。顧此非馨，尚達斯衷。茅縮可致，',25,'御定全唐詩/json/012.json','["貳觴以獻，三變其終。顧此非馨，尚達斯衷。茅縮可致，"]'),
('yuding-77','郊廟歌辭：釋奠武成王樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','明祀方終，備樂斯闋。黝纁就瘞，豆籩告撤。',40,'御定全唐詩/json/012.json','["明祀方終，備樂斯闋。黝纁就瘞，豆籩告撤。", "肸蚃尚餘，光景雲滅。返歸虛極，神心則悅。"]'),
('yuding-78','郊廟歌辭：享龍池樂章：第一章','姚崇','唐','御定全唐诗','yuding','','[]','恭聞帝裏生靈沼，應報明君鼎業新。既協翠泉光寶命，',40,'御定全唐詩/json/012.json','["恭聞帝裏生靈沼，應報明君鼎業新。既協翠泉光寶命，", "獨有前池一小雁，叨承舊惠入天津。"]'),
('yuding-79','郊廟歌辭：享龍池樂章：第二章','蔡孚','唐','御定全唐诗','yuding','','[]','帝宅王家大道邊，神馬龍龜湧聖泉。昔日昔時經此地，',40,'御定全唐詩/json/012.json','["帝宅王家大道邊，神馬龍龜湧聖泉。昔日昔時經此地，", "莫言波上春雲少，只為從龍直上天。"]'),
('yuding-80','郊廟歌辭：享龍池樂章：第三章','沈佺期','唐','御定全唐诗','yuding','','[]','龍池躍龍龍已飛，龍德光天天不違。池開天漢分黃道，',40,'御定全唐詩/json/012.json','["龍池躍龍龍已飛，龍德光天天不違。池開天漢分黃道，", "為報寰中百川水，來朝此地莫東歸。"]'),
('yuding-81','郊廟歌辭：享龍池樂章：第四章','盧懷慎','唐','御定全唐诗','yuding','','[]','代邸東南龍躍泉，清漪碧浪遠浮天。樓臺影就波中出，',40,'御定全唐詩/json/012.json','["代邸東南龍躍泉，清漪碧浪遠浮天。樓臺影就波中出，", "大川既濟慚為楫，報德空思奉細涓。"]'),
('yuding-82','郊廟歌辭：享龍池樂章：第五章','姜皎','唐','御定全唐诗','yuding','','[]','龍池初出此龍山，常經此地謁龍顏。日日芙蓉生夏水，',40,'御定全唐詩/json/012.json','["龍池初出此龍山，常經此地謁龍顏。日日芙蓉生夏水，", "願似飄颻五雲影，從來從去九天間。"]'),
('yuding-83','郊廟歌辭：享龍池樂章：第六章','崔日用','唐','御定全唐诗','yuding','','[]','龍興白水漢興符，聖主時乘運鬥樞。岸上豐茸五花樹，',40,'御定全唐詩/json/012.json','["龍興白水漢興符，聖主時乘運鬥樞。岸上豐茸五花樹，", "風色雲光隨隱見，赤雲神化象江湖。"]'),
('yuding-84','郊廟歌辭：享龍池樂章：第七章','蘇頲','唐','御定全唐诗','yuding','','[]','西京鳳邸躍龍泉，佳氣休光鎮在天。軒後霧圖今已得，',40,'御定全唐詩/json/012.json','["西京鳳邸躍龍泉，佳氣休光鎮在天。軒後霧圖今已得，", "願侍巡遊同舊裏，更聞簫鼓濟樓船。"]'),
('yuding-85','郊廟歌辭：享龍池樂章：第八章','李乂','唐','御定全唐诗','yuding','','[]','星分邑裏四人居，水洊源流萬頃餘。魏國君王稱象處，',40,'御定全唐詩/json/012.json','["星分邑裏四人居，水洊源流萬頃餘。魏國君王稱象處，", "自有神靈滋液地，年年雲物史官書。"]'),
('yuding-86','郊廟歌辭：享龍池樂章：第九章','薑晞','唐','御定全唐诗','yuding','','[]','靈沼縈回邸第前，浴日涵天寫曙天。始見龍台升鳳闕，',40,'御定全唐詩/json/012.json','["靈沼縈回邸第前，浴日涵天寫曙天。始見龍台升鳳闕，", "欲化帝圖從此受，正同河變一千年。"]'),
('yuding-87','郊廟歌辭：享龍池樂章：第十章','裴璀','唐','御定全唐诗','yuding','','[]','乾坤啟聖吐龍泉，泉水年年勝一年。始看魚躍方成海，',40,'御定全唐詩/json/012.json','["乾坤啟聖吐龍泉，泉水年年勝一年。始看魚躍方成海，", "休氣榮光常不散，懸知此地是神仙。"]'),
('yuding-0','郊廟歌辭：享太廟樂章：永和','不詳','唐','御定全唐诗','yuding','','[]','于穆烈祖，弘此丕基。永言配命，子孫保之。',40,'御定全唐詩/json/013.json','["于穆烈祖，弘此丕基。永言配命，子孫保之。", "百神既洽，萬國在茲。是用孝享，神其格思。"]'),
('yuding-1','郊廟歌辭：享太廟樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','大哉至德，允茲明聖。格於上下，聿遵誠敬。',40,'御定全唐詩/json/013.json','["大哉至德，允茲明聖。格於上下，聿遵誠敬。", "嘉樂斯登，鳴球以詠。神其降止，式隆景命。"]'),
('yuding-2','郊廟歌辭：享太廟樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','崇茲享祀，誠敬兼至。樂以感靈，禮以昭事。',40,'御定全唐詩/json/013.json','["崇茲享祀，誠敬兼至。樂以感靈，禮以昭事。", "粢盛咸絜，牲牷孔備。永言孝思，庶幾不匱。"]'),
('yuding-3','郊廟歌辭：享太廟樂章：長髮舞','不詳','唐','御定全唐诗','yuding','','[]','睿哲維唐，長髮其祥。帝命斯佑，王業克昌。',40,'御定全唐詩/json/013.json','["睿哲維唐，長髮其祥。帝命斯佑，王業克昌。", "配天載德，就日重光。本支百代，申錫無疆。"]'),
('yuding-4','郊廟歌辭：享太廟樂章：大基舞','不詳','唐','御定全唐诗','yuding','','[]','猗與祖業，皇矣帝先。翦商德厚，封唐慶延。',40,'御定全唐詩/json/013.json','["猗與祖業，皇矣帝先。翦商德厚，封唐慶延。", "在姬猶稷，方晉喻宣。基我鼎運，于萬斯年。"]'),
('yuding-5','郊廟歌辭：享太廟樂章：大成舞','不詳','唐','御定全唐诗','yuding','','[]','周稱王季，晉美帝文。明明盛德，穆穆齊芬。',40,'御定全唐詩/json/013.json','["周稱王季，晉美帝文。明明盛德，穆穆齊芬。", "藏用四履，屈道三分。鏗鏘鐘石，載紀鴻勳。"]'),
('yuding-6','郊廟歌辭：享太廟樂章：大明舞','不詳','唐','御定全唐诗','yuding','','[]','五紀更運，三正遞升。勳華既沒，禹湯勃興。',120,'御定全唐詩/json/013.json','["五紀更運，三正遞升。勳華既沒，禹湯勃興。", "神武命代，靈眷是膺。望雲彰德，察緯告征。", "上紐天維，下安地軸。征師涿野，萬國咸服。", "偃伯靈台，九官允穆。殊域委贐，懷生介福。", "大禮既飾，大樂已和。黑章擾囿，赤字浮河。", "功宣載籍，德被詠歌。克昌厥後，百祿是荷。"]'),
('yuding-7','郊廟歌辭：享太廟樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','八音斯奏，三獻畢陳。寶祚惟永，暉光日新。',20,'御定全唐詩/json/013.json','["八音斯奏，三獻畢陳。寶祚惟永，暉光日新。"]'),
('yuding-8','郊廟歌辭：享太廟樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','聖敬通神光七廟，靈心薦祚和萬方。',32,'御定全唐詩/json/013.json','["聖敬通神光七廟，靈心薦祚和萬方。", "嚴禋克配鴻基遠，明德惟馨鳳曆昌。"]'),
('yuding-9','郊廟歌辭：享太廟樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','于穆清廟，聿修嚴祀。四縣載陳，三獻斯止。',40,'御定全唐詩/json/013.json','["于穆清廟，聿修嚴祀。四縣載陳，三獻斯止。", "籩豆徹薦，人祇介祉。神維格思，錫祚不已。"]'),
('yuding-10','郊廟歌辭：享太廟樂章：永和','不詳','唐','御定全唐诗','yuding','','[]','肅肅清祀，烝烝孝思。薦享昭備，虔恭在茲。',40,'御定全唐詩/json/013.json','["肅肅清祀，烝烝孝思。薦享昭備，虔恭在茲。", "雍歌徹俎，祝嘏陳辭。用光武志，永固鴻基。"]'),
('yuding-11','郊廟歌辭：享太廟樂章：崇德舞','不詳','唐','御定全唐诗','yuding','','[]','五運改蔔，千齡啟聖。彤雲曉聚，黃星夜映。',120,'御定全唐詩/json/013.json','["五運改蔔，千齡啟聖。彤雲曉聚，黃星夜映。", "葉闡珠囊，基開玉鏡。下臨萬宇，上齊七政。", "霧開三象，塵清九服。海溓星暉，遠安邇肅。", "天地交泰，華夷輯睦。翔泳歸仁，中外禔福。", "績逾黜夏，勳高翦商。武陳七德，刑設三章。", "祥禽巢閣，仁獸游梁。卜年惟永，景福無疆。"]'),
('yuding-12','郊廟歌辭：享太廟樂章：鈞天舞','不詳','唐','御定全唐诗','yuding','','[]','承天撫籙，纂聖登皇。遐清萬宇，仰協三光。',120,'御定全唐詩/json/013.json','["承天撫籙，纂聖登皇。遐清萬宇，仰協三光。", "功成日用，道濟時康。璿圖載永，寶曆斯昌。", "日月揚暉，煙雲爛色。河岳修貢，神祇效職。", "舜風攸偃，堯曦先就。睿感通寰，孝思浹宙。", "奉揚先德，虔遵曩狩。展義天扃，飛英雲岫。", "化逸王表，神凝帝先。乘雲厭俗，馭日登玄。"]'),
('yuding-13','郊廟歌辭：享太廟樂章：太和舞','不詳','唐','御定全唐诗','yuding','','[]','廣樂既備，嘉薦既新。述先惟德，孝饗惟親。',40,'御定全唐詩/json/013.json','["廣樂既備，嘉薦既新。述先惟德，孝饗惟親。", "七獻具舉，五齊畢陳。錫茲祚福，于萬斯春。"]'),
('yuding-14','郊廟歌辭：享太廟樂章：景雲舞','不詳','唐','御定全唐诗','yuding','','[]','惟睿作聖，惟聖登皇。精感耀魄，時膺會昌。',120,'御定全唐詩/json/013.json','["惟睿作聖，惟聖登皇。精感耀魄，時膺會昌。", "舜慚大孝，堯推讓王。能事斯極，振古誰方。", "文明履運，車書同軌。巍巍赫赫，盡善盡美。", "衢室凝旒，大庭端扆。釋負之寄，事光復子。", "脫屣高天，登遐上玄。龍湖超忽，象野芊綿。", "遊衣複道，薦果初年。新廟奕奕，明德配天。"]'),
('yuding-15','郊廟歌辭：享太廟樂章：光大舞','不詳','唐','御定全唐诗','yuding','','[]','大業龍祉，徽音駿尊。潛居皇德，赫嗣天昆。',40,'御定全唐詩/json/013.json','["大業龍祉，徽音駿尊。潛居皇德，赫嗣天昆。", "展儀宗祖，重誠孝孫。春秋無極，享奏存存。"]'),
('yuding-16','郊廟歌辭：享太廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','七廟觀德，百靈攸仰。俗荷財成，物資含養。',40,'御定全唐詩/json/013.json','["七廟觀德，百靈攸仰。俗荷財成，物資含養。", "道光執契，化籠提象。肅肅雍雍，神其來饗。"]'),
('yuding-17','郊廟歌辭：享太廟樂章：金奏','不詳','唐','御定全唐诗','yuding','','[]','肅肅清廟，巍巍盛唐。配天立極，累聖重光。',40,'御定全唐詩/json/013.json','["肅肅清廟，巍巍盛唐。配天立極，累聖重光。", "樂和管磬，禮備烝嘗。永惟來格，降福無疆。"]'),
('yuding-18','郊廟歌辭：享太廟樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','五聲備奏，三獻終祠。車移鳳輦，旆轉虹旗。',40,'御定全唐詩/json/013.json','["五聲備奏，三獻終祠。車移鳳輦，旆轉虹旗。", "禮周籩豆，誠效虔祗。皇靈徙蹕，簪紳拜辭。"]'),
('yuding-19','郊廟歌辭：武后享清廟樂章十首：第一','不詳','唐','御定全唐诗','yuding','','[]','建清廟，贊玄功。擇吉日，展禋宗。',32,'御定全唐詩/json/013.json','["建清廟，贊玄功。擇吉日，展禋宗。", "樂已變，禮方崇。望神駕，降仙宮。"]'),
('yuding-20','郊廟歌辭：武后享清廟樂章十首：第二','不詳','唐','御定全唐诗','yuding','','[]','隆周創業，寶命惟新。敬宗茂典，爰表虔禋。',40,'御定全唐詩/json/013.json','["隆周創業，寶命惟新。敬宗茂典，爰表虔禋。", "聲明已備，文物斯陳。肅容如在，懇志方申。"]'),
('yuding-21','郊廟歌辭：武后享清廟樂章十首：第三登歌','不詳','唐','御定全唐诗','yuding','','[]','肅敷大禮，上謁尊靈。敬陳筐幣，載表丹誠。',20,'御定全唐詩/json/013.json','["肅敷大禮，上謁尊靈。敬陳筐幣，載表丹誠。"]'),
('yuding-22','郊廟歌辭：武后享清廟樂章十首：第四迎神','不詳','唐','御定全唐诗','yuding','','[]','敬奠蘋藻，式罄虔襟。潔誠斯展，佇降靈歆。',20,'御定全唐詩/json/013.json','["敬奠蘋藻，式罄虔襟。潔誠斯展，佇降靈歆。"]'),
('yuding-23','郊廟歌辭：武后享清廟樂章十首：第五飲福','不詳','唐','御定全唐诗','yuding','','[]','爰陳玉醴，式奠瓊漿。靈心有穆，介福無疆。',20,'御定全唐詩/json/013.json','["爰陳玉醴，式奠瓊漿。靈心有穆，介福無疆。"]'),
('yuding-24','郊廟歌辭：武后享清廟樂章十首：第六送文舞','不詳','唐','御定全唐诗','yuding','','[]','帝圖草創，皇業初開。功高佐命，業贊雲雷。',20,'御定全唐詩/json/013.json','["帝圖草創，皇業初開。功高佐命，業贊雲雷。"]'),
('yuding-25','郊廟歌辭：武后享清廟樂章十首：第七迎武舞','不詳','唐','御定全唐诗','yuding','','[]','赫赫玄功被穹壤，皇皇至德洽生靈。',32,'御定全唐詩/json/013.json','["赫赫玄功被穹壤，皇皇至德洽生靈。", "開基撥亂妖氛廓，佐命宣威海內清。"]'),
('yuding-26','郊廟歌辭：武后享清廟樂章十首：第八武舞作','不詳','唐','御定全唐诗','yuding','','[]','荷恩承顧托，執契恭臨撫。廟略靜邊荒，天兵耀神武。',24,'御定全唐詩/json/013.json','["荷恩承顧托，執契恭臨撫。廟略靜邊荒，天兵耀神武。"]'),
('yuding-27','郊廟歌辭：武后享清廟樂章十首：第九徹俎','不詳','唐','御定全唐诗','yuding','','[]','登歌已闋，獻禮方周。欽承景福，肅奉鴻休。',20,'御定全唐詩/json/013.json','["登歌已闋，獻禮方周。欽承景福，肅奉鴻休。"]'),
('yuding-28','郊廟歌辭：武后享清廟樂章十首：第十送神','不詳','唐','御定全唐诗','yuding','','[]','大禮言畢，仙衛將歸。莫申丹懇，空瞻紫微。',20,'御定全唐詩/json/013.json','["大禮言畢，仙衛將歸。莫申丹懇，空瞻紫微。"]'),
('yuding-29','郊廟歌辭：享太廟樂章：嚴和','不詳','唐','御定全唐诗','yuding','','[]','肅肅清廟，赫赫玄猷。功高萬古，化奄十洲。',40,'御定全唐詩/json/013.json','["肅肅清廟，赫赫玄猷。功高萬古，化奄十洲。", "中興丕業，上荷天休。祗奉先構，禮備懷柔。"]'),
('yuding-30','郊廟歌辭：享太廟樂章：升和','不詳','唐','御定全唐诗','yuding','','[]','顧惟菲薄，纂曆應期。中外同軌，夷狄來思。',40,'御定全唐詩/json/013.json','["顧惟菲薄，纂曆應期。中外同軌，夷狄來思。", "樂用崇德，禮以陳詞。夕惕若厲，欽奉弘基。"]'),
('yuding-31','郊廟歌辭：享太廟樂章：虔和','不詳','唐','御定全唐诗','yuding','','[]','禮標薦鬯，肅事祠庭。敬申如在，敢托非馨。',20,'御定全唐詩/json/013.json','["禮標薦鬯，肅事祠庭。敬申如在，敢托非馨。"]'),
('yuding-32','郊廟歌辭：享太廟樂章：歆和','不詳','唐','御定全唐诗','yuding','','[]','崇禋已備，粢盛聿修。潔誠斯展，鐘石方遒。',20,'御定全唐詩/json/013.json','["崇禋已備，粢盛聿修。潔誠斯展，鐘石方遒。"]'),
('yuding-33','郊廟歌辭：享太廟樂章：承光舞','不詳','唐','御定全唐诗','yuding','','[]','金相載穆，玉裕重輝。養德清禁，承光紫微。',80,'御定全唐詩/json/013.json','["金相載穆，玉裕重輝。養德清禁，承光紫微。", "幹宮候色，震象增威。監國方永，賓天不歸。", "孝友自衷，溫文性與。龍樓正啟，鶴駕斯舉。", "丹扆流念，鴻名式序。中興考室，永陳彝俎。"]'),
('yuding-34','郊廟歌辭：享太廟樂章：延和','不詳','唐','御定全唐诗','yuding','','[]','巍巍累聖，穆穆重光。奄有區夏，祚啟隆唐。',40,'御定全唐詩/json/013.json','["巍巍累聖，穆穆重光。奄有區夏，祚啟隆唐。", "百蠻飲澤，萬國來王。本枝億載，鼎祚逾長。"]'),
('yuding-35','郊廟歌辭：享太廟樂章：同和','不詳','唐','御定全唐诗','yuding','','[]','惟聖配天敷盛禮，惟天為大闡洪名。',32,'御定全唐詩/json/013.json','["惟聖配天敷盛禮，惟天為大闡洪名。", "恭禋展敬光先德，蘋藻申虔表志誠。"]'),
('yuding-36','郊廟歌辭：享太廟樂章：寧和','不詳','唐','御定全唐诗','yuding','','[]','炎馭失天綱，土德承天命。英猷被寰宇，懿躅隆邦政。',48,'御定全唐詩/json/013.json','["炎馭失天綱，土德承天命。英猷被寰宇，懿躅隆邦政。", "七德已綏邊，九夷咸底定。景化覃遐邇，深仁洽翔泳。"]'),
('yuding-37','郊廟歌辭：享太廟樂章：恭和','不詳','唐','御定全唐诗','yuding','','[]','禮週三獻，樂闋九成。肅承靈福，悚惕兼盈。',20,'御定全唐詩/json/013.json','["禮週三獻，樂闋九成。肅承靈福，悚惕兼盈。"]'),
('yuding-38','郊廟歌辭：享太廟樂章：通和','不詳','唐','御定全唐诗','yuding','','[]','祠容既畢，仙座爰興。停停鳳舉，靄靄雲升。',40,'御定全唐詩/json/013.json','["祠容既畢，仙座爰興。停停鳳舉，靄靄雲升。", "長隆寶運，永錫休征。福覃貽厥，恩被黎蒸。"]'),
('yuding-39','郊廟歌辭：享太廟樂章：昭和','不詳','唐','御定全唐诗','yuding','','[]','道洽二儀交泰，時休四宇和平。',28,'御定全唐詩/json/013.json','["道洽二儀交泰，時休四宇和平。", "環佩肅於庭實，鐘石揚乎頌聲。"]'),
('yuding-40','郊廟歌辭：享太廟樂章：誠敬','不詳','唐','御定全唐诗','yuding','','[]','顧惟菲質，忝位椒宮。虔奉蘋藻，肅事神宗。',40,'御定全唐詩/json/013.json','["顧惟菲質，忝位椒宮。虔奉蘋藻，肅事神宗。", "敢申誠絜，庶罄深衷。睟容有裕，靈享無窮。"]'),
('yuding-41','郊廟歌辭：享太廟樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','月禮已周，雲和將變。爰獻其醑，載遷其奠。',40,'御定全唐詩/json/013.json','["月禮已周，雲和將變。爰獻其醑，載遷其奠。", "明德逾隆，非馨是薦。澤沾動植，仁覃宇縣。"]'),
('yuding-42','郊廟歌辭：享太廟樂章：昭感','不詳','唐','御定全唐诗','yuding','','[]','鏗鏘韶濩，肅穆神容。洪規赫赫，祠典雍雍。',40,'御定全唐詩/json/013.json','["鏗鏘韶濩，肅穆神容。洪規赫赫，祠典雍雍。", "已週三獻，將乘六龍。虔誠有托，懇志無從。"]'),
('yuding-43','郊廟歌辭：享太廟樂章：永和三章','不詳','唐','御定全唐诗','yuding','','[]','肅九室，諧八音。歌皇慕，動神心。',96,'御定全唐詩/json/013.json','["肅九室，諧八音。歌皇慕，動神心。", "禮宿設，樂妙尋。聲明備，祼奠臨。", "律迓氣，音入玄。依玉幾，禦黼筵。", "聆愾息，僾周旋。九韶遍，百福傳。", "信工祝，永頌聲。來祖考，聽和平。", "相百辟，貢九瀛。神休委，帝孝成。"]'),
('yuding-44','郊廟歌辭：享太廟樂章：太和','不詳','唐','御定全唐诗','yuding','','[]','時文聖後，清廟肅邕。致誠勤薦，在貌思恭。',40,'御定全唐詩/json/013.json','["時文聖後，清廟肅邕。致誠勤薦，在貌思恭。", "玉節肆夏，金鏘五鐘。繩繩雲步，穆穆天容。"]'),
('yuding-45','郊廟歌辭：享太廟樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','天子享孝，工歌溥將。躬祼鬱鬯，乃焚膋薌。',40,'御定全唐詩/json/013.json','["天子享孝，工歌溥將。躬祼鬱鬯，乃焚膋薌。", "臭以達陰，聲以求陽。奉時烝嘗，永代不忘。"]'),
('yuding-46','郊廟歌辭：享太廟樂章：雍和二章','不詳','唐','御定全唐诗','yuding','','[]','在滌嘉豢，麗碑敬牲。角握之牡，色純之騂。',80,'御定全唐詩/json/013.json','["在滌嘉豢，麗碑敬牲。角握之牡，色純之騂。", "火傳陽燧，水溉陰精。太公胖俎，傅說和羹。", "俎豆有馥，粢盛絜豐。亦有和羹，既戒既平。", "鼓鐘管磬，肅唱和鳴。皇皇後祖，來我思成。"]'),
('yuding-47','郊廟歌辭：享太廟樂章：文舞','不詳','唐','御定全唐诗','yuding','','[]','聖謨九德，真言五千。慶集昌胄，符開帝先。',100,'御定全唐詩/json/013.json','["聖謨九德，真言五千。慶集昌胄，符開帝先。", "高文杖鉞，克配彼天。三宗握鏡，六合渙然。", "帝其承祀，率禮罔愆。圖書霧出，日月清懸。", "舞形德類，詠諗功傳。黃龍蜿蟺，彩雲蹁躚。", "五行氣順，八佾風宣。介此百祿，於皇萬年。"]'),
('yuding-48','郊廟歌辭：享太廟樂章：光大舞','不詳','唐','御定全唐诗','yuding','','[]','肅肅藝祖，滔滔浚源。有雄玉劍，作鎮金門。',40,'御定全唐詩/json/013.json','["肅肅藝祖，滔滔浚源。有雄玉劍，作鎮金門。", "玄王貽緒，後稷謀孫。肇禋九廟，四海來尊。"]'),
('yuding-49','郊廟歌辭：享太廟樂章：長髮舞','不詳','唐','御定全唐诗','yuding','','[]','具禮崇德，備樂承風。魏推幢主，周贈司空。',40,'御定全唐詩/json/013.json','["具禮崇德，備樂承風。魏推幢主，周贈司空。", "不行而至，無成有終。神興王業，天歸帝功。"]'),
('yuding-50','郊廟歌辭：享太廟樂章：大政舞','不詳','唐','御定全唐诗','yuding','','[]','於赫元命，權輿帝文。天齊八柱，地半三分。',40,'御定全唐詩/json/013.json','["於赫元命，權輿帝文。天齊八柱，地半三分。", "宗廟觀德，笙鏞樂勳。封唐之兆，成天下君。"]'),
('yuding-51','郊廟歌辭：享太廟樂章：大成舞','不詳','唐','御定全唐诗','yuding','','[]','帝舞季曆，龍聖生昌。後歌有蟜，胎炎孕黃。',40,'御定全唐詩/json/013.json','["帝舞季曆，龍聖生昌。後歌有蟜，胎炎孕黃。", "天地合德，日月齊光。肅雍孝享，祚我萬方。"]'),
('yuding-52','郊廟歌辭：享太廟樂章：大明舞','不詳','唐','御定全唐诗','yuding','','[]','赤精亂德，四海困窮。黃旗舉義，三靈會同。',40,'御定全唐詩/json/013.json','["赤精亂德，四海困窮。黃旗舉義，三靈會同。", "旱望春雨，雲披大風。溥天來祭，高祖之功。"]'),
('yuding-53','郊廟歌辭：享太廟樂章：崇德舞','不詳','唐','御定全唐诗','yuding','','[]','皇合一德，朝宗百神。削平天地，大拯生人。',40,'御定全唐詩/json/013.json','["皇合一德，朝宗百神。削平天地，大拯生人。", "上帝配食，單于入臣。戎歌陳舞，曄曄震震。"]'),
('yuding-54','郊廟歌辭：享太廟樂章：鈞天舞','不詳','唐','御定全唐诗','yuding','','[]','高皇邁道，端拱無為。化懷獯鬻，兵賦句驪。',40,'御定全唐詩/json/013.json','["高皇邁道，端拱無為。化懷獯鬻，兵賦句驪。", "禮尊封禪，樂盛來儀。合位媧後，同稱伏羲。"]'),
('yuding-55','郊廟歌辭：享太廟樂章：大和舞','不詳','唐','御定全唐诗','yuding','','[]','退居江水，鬱起丹陵。禮物還舊，朝章中興。',40,'御定全唐詩/json/013.json','["退居江水，鬱起丹陵。禮物還舊，朝章中興。", "龍圖友及，駿命恭膺。鳴球香瓚，大糦是承。"]'),
('yuding-56','郊廟歌辭：享太廟樂章：景雲舞','不詳','唐','御定全唐诗','yuding','','[]','景雲霏爛，告我帝符。噫帝沖德，與天為徒。',40,'御定全唐詩/json/013.json','["景雲霏爛，告我帝符。噫帝沖德，與天為徒。", "笙鏞遙遠，俎豆虛無。春秋孝獻，回復此都。"]'),
('yuding-57','郊廟歌辭：享太廟樂章：福和','不詳','唐','御定全唐诗','yuding','','[]','備禮用樂，崇親致尊。誠通慈降，敬徹愛存。獻懷稱壽，',25,'御定全唐詩/json/013.json','["備禮用樂，崇親致尊。誠通慈降，敬徹愛存。獻懷稱壽，"]'),
('yuding-58','郊廟歌辭：享太廟樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','六鐘翕協六變成，八佾徜徉八風生。',32,'御定全唐詩/json/013.json','["六鐘翕協六變成，八佾徜徉八風生。", "樂九韶兮人神感，美七德兮天地清。"]'),
('yuding-59','郊廟歌辭：享太廟樂章：凱安四章','不詳','唐','御定全唐诗','yuding','','[]','瑟彼瑤爵，亞惟上公。室如屏氣，門不容躬。',168,'御定全唐詩/json/013.json','["瑟彼瑤爵，亞惟上公。室如屏氣，門不容躬。", "禮殷其本，樂執其中。聖皇永慕，天地幽通。", "禮匝三獻，樂遍九成。降循軒陛，仰欷皇情。", "福與仁合，德因孝明。百年神畏，四海風行。", "總總幹戚，填填鼓鐘。奮揚爭氣，坐作為容。", "離若鷙鳥，合如戰龍。萬方觀德，肅肅雍雍。", "烈祖順三靈，文宗威四海。黃鉞誅群盜，朱旗掃多罪。", "戢兵天下安，約法人心改。大哉幹羽意，長見風雲在。"]'),
('yuding-60','郊廟歌辭：享太廟樂章：登歌','不詳','唐','御定全唐诗','yuding','','[]','止笙磬，撤豆籩。廓無響，窅入玄。主在室，神在天。',40,'御定全唐詩/json/013.json','["止笙磬，撤豆籩。廓無響，窅入玄。主在室，神在天。", "情餘慕，禮罔愆。喜黍稷，屢豐年。"]'),
('yuding-61','郊廟歌辭：享太廟樂章：永和','不詳','唐','御定全唐诗','yuding','','[]','眇嘉樂，授靈爽。感若來，思如往。休氣散，回風上。',40,'御定全唐詩/json/013.json','["眇嘉樂，授靈爽。感若來，思如往。休氣散，回風上。", "返寂寞，還惚恍。懷靈駕，結空想。"]'),
('yuding-62','郊廟歌辭：享太廟樂章：廣運舞','郭子儀','唐','御定全唐诗','yuding','','[]','于赫皇祖，昭明有融。惟文之德，惟武之功。',40,'御定全唐詩/json/013.json','["于赫皇祖，昭明有融。惟文之德，惟武之功。", "河海靜謐，車書混同。虔恭孝饗，穆穆玄風。"]'),
('yuding-63','郊廟歌辭：享太廟樂章：惟新舞','劉晏','唐','御定全唐诗','yuding','','[]','漢祚惟永，神功中興。風驅氛祲，天覆黎蒸。',40,'御定全唐詩/json/013.json','["漢祚惟永，神功中興。風驅氛祲，天覆黎蒸。", "三光再朗，庶績其凝。重熙累洽，景命是膺。"]'),
('yuding-64','郊廟歌辭：享太廟樂章：保大舞','郭子儀','唐','御定全唐诗','yuding','','[]','于穆文考，聖神昭章。肅勺群慝，含光遠方。',40,'御定全唐詩/json/013.json','["于穆文考，聖神昭章。肅勺群慝，含光遠方。", "萬物茂遂，九夷賓王。愔愔雲韶，德音不忘。"]'),
('yuding-65','郊廟歌辭：享太廟樂章：文明舞','鄭餘慶','唐','御定全唐诗','yuding','','[]','開邸除暴，時邁勳尊。三元告命，四極駿奔。',40,'御定全唐詩/json/013.json','["開邸除暴，時邁勳尊。三元告命，四極駿奔。", "金枝翠葉，輝燭瑤琨。象德億載，貽慶湯孫。"]'),
('yuding-66','郊廟歌辭：享太廟樂章：大順舞','鄭絪','唐','御定全唐诗','yuding','','[]','于穆時文，受天明命。允恭玄默，化成理定。',40,'御定全唐詩/json/013.json','["于穆時文，受天明命。允恭玄默，化成理定。", "出震嗣德，應幹傳聖。猗歟緝熙，千億流慶。"]'),
('yuding-67','郊廟歌辭：享太廟樂章：象德舞','段文昌','唐','御定全唐诗','yuding','','[]','肅肅清廟，登顯至德。澤周八荒，兵定四極。',40,'御定全唐詩/json/013.json','["肅肅清廟，登顯至德。澤周八荒，兵定四極。", "生物咸遂，群盜滅息。明聖欽承，子孫千億。"]'),
('yuding-68','郊廟歌辭：享太廟樂章：和甯舞','牛僧孺','唐','御定全唐诗','yuding','','[]','湜湜頎頎，融昭德輝。不紐不舒，貫成九圍。',40,'御定全唐詩/json/013.json','["湜湜頎頎，融昭德輝。不紐不舒，貫成九圍。", "武烈文經，敷施當宜。纂堯付啟，億萬熙熙。"]'),
('yuding-69','郊廟歌辭：享太廟樂章：大定舞','李回','唐','御定全唐诗','yuding','','[]','受天明命，敷佑下土。化時以儉，衛文以武。',40,'御定全唐詩/json/013.json','["受天明命，敷佑下土。化時以儉，衛文以武。", "氛消夷夏，俗臻往古。億萬斯年，形於律呂。"]'),
('yuding-70','郊廟歌辭：享太廟樂章：宣宗室舞','夏侯孜','唐','御定全唐诗','yuding','','[]','於鑠令主，聖祚重昌。興起教義，申明典章。',40,'御定全唐詩/json/013.json','["於鑠令主，聖祚重昌。興起教義，申明典章。", "俗尚素樸，人皆樂康。積德可報，流慶無疆。"]'),
('yuding-71','郊廟歌辭：享太廟樂章：懿宗室舞','蕭仿','唐','御定全唐诗','yuding','','[]','聖祚無疆，慶傳樂章。金枝繁茂，玉葉延長。',40,'御定全唐詩/json/013.json','["聖祚無疆，慶傳樂章。金枝繁茂，玉葉延長。", "海瀆常晏，波濤不揚。汪汪美化，垂范今王。"]'),
('yuding-72','郊廟歌辭：享太廟樂章：咸甯舞','不詳','唐','御定全唐诗','yuding','','[]','於鑠丕嗣，惟帝之光。羽鑰象德，金石薦祥。',40,'御定全唐詩/json/013.json','["於鑠丕嗣，惟帝之光。羽鑰象德，金石薦祥。", "聖系無極，景命永昌。神降上哲，維天配長。"]'),
('yuding-0','郊廟歌辭：太清宮樂章：煌煌','不詳','唐','御定全唐诗','yuding','','[]','煌煌道宮，肅肅太清。禮光尊祖，樂備充庭。',60,'御定全唐詩/json/014.json','["煌煌道宮，肅肅太清。禮光尊祖，樂備充庭。", "罄竭誠至，希夷降靈。雲凝翠蓋，風焰紅旌。", "眾真以從，九奏初迎。永惟休佑，是錫和平。"]'),
('yuding-1','郊廟歌辭：太清宮樂章：沖和','不詳','唐','御定全唐诗','yuding','','[]','虛無結思，鐘磬和音。歌以頌德，香以達心。',40,'御定全唐詩/json/014.json','["虛無結思，鐘磬和音。歌以頌德，香以達心。", "禮殊祼鬯，義感昭臨。靈車至止，慶垂愔愔。"]'),
('yuding-2','郊廟歌辭：太清宮樂章：香初上','不詳','唐','御定全唐诗','yuding','','[]','肅肅我祖，綿綿道宗。至感潛達，靈心暗通。',40,'御定全唐詩/json/014.json','["肅肅我祖，綿綿道宗。至感潛達，靈心暗通。", "雲輧禦氣，芝蓋隨風。四時禋祀，萬國來同。"]'),
('yuding-3','郊廟歌辭：太清宮樂章：再上','不詳','唐','御定全唐诗','yuding','','[]','仙宗績道，我李承天。慶深虛極，符光象先。',40,'御定全唐詩/json/014.json','["仙宗績道，我李承天。慶深虛極，符光象先。", "俗登仁壽，化闡蟺涓。五千貽範，億萬斯年。"]'),
('yuding-4','郊廟歌辭：太清宮樂章：終上','不詳','唐','御定全唐诗','yuding','','[]','不宰元功，無為上聖。洪源長髮，誕受天命。',40,'御定全唐詩/json/014.json','["不宰元功，無為上聖。洪源長髮，誕受天命。", "金奏迎真，璿宮展盛。備禮周樂，垂光儲慶。"]'),
('yuding-5','郊廟歌辭：太清宮樂章：紫極舞','不詳','唐','御定全唐诗','yuding','','[]','至道生元氣，重圓法混成。無為觀大象，沖用體常名。',72,'御定全唐詩/json/014.json','["至道生元氣，重圓法混成。無為觀大象，沖用體常名。", "仙樂臨丹闕，雲車出玉京。靈符百代應，瑞節九貞迎。", "寶運開皇極，天臨映太清。長垂一德慶，永庇萬方寧。"]'),
('yuding-6','郊廟歌辭：太清宮樂章：序入破第一奏','不詳','唐','御定全唐诗','yuding','','[]','真宗開妙理，沖教統清虛。化演無為日，言昭有象初。',48,'御定全唐詩/json/014.json','["真宗開妙理，沖教統清虛。化演無為日，言昭有象初。", "瑤台肅靈瑞，金闕映仙居。一奏三清樂，長回八景輿。"]'),
('yuding-7','郊廟歌辭：太清宮樂章：第二奏','不詳','唐','御定全唐诗','yuding','','[]','虛極仙宗本，希夷象帝先。百靈朝太上，萬法祖重圓。',48,'御定全唐詩/json/014.json','["虛極仙宗本，希夷象帝先。百靈朝太上，萬法祖重圓。", "善貸惟沖德，功成謂自然。雲門達和氣，思用合鈞天。"]'),
('yuding-8','郊廟歌辭：太清宮樂章：第三奏','不詳','唐','御定全唐诗','yuding','','[]','元符傳紫極，寶祚啟高真。道德先垂裕，沖和已化淳。',48,'御定全唐詩/json/014.json','["元符傳紫極，寶祚啟高真。道德先垂裕，沖和已化淳。", "人風齊太古，天瑞葉惟新。仙樂清都上，長明交泰辰。"]'),
('yuding-9','郊廟歌辭：太清宮樂章：登歌','不詳','唐','御定全唐诗','yuding','','[]','嚴禋展事，理潔烝嘗。皇矣聖祖，德惟馨香。',40,'御定全唐詩/json/014.json','["嚴禋展事，理潔烝嘗。皇矣聖祖，德惟馨香。", "盛薦既撤，工歌載揚。大來之慶，降福穰穰。"]'),
('yuding-10','郊廟歌辭：太清宮樂章：真和','不詳','唐','御定全唐诗','yuding','','[]','玉磬含香，金爐既馥。風馭泠泠，雲壇肅肅。',40,'御定全唐詩/json/014.json','["玉磬含香，金爐既馥。風馭泠泠，雲壇肅肅。", "杳歸大象，霈流嘉福。俾甯萬邦，無思不服。"]'),
('yuding-11','郊廟歌辭：德明興聖廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','元尊九德，佐堯光宅。烈祖太宗，方周作伯。',40,'御定全唐詩/json/014.json','["元尊九德，佐堯光宅。烈祖太宗，方周作伯。", "響懷霜露，樂變金石。白雲清風，仿佛來格。"]'),
('yuding-12','郊廟歌辭：德明興聖廟樂章：登歌奠幣','不詳','唐','御定全唐诗','yuding','','[]','四時有典，百事來祭。尊祖奉宗，嚴禋大帝。',40,'御定全唐詩/json/014.json','["四時有典，百事來祭。尊祖奉宗，嚴禋大帝。", "禮先蒼璧，奠幣黝制。于斯萬年，熙成帝系。"]'),
('yuding-13','郊廟歌辭：德明興聖廟樂章：迎俎','不詳','唐','御定全唐诗','yuding','','[]','盛牲實俎，涓選休成。鼎煁陽燧，玉盥陰精。',40,'御定全唐詩/json/014.json','["盛牲實俎，涓選休成。鼎煁陽燧，玉盥陰精。", "有飶嘉豆，既和大羹。侑以清樂，細齊人情。"]'),
('yuding-14','郊廟歌辭：德明興聖廟樂章：德明酌獻','不詳','唐','御定全唐诗','yuding','','[]','清廟奕奕，和樂雍雍。器尊犧象，禮屬宗公。',40,'御定全唐詩/json/014.json','["清廟奕奕，和樂雍雍。器尊犧象，禮屬宗公。", "白水方祼，黃流在中。謨明之德，萬古清風。"]'),
('yuding-15','郊廟歌辭：德明興聖廟樂章：興聖酌獻','不詳','唐','御定全唐诗','yuding','','[]','閟宮靜謐，合樂周張。泰奠始獻，百末重觴。',40,'御定全唐詩/json/014.json','["閟宮靜謐，合樂周張。泰奠始獻，百末重觴。", "震澹存誠，庶幾迪嘗。遙源之祚，天漢靈長。"]'),
('yuding-16','郊廟歌辭：德明興聖廟樂章：亞獻終獻','不詳','唐','御定全唐诗','yuding','','[]','惟清惟肅，靡聞靡見。舉備九成，俯終三獻。',40,'御定全唐詩/json/014.json','["惟清惟肅，靡聞靡見。舉備九成，俯終三獻。", "慶彰曼壽，胙徹嘉薦。瘞玉埋牲，禮神斯遍。"]'),
('yuding-17','郊廟歌辭：德明興聖廟樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','元精回復，靈貺繁滋。風灑蘭路，雲搖桂旗。',40,'御定全唐詩/json/014.json','["元精回復，靈貺繁滋。風灑蘭路，雲搖桂旗。", "高丘緬邈，涼部逶遲。瞻望靡及，纏綿永思。"]'),
('yuding-18','郊廟歌辭：儀坤廟樂章：永和','徐彥伯','唐','御定全唐诗','yuding','','[]','猗若清廟，肅肅熒熒。國薦嚴祀，坤興淑靈。',40,'御定全唐詩/json/014.json','["猗若清廟，肅肅熒熒。國薦嚴祀，坤興淑靈。", "有幾在室，有樂在庭。臨茲孝享，百祿惟寧。"]'),
('yuding-19','郊廟歌辭：儀坤廟樂章：金奏','不詳','唐','御定全唐诗','yuding','','[]','陰靈曜祉，軒曜降精。祥符淑氣，慶集柔明。',40,'御定全唐詩/json/014.json','["陰靈曜祉，軒曜降精。祥符淑氣，慶集柔明。", "瑤俎既列，雕桐發聲。徽猷永遠，比德皇英。"]'),
('yuding-20','郊廟歌辭：儀坤廟樂章：太和','丘說','唐','御定全唐诗','yuding','','[]','孝哉我後，沖乎乃聖。道映重華，德輝文命。',40,'御定全唐詩/json/014.json','["孝哉我後，沖乎乃聖。道映重華，德輝文命。", "慕深視篋，情殷撫鏡。萬國移風，兆人承慶。"]'),
('yuding-21','郊廟歌辭：儀坤廟樂章：肅和','張齊賢','唐','御定全唐诗','yuding','','[]','祼圭既濯，郁鬯既陳。畫幕雲舉，黃流玉醇。',40,'御定全唐詩/json/014.json','["祼圭既濯，郁鬯既陳。畫幕雲舉，黃流玉醇。", "儀充獻酌，禮盛眾禋。地察惟孝，愉焉饗親。"]'),
('yuding-22','郊廟歌辭：儀坤廟樂章：雍和','鄭善玉','唐','御定全唐诗','yuding','','[]','酌鬱既灌，薌蕭方爇。籩豆靜器，簠簋芬飶。',40,'御定全唐詩/json/014.json','["酌鬱既灌，薌蕭方爇。籩豆靜器，簠簋芬飶。", "魚臘薦美，牲牷表潔。是戢是將，載迎載列。"]'),
('yuding-23','郊廟歌辭：儀坤廟樂章：昭升','薛稷','唐','御定全唐诗','yuding','','[]','陽靈配德，陰魄昭升。堯壇鳳下，漢室龍興。',60,'御定全唐詩/json/014.json','["陽靈配德，陰魄昭升。堯壇鳳下，漢室龍興。", "伣天作對，前旒是凝。化行南國，道盛西陵，", "陰陰靈廟，光靈若憑。德馨惟享，孝思烝烝。"]'),
('yuding-24','郊廟歌辭：儀坤廟樂章：坤貞','不詳','唐','御定全唐诗','yuding','','[]','幹道既亨，坤元以貞。肅雍攸在，輔佐斯成。',80,'御定全唐詩/json/014.json','["幹道既亨，坤元以貞。肅雍攸在，輔佐斯成。", "外睦九族，內光一庭。克生睿哲，祚我休明。", "欽若徽範，悠哉淑靈。建茲清宮，於彼上京。", "縮茅以獻，絜秬惟馨。實受其福，期乎億齡。"]'),
('yuding-25','郊廟歌辭：儀坤廟樂章：壽和','徐堅','唐','御定全唐诗','yuding','','[]','于穆清廟，肅雍嚴祀。合福受厘，介以繁祉。',20,'御定全唐詩/json/014.json','["于穆清廟，肅雍嚴祀。合福受厘，介以繁祉。"]'),
('yuding-26','郊廟歌辭：儀坤廟樂章：舒和','胡雄','唐','御定全唐诗','yuding','','[]','送文迎武遞參差，一始一終光聖儀。',32,'御定全唐詩/json/014.json','["送文迎武遞參差，一始一終光聖儀。", "四海生人歌有慶，千齡孝享肅無虧。"]'),
('yuding-27','郊廟歌辭：儀坤廟樂章：安和','劉子玄','唐','御定全唐诗','yuding','','[]','妙算申帷幄，神謀及廟庭。兩階文物備，七德武功成。',48,'御定全唐詩/json/014.json','["妙算申帷幄，神謀及廟庭。兩階文物備，七德武功成。", "校獵長楊苑，屯軍細柳營。將軍獻凱入，歌舞溢重城。"]'),
('yuding-28','郊廟歌辭：儀坤廟樂章：雍和','員半千','唐','御定全唐诗','yuding','','[]','孝享雲畢，惟徹有章。雲感玄羽，風淒素商。',40,'御定全唐詩/json/014.json','["孝享雲畢，惟徹有章。雲感玄羽，風淒素商。", "瞻望神座，祗戀匪遑。禮終樂闋，肅雍鏘鏘。"]'),
('yuding-29','郊廟歌辭：儀坤廟樂章：永和','祝欽明','唐','御定全唐诗','yuding','','[]','閟宮實實，清廟微微。降格無象，馨香有依。',40,'御定全唐詩/json/014.json','["閟宮實實，清廟微微。降格無象，馨香有依。", "式昭纂慶，方融嗣徽。明禋是享，神保聿歸。"]'),
('yuding-30','郊廟歌辭：儀坤廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','月靈降德，坤元授光。娥英比秀，任姒均芳。',40,'御定全唐詩/json/014.json','["月靈降德，坤元授光。娥英比秀，任姒均芳。", "瑤台薦祉，金屋延祥。迎神有樂，歆此嘉薌。"]'),
('yuding-31','郊廟歌辭：儀坤廟樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','玉帛儀大，金絲奏廣。靈應有孚，冥征不爽。',40,'御定全唐詩/json/014.json','["玉帛儀大，金絲奏廣。靈應有孚，冥征不爽。", "降彼休福，歆茲禋享。送樂有章，神麾其上。"]'),
('yuding-32','郊廟歌辭：昭德皇后廟樂章：永和','不詳','唐','御定全唐诗','yuding','','[]','穆清廟，薦嚴禋。昭禮備，和樂新。',32,'御定全唐詩/json/014.json','["穆清廟，薦嚴禋。昭禮備，和樂新。", "望靈光，集元辰。祚無極，享萬春。"]'),
('yuding-33','郊廟歌辭：昭德皇后廟樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','誠心達，娛樂分。升簫膋，鬱氛氳。',32,'御定全唐詩/json/014.json','["誠心達，娛樂分。升簫膋，鬱氛氳。", "茅既縮，鬯既熏。後來思，福如雲。"]'),
('yuding-34','郊廟歌辭：昭德皇后廟樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','我將我享，盡明而誠。載芬黍稷，載滌犧牲。',40,'御定全唐詩/json/014.json','["我將我享，盡明而誠。載芬黍稷，載滌犧牲。", "懿矣元良，萬邦以貞。心乎愛敬，若睹容聲。"]'),
('yuding-35','郊廟歌辭：昭德皇后廟樂章：坤元','不詳','唐','御定全唐诗','yuding','','[]','于穆先後，麗聖稱崇。母臨萬宇，道被六宮。',40,'御定全唐詩/json/014.json','["于穆先後，麗聖稱崇。母臨萬宇，道被六宮。", "昌時協慶，理內成功。殷薦明德，傳芳國風。"]'),
('yuding-36','郊廟歌辭：昭德皇后廟樂章：壽和','不詳','唐','御定全唐诗','yuding','','[]','工祝致告，徽音不遐。酒醴咸旨，馨香具嘉。',30,'御定全唐詩/json/014.json','["工祝致告，徽音不遐。酒醴咸旨，馨香具嘉。", "受厘獻祉，永慶邦家。"]'),
('yuding-37','郊廟歌辭：昭德皇后廟樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','金枝羽部徹清歌，瑤台肅穆笙磬羅。',32,'御定全唐詩/json/014.json','["金枝羽部徹清歌，瑤台肅穆笙磬羅。", "諧音遍響合明意，萬類昭融靈應多。"]'),
('yuding-38','郊廟歌辭：昭德皇后廟樂章：凱安','不詳','唐','御定全唐诗','yuding','','[]','辰位列四星，帝功參十亂。進賢勤內輔，扈蹕清多難。',48,'御定全唐詩/json/014.json','["辰位列四星，帝功參十亂。進賢勤內輔，扈蹕清多難。", "承天厚載均，並耀宵光燦。留徽藹前躅，萬古披圖煥。"]'),
('yuding-39','郊廟歌辭：昭德皇后廟樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','公屍既起，享禮載終。稱歌進徹，盡敬繇衷。',30,'御定全唐詩/json/014.json','["公屍既起，享禮載終。稱歌進徹，盡敬繇衷。", "澤流惠下，大小咸同。"]'),
('yuding-40','郊廟歌辭：昭德皇后廟樂章：永和','不詳','唐','御定全唐诗','yuding','','[]','昭事終，幽享餘。移月禦，返仙居。',32,'御定全唐詩/json/014.json','["昭事終，幽享餘。移月禦，返仙居。", "璿庭寂，靈幄虛。顧裴回，感皇儲。"]'),
('yuding-0','郊廟歌辭：讓皇帝廟樂章：迎神','李舒','唐','御定全唐诗','yuding','','[]','皇矣天宗，德先王季。因心則友，克讓以位。',40,'御定全唐詩/json/015.json','["皇矣天宗，德先王季。因心則友，克讓以位。", "爰命有司，式遵前志。神其降靈，昭饗祀事。"]'),
('yuding-1','郊廟歌辭：讓皇帝廟樂章：奠幣','李舒','唐','御定全唐诗','yuding','','[]','惟帝時若，去而上仙。祀用商舞，樂備宮懸。',40,'御定全唐詩/json/015.json','["惟帝時若，去而上仙。祀用商舞，樂備宮懸。", "白璧加薦，玄纁告虔。子孫拜後，承茲吉蠲。"]'),
('yuding-2','郊廟歌辭：讓皇帝廟樂章：迎俎','李舒','唐','御定全唐诗','yuding','','[]','祀盛體薦，禮協粢盛。方周假廟，用魯純牲。',40,'御定全唐詩/json/015.json','["祀盛體薦，禮協粢盛。方周假廟，用魯純牲。", "捧徹祗敬，擊拊和鳴。受厘歸胙，既戒而平。"]'),
('yuding-3','郊廟歌辭：讓皇帝廟樂章：酌獻','李舒','唐','御定全唐诗','yuding','','[]','八音具舉，三壽既盥。潔茲宗彝，瑟彼圭瓚。',40,'御定全唐詩/json/015.json','["八音具舉，三壽既盥。潔茲宗彝，瑟彼圭瓚。", "蘭肴重錯，椒醑飄散。降胙維城，永為藩翰。"]'),
('yuding-4','郊廟歌辭：讓皇帝廟樂章：亞獻終獻','李舒','唐','御定全唐诗','yuding','','[]','秩禮有序，和音既同。九儀不忒，三揖將終。',40,'御定全唐詩/json/015.json','["秩禮有序，和音既同。九儀不忒，三揖將終。", "孝感藩後，相維辟公。四時之典，永永無窮。"]'),
('yuding-5','郊廟歌辭：讓皇帝廟樂章：送神','李舒','唐','御定全唐诗','yuding','','[]','奠獻已事，昏昕載分。風搖雨散，靈衛絪縕。',40,'御定全唐詩/json/015.json','["奠獻已事，昏昕載分。風搖雨散，靈衛絪縕。", "龍駕帝服，上騰五雲。泮宮複閟，寂寞無聞。"]'),
('yuding-6','郊廟歌辭：享隱太子廟樂章：誠和','不詳','唐','御定全唐诗','yuding','','[]','道閟鶴關，運纏鳩裏。門集大命，俾歆嘉祀。',40,'御定全唐詩/json/015.json','["道閟鶴關，運纏鳩裏。門集大命，俾歆嘉祀。", "禮亞六瑚，誠殫二簋。有誠顒若，神斯戾止。"]'),
('yuding-7','郊廟歌辭：享隱太子廟樂章：肅和','不詳','唐','御定全唐诗','yuding','','[]','歲肇春宗，幹開震長。瑤山既寂，戾園斯享。',40,'御定全唐詩/json/015.json','["歲肇春宗，幹開震長。瑤山既寂，戾園斯享。", "玉肅其事，物昭其象。弦誦成風，笙歌合響。"]'),
('yuding-8','郊廟歌辭：享隱太子廟樂章：雍和','不詳','唐','御定全唐诗','yuding','','[]','明典肅陳，神居邃啟。春伯聯事，秋官相禮。',40,'御定全唐詩/json/015.json','["明典肅陳，神居邃啟。春伯聯事，秋官相禮。", "有來雍雍，登歌濟濟。緬維主鬯，庶歆芳醴。"]'),
('yuding-9','郊廟歌辭：享隱太子廟樂章：舒和','不詳','唐','御定全唐诗','yuding','','[]','三縣已判歌鐘列，六佾將開羽戚分。',32,'御定全唐詩/json/015.json','["三縣已判歌鐘列，六佾將開羽戚分。", "尚想燕飛來蔽日，終疑鶴影降淩雲。"]'),
('yuding-10','郊廟歌辭：享隱太子廟樂章：凱安','不詳','唐','御定全唐诗','yuding','','[]','天步昔將開，商郊初欲踐。撫戎金陣廓，貳極瑤圖闡。',48,'御定全唐詩/json/015.json','["天步昔將開，商郊初欲踐。撫戎金陣廓，貳極瑤圖闡。", "雞戟遂崇儀，龍樓期好善。弄兵隳震業，啟聖隆嗣典。"]'),
('yuding-11','郊廟歌辭：隱太子廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','蒼震有位，黃離蔽明。江充禍結，戾據災成。',40,'御定全唐詩/json/015.json','["蒼震有位，黃離蔽明。江充禍結，戾據災成。", "銜冤昔痛，贈典今榮。享靈有秩，奉樂以迎。"]'),
('yuding-12','郊廟歌辭：隱太子廟樂章：送神','不詳','唐','御定全唐诗','yuding','','[]','皇情悼往，祀議增設。鐘鼓鏗鏘，羽旄昭晰。',40,'御定全唐詩/json/015.json','["皇情悼往，祀議增設。鐘鼓鏗鏘，羽旄昭晰。", "掌禮雲備，司筵告徹。樂以送神，靈其鑒闋。"]'),
('yuding-13','郊廟歌辭：享章懷太子廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','副君昭象，道應黃離。銅樓備德，玉裕成規。',40,'御定全唐詩/json/015.json','["副君昭象，道應黃離。銅樓備德，玉裕成規。", "仙氣靄靄，靈從師師。前驅戾止，控鶴來儀。"]'),
('yuding-14','郊廟歌辭：享章懷太子廟樂章：登歌酌鬯','不詳','唐','御定全唐诗','yuding','','[]','忠孝本著，羽翼先成。寢門昭德，馳道為程。',40,'御定全唐詩/json/015.json','["忠孝本著，羽翼先成。寢門昭德，馳道為程。", "幣帛有典，容衛無聲。司存既肅，廟享惟清。"]'),
('yuding-15','郊廟歌辭：享章懷太子廟樂章：迎俎酌獻','不詳','唐','御定全唐诗','yuding','','[]','通三錫胤，明兩承英。太山比赫，伊水聞笙。',40,'御定全唐詩/json/015.json','["通三錫胤，明兩承英。太山比赫，伊水聞笙。", "宗祧是寄，禮樂其亨。嘉辰薦俎，以發聲明。"]'),
('yuding-16','郊廟歌辭：享章懷太子廟樂章：送文舞迎武舞','不詳','唐','御定全唐诗','yuding','','[]','羽鑰崇文禮以畢，幹戚奮武事將行。',32,'御定全唐詩/json/015.json','["羽鑰崇文禮以畢，幹戚奮武事將行。", "用舍繇來其有致，壯志宣威樂太平。"]'),
('yuding-17','郊廟歌辭：享章懷太子廟樂章：武舞作','不詳','唐','御定全唐诗','yuding','','[]','綠林熾炎曆，黃虞格有苗。沙塵驚塞外，帷幄命嫖姚。',48,'御定全唐詩/json/015.json','["綠林熾炎曆，黃虞格有苗。沙塵驚塞外，帷幄命嫖姚。", "七德干戈止，三邊雲霧消。寶祚長無極，歌舞盛今朝。"]'),
('yuding-18','郊廟歌辭：享懿德太子廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','甲觀昭祥，畫堂升位。禮絕群後，望尊儲貳。',40,'御定全唐詩/json/015.json','["甲觀昭祥，畫堂升位。禮絕群後，望尊儲貳。", "啟誦慚德，莊丕掩粹。伊浦鳳翔，緱峰鶴至。"]'),
('yuding-19','郊廟歌辭：享懿德太子廟樂章：登歌酌鬯','不詳','唐','御定全唐诗','yuding','','[]','譽闡元儲，寄崇明兩。玉裕雖晦，銅樓可想。',40,'御定全唐詩/json/015.json','["譽闡元儲，寄崇明兩。玉裕雖晦，銅樓可想。", "弦誦輟音，笙歌罷響。幣帛言設，禮容無爽。"]'),
('yuding-20','郊廟歌辭：享懿德太子廟樂章：迎俎酌獻','不詳','唐','御定全唐诗','yuding','','[]','雍雍盛典，肅肅靈祠。賓天有聖，對日無期。',40,'御定全唐詩/json/015.json','["雍雍盛典，肅肅靈祠。賓天有聖，對日無期。", "飄颻羽服，掣曳雲旗。眷言主鬯，心乎愴茲。"]'),
('yuding-21','郊廟歌辭：享懿德太子廟樂章：送文舞迎武舞','不詳','唐','御定全唐诗','yuding','','[]','八音協奏陳金石，六佾分行整禮容。',32,'御定全唐詩/json/015.json','["八音協奏陳金石，六佾分行整禮容。", "滄溟赴海還稱少，素月開輪即是重。"]'),
('yuding-22','郊廟歌辭：享懿德太子廟樂章：武舞作','不詳','唐','御定全唐诗','yuding','','[]','隋季昔雲終，唐年初啟聖。纂戎將禁暴，崇儒更敷政。',36,'御定全唐詩/json/015.json','["隋季昔雲終，唐年初啟聖。纂戎將禁暴，崇儒更敷政。", "威略靜三邊，仁恩覃萬姓。"]'),
('yuding-23','郊廟歌辭：享節湣太子廟樂章：迎神','不詳','唐','御定全唐诗','yuding','','[]','儲後望崇，元良寄切。寢門是仰，馳道不絕。',40,'御定全唐詩/json/015.json','["儲後望崇，元良寄切。寢門是仰，馳道不絕。", "仙袂雲會，靈旗電晰。煌煌而來，禮物攸設。"]'),
('yuding-24','郊廟歌辭：享節湣太子廟樂章：登歌酌鬯','不詳','唐','御定全唐诗','yuding','','[]','灼灼重明，仰承元首。既賢且哲，惟孝與友。',40,'御定全唐詩/json/015.json','["灼灼重明，仰承元首。既賢且哲，惟孝與友。", "惟孝雖遙，靈規不朽。禮因誠致，備絜玄酒。"]'),
('yuding-25','郊廟歌辭：享節湣太子廟樂章：迎俎酌獻','不詳','唐','御定全唐诗','yuding','','[]','嘉薦有典，至誠莫騫。畫梁雲亙，雕俎星連。',40,'御定全唐詩/json/015.json','["嘉薦有典，至誠莫騫。畫梁雲亙，雕俎星連。", "樂器周列，禮容備宣。依稀如在，若未賓天。"]'),
('yuding-26','郊廟歌辭：享節湣太子廟樂章：送文舞出迎武舞入','不詳','唐','御定全唐诗','yuding','','[]','邕邕闡化憑文德，赫赫宣威藉武功。',32,'御定全唐詩/json/015.json','["邕邕闡化憑文德，赫赫宣威藉武功。", "既執羽旄先拂吹，還持玉戚更揮空。"]'),
('yuding-27','郊廟歌辭：享節湣太子廟樂章：武舞作','不詳','唐','御定全唐诗','yuding','','[]','武德諒雍雍，由來掃寇戎。劍光揮作電，旗影列成虹。',48,'御定全唐詩/json/015.json','["武德諒雍雍，由來掃寇戎。劍光揮作電，旗影列成虹。", "霧廓三邊靜，波澄四海同。睿圖今已盛，相共舞皇風。"]'),
('yuding-28','郊廟歌辭：享文敬太子廟樂章：請神','許孟容','唐','御定全唐诗','yuding','','[]','觴牢具品，管磬有節。祝道夤恭，神儀昭晰。',40,'御定全唐詩/json/015.json','["觴牢具品，管磬有節。祝道夤恭，神儀昭晰。", "桐圭早貴，象輅追設。聲達樂成，降歆豐潔。"]'),
('yuding-29','郊廟歌辭：享文敬太子廟樂章：登歌','陳京','唐','御定全唐诗','yuding','','[]','歌以德發，聲以樂貴。樂善名存，追仙禮異。',40,'御定全唐詩/json/015.json','["歌以德發，聲以樂貴。樂善名存，追仙禮異。", "鸞旌拱修，鳳鳴合吹。神聽皇慈，仲月皆至。"]'),
('yuding-30','郊廟歌辭：享文敬太子廟樂章：迎俎酌獻','馮伉','唐','御定全唐诗','yuding','','[]','撰日瞻景，誠陳樂張。禮容秩秩，羽舞煌煌。',40,'御定全唐詩/json/015.json','["撰日瞻景，誠陳樂張。禮容秩秩，羽舞煌煌。", "肅將滌濯，祗薦芬芳。永錫繁祉，思深饗嘗。"]'),
('yuding-31','郊廟歌辭：享文敬太子廟樂章：送文舞迎武舞','不詳','唐','御定全唐诗','yuding','','[]','幹旄羽鑰相虧蔽，一進一退殊行綴。',32,'御定全唐詩/json/015.json','["幹旄羽鑰相虧蔽，一進一退殊行綴。", "昔獻三雍盛禮容，今陳六佾崇儀制。"]'),
('yuding-32','郊廟歌辭：享文敬太子廟樂章：亞獻終獻','崔邠','唐','御定全唐诗','yuding','','[]','醴齊泛尊彝，軒縣動幹戚。入室僾如在，升階虔所曆。',48,'御定全唐詩/json/015.json','["醴齊泛尊彝，軒縣動幹戚。入室僾如在，升階虔所曆。", "奮疾合威容，定利舒皦繹。方崇廟貌禮，永被君恩錫。"]'),
('yuding-33','郊廟歌辭：享文敬太子廟樂章：送神','崔邠','唐','御定全唐诗','yuding','','[]','三獻具舉，九旗將旋。追勞表德，罷享賓天。',40,'御定全唐詩/json/015.json','["三獻具舉，九旗將旋。追勞表德，罷享賓天。", "風引仙管，堂虛畫筵。芳馨常在，瞻望悠然。"]'),
('yuding-34','郊廟歌辭：享惠昭太子廟樂章：請神','歸登','唐','御定全唐诗','yuding','','[]','嘉薦既陳，祀事孔明。閑歌在堂，萬舞在庭。',40,'御定全唐詩/json/015.json','["嘉薦既陳，祀事孔明。閑歌在堂，萬舞在庭。", "外則盡物，內則盡誠。鳳笙如聞，歌其潔精。"]'),
('yuding-35','郊廟歌辭：享惠昭太子廟樂章：登歌','杜羔','唐','御定全唐诗','yuding','','[]','因心克孝，位震遺芬。賓天道茂，軫懷氣分。',40,'御定全唐詩/json/015.json','["因心克孝，位震遺芬。賓天道茂，軫懷氣分。", "發祗乃祀，咳歎如聞。二歌斯升，以詠德熏。"]'),
('yuding-36','郊廟歌辭：享惠昭太子廟樂章：迎俎酌獻','李逢吉','唐','御定全唐诗','yuding','','[]','既潔酒醴，聿陳熟腥。肅將震念，昭格儲靈。',40,'御定全唐詩/json/015.json','["既潔酒醴，聿陳熟腥。肅將震念，昭格儲靈。", "展矣禮典，熏然德馨。愔愔管磬，亦具是聽。"]'),
('yuding-37','郊廟歌辭：享惠昭太子廟樂章：送文舞出迎武舞入','孟簡','唐','御定全唐诗','yuding','','[]','喧喧金石容既缺，肅肅羽駕就行列。',32,'御定全唐詩/json/015.json','["喧喧金石容既缺，肅肅羽駕就行列。", "緱山遺響昔所聞，廟庭進旅今攸設。"]'),
('yuding-38','郊廟歌辭：享惠昭太子廟樂章：亞獻終獻','裴度','唐','御定全唐诗','yuding','','[]','重輪始發祥，齒胄方興學。冥然升紫府，鏗爾薦清樂。',48,'御定全唐詩/json/015.json','["重輪始發祥，齒胄方興學。冥然升紫府，鏗爾薦清樂。", "奠斝致馨香，在庭紛羽鑰。禮成神既醉，仿佛緱山鶴。"]'),
('yuding-39','郊廟歌辭：享惠昭太子廟樂章：送神','王涯','唐','御定全唐诗','yuding','','[]','威儀畢陳，備樂將闋。苞茅酒縮，膋蕭香徹。',40,'御定全唐詩/json/015.json','["威儀畢陳，備樂將闋。苞茅酒縮，膋蕭香徹。", "宮臣展事，肅雍在列。迎精送往，厥鑒昭晰。"]'),
('yuding-40','《郊廟歌辭：武后崇先廟樂章','不詳','唐','御定全唐诗','yuding','','[]','先德謙撝冠昔，嚴規節素超今。奉國忠誠每竭，',42,'御定全唐詩/json/015.json','["先德謙撝冠昔，嚴規節素超今。奉國忠誠每竭，", "既迫王公屢請，方乃俯遂群心。有限無由展敬，"]'),
('yuding-41','郊廟歌辭：褒德廟樂章：昭德','不詳','唐','御定全唐诗','yuding','','[]','道赫梧宮，悲盈蒿裏。爰賜徽烈，載敷嘉祀。',40,'御定全唐詩/json/015.json','["道赫梧宮，悲盈蒿裏。爰賜徽烈，載敷嘉祀。", "享洽四時，規陳二簋。靈應昭格，神其戾止。"]'),
('yuding-42','郊廟歌辭：褒德廟樂章：進德','不詳','唐','御定全唐诗','yuding','','[]','塗山懿戚，媯汭崇姻。祠筵肇啟，祭典方申。',40,'御定全唐詩/json/015.json','["塗山懿戚，媯汭崇姻。祠筵肇啟，祭典方申。", "禮以備物，樂以感神。用隆敦敘，載穆彝倫。"]'),
('yuding-43','郊廟歌辭：褒德廟樂章：褒德','不詳','唐','御定全唐诗','yuding','','[]','家著累仁，門昭積善。瑤篚既列，金縣式展。',20,'御定全唐詩/json/015.json','["家著累仁，門昭積善。瑤篚既列，金縣式展。"]'),
('yuding-44','郊廟歌辭：褒德廟樂章：武舞作','不詳','唐','御定全唐诗','yuding','','[]','昭昭竹殿開，奕奕蘭宮啟。懿範隆丹掖，殊榮辟朱邸。',48,'御定全唐詩/json/015.json','["昭昭竹殿開，奕奕蘭宮啟。懿範隆丹掖，殊榮辟朱邸。", "六佾薦徽容，三簋陳芳醴。萬石覃貽厥，分珪崇祖禰。"]'),
('yuding-45','郊廟歌辭：褒德廟樂章：彰德','不詳','唐','御定全唐诗','yuding','','[]','名隆五嶽，秩映三台。嚴祠已備，睟影方回。',20,'御定全唐詩/json/015.json','["名隆五嶽，秩映三台。嚴祠已備，睟影方回。"]'),
('yuding-46','舞曲歌辭：功成慶善樂舞詞','不詳','唐','御定全唐诗','yuding','','[]','壽丘惟舊跡，酆邑乃前基。粵餘承累聖，懸弧亦在茲。',121,'御定全唐詩/json/015.json','["壽丘惟舊跡，酆邑乃前基。粵餘承累聖，懸弧亦在茲。", "弱齡逢運改，提劍郁匡時。指麾八荒定，懷柔萬國夷。", "梯山盛入款，駕海亦來思。單于陪武帳，日逐衛文lq。", "端扆朝四岳，無為任百司。霜節明秋景，輕冰結水湄。", "芸黃遍原隰，禾穎積京坻。共樂還譙宴，歡此大風詩。"]'),
('yuding-47','舞曲歌辭：中和樂舞詞','不詳','唐','御定全唐诗','yuding','','[]','芳歲肇佳節，物華當仲春。乾坤既昭泰，煙景含氤氳。',96,'御定全唐詩/json/015.json','["芳歲肇佳節，物華當仲春。乾坤既昭泰，煙景含氤氳。", "德淺荷玄貺，樂成思治人。前庭列鐘鼓，廣殿延群臣。", "八卦隨舞意，五音轉曲新。顧非咸池奏，庶協南風熏。", "式宴禮所重，浹歡情必均。同和諒在茲，萬國希可親。"]'),
('yuding-48','舞曲歌辭：凱樂歌辭：破陣樂','不詳','唐','御定全唐诗','yuding','','[]','受律辭元首，相將討叛臣。咸歌破陣樂，共賞太平人。',24,'御定全唐詩/json/015.json','["受律辭元首，相將討叛臣。咸歌破陣樂，共賞太平人。"]'),
('yuding-49','舞曲歌辭：凱樂歌辭：應聖期','不詳','唐','御定全唐诗','yuding','','[]','聖德期昌運，雍熙萬宇清。乾坤資化育，海嶽共休明。',48,'御定全唐詩/json/015.json','["聖德期昌運，雍熙萬宇清。乾坤資化育，海嶽共休明。", "辟土欣耕稼，銷戈遂偃兵。殊方歌帝澤，執贄駕升平。"]'),
('yuding-50','舞曲歌辭：凱樂歌辭：賀聖歡','不詳','唐','御定全唐诗','yuding','','[]','四海皇風被，千年德水清。戎衣更不著，今日告功成。',24,'御定全唐詩/json/015.json','["四海皇風被，千年德水清。戎衣更不著，今日告功成。"]'),
('yuding-51','舞曲歌辭：凱樂歌辭：君臣同慶樂','不詳','唐','御定全唐诗','yuding','','[]','主聖開昌曆，臣忠奉大猷。君看偃革後，便是太平秋。',24,'御定全唐詩/json/015.json','["主聖開昌曆，臣忠奉大猷。君看偃革後，便是太平秋。"]'),
('yuding-0','郊廟歌辭：梁郊祀樂章：慶和','趙光逢','唐','御定全唐诗','yuding','','[]','就陽位，升圓丘。佩雙玉，禦大裘。',208,'御定全唐詩/json/016.json','["就陽位，升圓丘。佩雙玉，禦大裘。", "膺天命，擁神休。萬靈感，百祿遒。", "秉黃鉞，建朱旗。震八表，清二儀。", "帝業顯，王道夷。受景命，啟皇基。", "開九門，懷百神。通肸蚃，接氤氳。", "明粢薦，廣樂陳。奠嘉璧，燎芳薪。", "膺寶圖，執左契。德應天，聖饗帝。", "薦表衷，荷靈惠。壽萬年，祚百世。", "惟德動天，有感必通。秉茲一德，禋于六宗。", "欽夤寶命，恭肅禮容。來顧來享，永穆皇風。", "天惟佑德，辟乃奉天。交感斯在，昭事罔愆。", "歲功已就，王道無偏。於焉報本，是用告虔。"]'),
('yuding-1','郊廟歌辭：梁郊祀樂章：慶順','不詳','唐','御定全唐诗','yuding','','[]','聖皇戾止，天步舒遲。幹幹睿相，穆穆皇儀。',40,'御定全唐詩/json/016.json','["聖皇戾止，天步舒遲。幹幹睿相，穆穆皇儀。", "進退必肅，陟降是祗。六變克協，萬靈協隨。"]'),
('yuding-2','郊廟歌辭：梁郊祀樂章：慶平','不詳','唐','御定全唐诗','yuding','','[]','天命降鑒，帝德惟馨。享祀不忒，禮容孔明。',40,'御定全唐詩/json/016.json','["天命降鑒，帝德惟馨。享祀不忒，禮容孔明。", "奠璧布幣，薦神獻精。神佑以答，敷錫永寧。"]'),
('yuding-3','郊廟歌辭：梁郊祀樂章：慶肅','張袞','唐','御定全唐诗','yuding','','[]','籩豆簠簋，黍稷非馨。懿茲彝器，厥德惟明。',40,'御定全唐詩/json/016.json','["籩豆簠簋，黍稷非馨。懿茲彝器，厥德惟明。", "金石匏革，以和以平。繇此無體，期乎永寧。"]'),
('yuding-4','郊廟歌辭：梁郊祀樂章：慶熙','不詳','唐','御定全唐诗','yuding','','[]','哲後躬享，旨酒斯陳。王恭無斁，嚴祀維夤。',40,'御定全唐詩/json/016.json','["哲後躬享，旨酒斯陳。王恭無斁，嚴祀維夤。", "皇祖以配，大孝以振。宜錫景福，永休下民。"]'),
('yuding-5','郊廟歌辭：梁郊祀樂章：慶隆','不詳','唐','御定全唐诗','yuding','','[]','恭祀上帝，于國之陽。爵醴是荷，鴻基永昌。',20,'御定全唐詩/json/016.json','["恭祀上帝，于國之陽。爵醴是荷，鴻基永昌。"]'),
('yuding-6','郊廟歌辭：梁郊祀樂章：慶融','不詳','唐','御定全唐诗','yuding','','[]','道和氣兮襲氤氳，宣皇規兮彰聖神。',32,'御定全唐詩/json/016.json','["道和氣兮襲氤氳，宣皇規兮彰聖神。", "服遐裔兮敷質文，格苗扈兮息煙塵。"]'),
('yuding-7','郊廟歌辭：梁郊祀樂章：慶休','不詳','唐','御定全唐诗','yuding','','[]','大業來四夷，仁風和萬國。白日體無私，皇天輔有德。',48,'御定全唐詩/json/016.json','["大業來四夷，仁風和萬國。白日體無私，皇天輔有德。", "七旬罪已服，六月師方克。偉哉帝道隆，終始常作則。"]'),
('yuding-8','郊廟歌辭：梁郊祀樂章：慶和','不詳','唐','御定全唐诗','yuding','','[]','煙燎升，禮容徹。誠感達，人神悅。',32,'御定全唐詩/json/016.json','["煙燎升，禮容徹。誠感達，人神悅。", "靈貺彰，聖情結。玉座寂，金爐歇。"]'),
('yuding-9','郊廟歌辭：周郊祀樂章：昭順樂','不詳','唐','御定全唐诗','yuding','','[]','五兵勿用，萬國咸安。告功圓蓋，受命雲壇。',40,'御定全唐詩/json/016.json','["五兵勿用，萬國咸安。告功圓蓋，受命雲壇。", "樂鳴鳳律，禮備雞竿。神光欲降，眾目遐觀。"]'),
('yuding-10','郊廟歌辭：周郊祀樂章：治順樂','不詳','唐','御定全唐诗','yuding','','[]','羽衛離丹闕，金軒赴泰壇。珠旗明月色，玉佩曉霜寒。',48,'御定全唐詩/json/016.json','["羽衛離丹闕，金軒赴泰壇。珠旗明月色，玉佩曉霜寒。", "黼黻龍衣備，琮璜寶器完。百神將受職，宗社保長安。"]'),
('yuding-11','郊廟歌辭：周郊祀樂章：感順樂','不詳','唐','御定全唐诗','yuding','','[]','明君陳大禮，展幣祀圓丘。雅樂聲齊發，祥雲色正浮。',24,'御定全唐詩/json/016.json','["明君陳大禮，展幣祀圓丘。雅樂聲齊發，祥雲色正浮。"]'),
('yuding-12','郊廟歌辭：周郊祀樂章：禋順樂','不詳','唐','御定全唐诗','yuding','','[]','黃彝將獻，特牲預迎。既修昭事，潛達明誠。',20,'御定全唐詩/json/016.json','["黃彝將獻，特牲預迎。既修昭事，潛達明誠。"]'),
('yuding-13','郊廟歌辭：周郊祀樂章：福順樂','不詳','唐','御定全唐诗','yuding','','[]','相承五運，取法三才。大禮爰展，率土咸來。',40,'御定全唐詩/json/016.json','["相承五運，取法三才。大禮爰展，率土咸來。", "卿雲秘室，甘泉寶台。象樽初酌，受福不回。"]'),
('yuding-14','郊廟歌辭：周郊祀樂章：福順樂','不詳','唐','御定全唐诗','yuding','','[]','昊天成命，邦國盛儀。多士齊列，六龍載馳。',40,'御定全唐詩/json/016.json','["昊天成命，邦國盛儀。多士齊列，六龍載馳。", "壇升泰一，樂奏咸池。高明祚德，永致昌期。"]'),
('yuding-15','郊廟歌辭：周郊祀樂章：福順樂','不詳','唐','御定全唐诗','yuding','','[]','上天垂景貺，哲後舉鸞觴。明德今方祚，邦家萬世昌。',24,'御定全唐詩/json/016.json','["上天垂景貺，哲後舉鸞觴。明德今方祚，邦家萬世昌。"]'),
('yuding-16','郊廟歌辭：周郊祀樂章：忠順樂','不詳','唐','御定全唐诗','yuding','','[]','木鐸敷音文德昌，朱幹成列武功彰。',32,'御定全唐詩/json/016.json','["木鐸敷音文德昌，朱幹成列武功彰。", "雷鞀鷺羽今休用，玉戚相參正發揚。"]'),
('yuding-17','郊廟歌辭：周郊祀樂章：武舞樂','不詳','唐','御定全唐诗','yuding','','[]','圭瓚方陳禮，幹旄乃象功。成文非羽鑰，猛勢若羆熊。',24,'御定全唐詩/json/016.json','["圭瓚方陳禮，幹旄乃象功。成文非羽鑰，猛勢若羆熊。"]'),
('yuding-18','郊廟歌辭：周郊祀樂章：昭順樂','不詳','唐','御定全唐诗','yuding','','[]','雲門孤竹，蒼璧黃琮。既祀天地，克配祖宗。',40,'御定全唐詩/json/016.json','["雲門孤竹，蒼璧黃琮。既祀天地，克配祖宗。", "虔修盛禮，仰答玄功。神歸碧落，神降無窮。"]'),
('yuding-19','郊廟歌辭：梁太廟樂舞辭：開平舞','不詳','唐','御定全唐诗','yuding','','[]','黍稷馨，醴z0清。牲牷潔，金石鏗。',33,'御定全唐詩/json/016.json','["黍稷馨，醴z0清。牲牷潔，金石鏗。", "恭祀事，結皇情。神來格，歌頌聲。"]'),
('yuding-20','郊廟歌辭：梁太廟樂舞辭：皇帝行','不詳','唐','御定全唐诗','yuding','','[]','莫高者天，攀躋弗克。隮天有方，累仁積德。',40,'御定全唐詩/json/016.json','["莫高者天，攀躋弗克。隮天有方，累仁積德。", "祖宗隆之，子孫履之。配天明祀，永永孝思。"]'),
('yuding-21','郊廟歌辭：梁太廟樂舞辭：帝盥','不詳','唐','御定全唐诗','yuding','','[]','莊肅蒞事，周旋禮容。祼鬯嚴潔，穆穆雍雍。',20,'御定全唐詩/json/016.json','["莊肅蒞事，周旋禮容。祼鬯嚴潔，穆穆雍雍。"]'),
('yuding-22','郊廟歌辭：梁太廟樂舞辭：登歌','不詳','唐','御定全唐诗','yuding','','[]','於赫我皇，建中立極。動以武功，靜以文德。',40,'御定全唐詩/json/016.json','["於赫我皇，建中立極。動以武功，靜以文德。", "昭事上帝，歡心萬國。大報嚴禋，四海述職。"]'),
('yuding-23','郊廟歌辭：梁太廟樂舞辭：大合舞','不詳','唐','御定全唐诗','yuding','','[]','于穆皇祖，浚哲雍熙。美溢中夏，化被南陲。',40,'御定全唐詩/json/016.json','["于穆皇祖，浚哲雍熙。美溢中夏，化被南陲。", "後稷累德，公劉創基。肇興九廟，樂合來儀。"]'),
('yuding-24','郊廟歌辭：梁太廟樂舞辭：象功舞','不詳','唐','御定全唐诗','yuding','','[]','天地合德，睿聖昭彰。累贈太傅，俄登魏王。',40,'御定全唐詩/json/016.json','["天地合德，睿聖昭彰。累贈太傅，俄登魏王。", "雄名不朽，奕葉而光。建國之兆，君臨萬方。"]'),
('yuding-25','郊廟歌辭：梁太廟樂舞辭：來儀舞','不詳','唐','御定全唐诗','yuding','','[]','於赫帝命，應天順人。亭育品匯，賓禮百神。',40,'御定全唐詩/json/016.json','["於赫帝命，應天順人。亭育品匯，賓禮百神。", "洪基永固，景命惟新。肅恭孝享，祚我生民。"]'),
('yuding-26','郊廟歌辭：梁太廟樂舞辭：昭德舞','不詳','唐','御定全唐诗','yuding','','[]','肅肅文考，源浚派長。漢稱誕季，周實生昌。',40,'御定全唐詩/json/016.json','["肅肅文考，源浚派長。漢稱誕季，周實生昌。", "奄有四海，超彼百王。笙鏞迭奏，禮物熒煌。"]'),
('yuding-27','郊廟歌辭：梁太廟樂舞辭：飲福','不詳','唐','御定全唐诗','yuding','','[]','戛玉摐金永頌聲，檿絲孤竹和且清。',32,'御定全唐詩/json/016.json','["戛玉摐金永頌聲，檿絲孤竹和且清。", "靈歆醉止犧象盈，自天降福千萬齡。"]'),
('yuding-28','郊廟歌辭：梁太廟樂舞辭：撤豆','不詳','唐','御定全唐诗','yuding','','[]','笙鏞洋洋，庭燎煌煌。明星有爛，祝史下堂。',40,'御定全唐詩/json/016.json','["笙鏞洋洋，庭燎煌煌。明星有爛，祝史下堂。", "籩豆斯撤，禮容有章。克勤克儉，無怠無荒。"]'),
('yuding-29','郊廟歌辭：梁太廟樂舞辭：送神','不詳','唐','御定全唐诗','yuding','','[]','其降無從，其往無蹤。黍稷非馨，有感必通。',40,'御定全唐詩/json/016.json','["其降無從，其往無蹤。黍稷非馨，有感必通。", "赫奕令德，仿佛睟容。再拜慌忽，遐想昊穹。"]'),
('yuding-30','郊廟歌辭：後唐宗廟樂舞辭：昭德舞','不詳','唐','御定全唐诗','yuding','','[]','懿彼明德，赫赫煌煌。名高閫域，功著旗常。',40,'御定全唐詩/json/016.json','["懿彼明德，赫赫煌煌。名高閫域，功著旗常。", "道符休泰，運葉祺祥。慶傳萬祀，以播耿光。"]'),
('yuding-31','郊廟歌辭：後唐宗廟樂舞辭：文明舞','不詳','唐','御定全唐诗','yuding','','[]','帝業光揚，皇圖翕赫。聖德孔彰，神功不測。',40,'御定全唐詩/json/016.json','["帝業光揚，皇圖翕赫。聖德孔彰，神功不測。", "信及豚魚，恩沾動植。懿範鴻名，傳之萬億。"]'),
('yuding-32','郊廟歌辭：後唐宗廟樂舞辭：應天舞','不詳','唐','御定全唐诗','yuding','','[]','晉國肇興，雄圖再固。黼黻帝道，金玉王度。',40,'御定全唐詩/json/016.json','["晉國肇興，雄圖再固。黼黻帝道，金玉王度。", "皇天無親，惟德是輔。載誕英明，永光聖祚。"]'),
('yuding-33','郊廟歌辭：後唐宗廟樂舞辭：永平舞','不詳','唐','御定全唐诗','yuding','','[]','慶傳瓚祚，位正瑤圖。功宣四海，化被八區。',40,'御定全唐詩/json/016.json','["慶傳瓚祚，位正瑤圖。功宣四海，化被八區。", "靜彰帝道，動合幹符。千秋萬祀，永荷昭蘇。"]'),
('yuding-34','郊廟歌辭：後唐宗廟樂舞辭：武成舞','不詳','唐','御定全唐诗','yuding','','[]','艱難王業，返正皇唐。先天再造，卻日重光。',40,'御定全唐詩/json/016.json','["艱難王業，返正皇唐。先天再造，卻日重光。", "漢紹世祖，夏資少康。功成德茂，率祀無疆。"]'),
('yuding-35','郊廟歌辭：後唐宗廟樂舞辭：雍熙舞','不詳','唐','御定全唐诗','yuding','','[]','仁君禦宇，寰海謐清。運符武德，道協文明。',40,'御定全唐詩/json/016.json','["仁君禦宇，寰海謐清。運符武德，道協文明。", "九成式敘，百度惟貞。金門積慶，玉葉傳榮。"]'),
('yuding-36','郊廟歌辭：漢宗廟樂舞辭：武德舞','不詳','唐','御定全唐诗','yuding','','[]','明明我祖，天集休明。神母夜哭，彤雲晝興。',40,'御定全唐詩/json/016.json','["明明我祖，天集休明。神母夜哭，彤雲晝興。", "籩豆有踐，管鑰斯登。孝孫致告，神其降靈。"]'),
('yuding-37','郊廟歌辭：漢宗廟樂舞辭：靈長舞','不詳','唐','御定全唐诗','yuding','','[]','天降祥，漢祚昌。火炎上，水靈長。建廟社，潔蒸嘗。',64,'御定全唐詩/json/016.json','["天降祥，漢祚昌。火炎上，水靈長。建廟社，潔蒸嘗。", "羅鐘石，儼珩璜。陳玉豆，酌金觴。氣昭感，德馨香。", "祗洛汭，瞻晉陽。降吾祖，福穰穰。"]'),
('yuding-38','郊廟歌辭：漢宗廟樂舞辭：積善舞','不詳','唐','御定全唐诗','yuding','','[]','黍稷斯馨，祖德惟明。蛇告赤帝，龜謀大橫。',80,'御定全唐詩/json/016.json','["黍稷斯馨，祖德惟明。蛇告赤帝，龜謀大橫。", "雲行雨施，天成地平。造我家邦，斡我璿衡。", "陶匏在禦，醍盎惟精。或戛或擊，載炮載烹。", "飲福受胙，舞降歌迎。滔滔不竭，洪惟水行。"]'),
('yuding-39','郊廟歌辭：漢宗廟樂舞辭：顯仁舞','不詳','唐','御定全唐诗','yuding','','[]','運極金行謝，天資水德隆。禮神鄜畤館，布政未央宮。',96,'御定全唐詩/json/016.json','["運極金行謝，天資水德隆。禮神鄜畤館，布政未央宮。", "詰旦備明祀，登歌答茂功。雲軒臨降久，星俎薦陳豐。", "靄靄沉檀霧，鏘鏘環佩風。熒煌升藻藉，肸蚃轉珠櫳。", "尊祖咸韶備，貽孫書軌同。京坻長有積，宗社享無窮。"]'),
('yuding-40','郊廟歌辭：漢宗廟樂舞辭：章慶舞','不詳','唐','御定全唐诗','yuding','','[]','罘罳曉唱雞人，三牲八簋斯陳。霧集瑤階瑣闥，',70,'御定全唐詩/json/016.json','["罘罳曉唱雞人，三牲八簋斯陳。霧集瑤階瑣闥，", "酌鬯既終三獻，凝旒何止千春。阿閣長棲彩鳳，", "玉斝犧樽瀲灩，龍旗鳳轄逡巡。", "瞻望月遊冠冕，猶疑蒼野回輪。"]'),
('yuding-41','郊廟歌辭：漢宗廟樂舞辭：觀德舞','張昭','唐','御定全唐诗','yuding','','[]','高廟明靈再啟圖，金根玉輅幸神都。巢阿丹鳳銜書命，',72,'御定全唐詩/json/016.json','["高廟明靈再啟圖，金根玉輅幸神都。巢阿丹鳳銜書命，", "薦櫻鶴館笳簫咽，酌鬯金楹劍佩趨。星俎雲罍兼魯禮，", "薦豆奉觴親玉幾，配天合祖耀璿樞。受厘飲酒皇歡洽，"]'),
('yuding-42','郊廟歌辭：周宗廟樂舞辭：肅順','不詳','唐','御定全唐诗','yuding','','[]','我後至孝，祗謁祖先。仰瞻廟貌，夙設宮懸。',40,'御定全唐詩/json/016.json','["我後至孝，祗謁祖先。仰瞻廟貌，夙設宮懸。", "朱弦疏越，羽舞迴旋。神其來格，明祀惟虔。"]'),
('yuding-43','郊廟歌辭：周宗廟樂舞辭：治順','不詳','唐','御定全唐诗','yuding','','[]','清廟將入，袞服是依。載行載止，令色令儀。',40,'御定全唐詩/json/016.json','["清廟將入，袞服是依。載行載止，令色令儀。", "永終就養，空極孝思。瞻望如在，顧複長違。"]'),
('yuding-44','郊廟歌辭：周宗廟樂舞辭：肅雍舞','不詳','唐','御定全唐诗','yuding','','[]','周道載興，象日之明。萬邦咸慶，百谷用成。',80,'御定全唐詩/json/016.json','["周道載興，象日之明。萬邦咸慶，百谷用成。", "于穆聖祖，祗薦鴻名。祀于廟社，陳其犧牲。", "進旅退旅，皇武之形。一倡三歎，朱弦之聲。", "以妥以侑，既和且平。至誠潛達，介福攸寧。"]'),
('yuding-45','郊廟歌辭：周宗廟樂舞辭：章德舞','不詳','唐','御定全唐诗','yuding','','[]','清廟新，展嚴禋。恭祖德，厚人倫。雅樂薦，禮器陳。',64,'御定全唐詩/json/016.json','["清廟新，展嚴禋。恭祖德，厚人倫。雅樂薦，禮器陳。", "儼皇屍，列虞賓。神如在，聲不聞。享必信，貌惟夤。", "想龍服，奠犧樽。禮既備，慶來臻。"]'),
('yuding-46','郊廟歌辭：周宗廟樂舞辭：善慶舞','不詳','唐','御定全唐诗','yuding','','[]','蔔世長，帝祚昌。定中國，服四方。修明祀，從舊章。',64,'御定全唐詩/json/016.json','["蔔世長，帝祚昌。定中國，服四方。修明祀，從舊章。", "奏激楚，轉清商。羅俎豆，列簪裳。歌累累，容皇皇。", "望來格，降休祥。祝敢告，壽無疆。"]'),
('yuding-47','郊廟歌辭：周宗廟樂舞辭：觀成舞','不詳','唐','御定全唐诗','yuding','','[]','穆穆王國，奕奕神功。毖祀載展，明德有融。',80,'御定全唐詩/json/016.json','["穆穆王國，奕奕神功。毖祀載展，明德有融。", "彝樽斯滿，簠簋斯豐。紛絺旄羽，鏘洋磬鐘。", "或升或降，克和克同。孔惠之禮，必肅之容。", "錫以純嘏，祚其允恭。神保是饗，萬世無窮。"]'),
('yuding-48','郊廟歌辭：周宗廟樂舞辭：明德舞','不詳','唐','御定全唐诗','yuding','','[]','惟彼岐陽，德大流光。載造周室，澤及遐荒。',80,'御定全唐詩/json/016.json','["惟彼岐陽，德大流光。載造周室，澤及遐荒。", "于鑠聖祖，上帝是皇。乃聖乃神，知微知彰。", "新廟奕奕，豐年穰穰。取彼血膋，以往蒸嘗。", "黍稷惟馨，籩豆大房。工祝致告，受福無疆。"]'),
('yuding-49','郊廟歌辭：周宗廟樂舞辭：咸順','不詳','唐','御定全唐诗','yuding','','[]','萬舞咸列，三階克清。貫珠一倡，擊石九成。',40,'御定全唐詩/json/016.json','["萬舞咸列，三階克清。貫珠一倡，擊石九成。", "盈觴雖酌，靈坐無形。永懷我祖，達其孝誠。"]'),
('yuding-50','郊廟歌辭：周宗廟樂舞辭：禋順','不詳','唐','御定全唐诗','yuding','','[]','旨酒既獻，嘉殽乃迎。振其鞀鼓，潔以鉶羹。',40,'御定全唐詩/json/016.json','["旨酒既獻，嘉殽乃迎。振其鞀鼓，潔以鉶羹。", "肇禋肇祀，或炮或烹。皇屍儼若，保饗是明。"]'),
('yuding-51','郊廟歌辭：周宗廟樂舞辭：福順','不詳','唐','御定全唐诗','yuding','','[]','新廟奕奕，金奏洋洋。享于祖考，循彼典章。',40,'御定全唐詩/json/016.json','["新廟奕奕，金奏洋洋。享于祖考，循彼典章。", "清酤特滿，嘉玉騰光。神醉既告，帝祉無疆。"]'),
('yuding-52','郊廟歌辭：周宗廟樂舞辭：忠順','不詳','唐','御定全唐诗','yuding','','[]','稱文既表溫柔德，示武須成蹈厲容。',32,'御定全唐詩/json/016.json','["稱文既表溫柔德，示武須成蹈厲容。", "綴兆疾舒皆應節，明明我祖樂無窮。"]'),
('yuding-53','郊廟歌辭：善勝舞','不詳','唐','御定全唐诗','yuding','','[]','聖祖累功，福鐘來裔。持羽執幹。舞文不廢。',20,'御定全唐詩/json/016.json','["聖祖累功，福鐘來裔。持羽執幹。舞文不廢。"]'),
('yuding-54','郊廟歌辭：善勝舞：禋順','不詳','唐','御定全唐诗','yuding','','[]','禮畢祀先，香散幾筵。罷舞幹戚，收撤豆籩。',20,'御定全唐詩/json/016.json','["禮畢祀先，香散幾筵。罷舞幹戚，收撤豆籩。"]'),
('yuding-55','郊廟歌辭：善勝舞：肅順','不詳','唐','御定全唐诗','yuding','','[]','樂奏四順，福受萬年。神歸碧天，庭餘瑞煙。',20,'御定全唐詩/json/016.json','["樂奏四順，福受萬年。神歸碧天，庭餘瑞煙。"]'),
('yuding-56','郊廟歌辭：晉朝饗樂章：初舉酒文同樂','不詳','唐','御定全唐诗','yuding','','[]','赫矣昌運，明哉聖王。文興墜典，禮復舊章。',40,'御定全唐詩/json/016.json','["赫矣昌運，明哉聖王。文興墜典，禮復舊章。", "鴛鸞濟濟，鳥獸蹌蹌。一人有慶，萬福無疆。"]'),
('yuding-57','郊廟歌辭：晉朝饗樂章：舉酒','不詳','唐','御定全唐诗','yuding','','[]','大明禦宇，至德動天。君臣慶會，禮樂昭宣。',40,'御定全唐詩/json/016.json','["大明禦宇，至德動天。君臣慶會，禮樂昭宣。", "劍佩成列，金石在懸。椒觴再獻，寶曆萬年。"]'),
('yuding-58','郊廟歌辭：晉朝饗樂章：再舉酒','不詳','唐','御定全唐诗','yuding','','[]','朝野無事，寰瀛大康。聖人有作，盛禮重光。',40,'御定全唐詩/json/016.json','["朝野無事，寰瀛大康。聖人有作，盛禮重光。", "萬國執玉，千官奉觴。南山永固，地久天長。"]'),
('yuding-59','郊廟歌辭：晉朝饗樂章：四舉酒','不詳','唐','御定全唐诗','yuding','','[]','八表歡無事，三秋賀有成。照臨同日遠，渥澤並雲行。',48,'御定全唐詩/json/016.json','["八表歡無事，三秋賀有成。照臨同日遠，渥澤並雲行。", "河變千年色，山呼萬歲聲。願修封岱禮，方以稱文明。"]'),
('yuding-60','郊廟歌辭：晉朝饗樂章：群臣酒行歌','不詳','唐','御定全唐诗','yuding','','[]','劍佩儼如林，齊傾拱北心。渥恩頒美祿，咸濩聽和音。',144,'御定全唐詩/json/016.json','["劍佩儼如林，齊傾拱北心。渥恩頒美祿，咸濩聽和音。", "一德君臣合，重瞳日月臨。歌時兼樂聖，唯待贊泥金。", "萬國咸歸禹，千官共祝堯。拜恩瞻鳳扆，傾耳聽雲韶。", "運啟金行遠，時和玉燭調。酒酣齊抃舞，同賀聖明朝。", "令節陳高會，群臣侍禦筵。玉墀留愛景，金殿靄祥煙。", "振鷺涵天澤，靈禽下樂懸。聖明無一事，何處讓堯年。"]'),
('yuding-61','郊廟歌辭：周朝饗樂章：忠順','不詳','唐','御定全唐诗','yuding','','[]','歲迎更始，節及朝元。冕旒仰止，冠劍相連。',40,'御定全唐詩/json/016.json','["歲迎更始，節及朝元。冕旒仰止，冠劍相連。", "八音合奏，萬物齊宣。常陳盛禮，願永千年。"]'),
('yuding-62','郊廟歌辭：周朝饗樂章：忠順','不詳','唐','御定全唐诗','yuding','','[]','明君當寧，列辟奉觴。雲容表瑞，日影初長。',40,'御定全唐詩/json/016.json','["明君當寧，列辟奉觴。雲容表瑞，日影初長。", "衣冠濟濟，鐘磬洋洋。令儀克盛，嘉會有章。"]'),
('yuding-63','郊廟歌辭：周朝饗樂章：治順','不詳','唐','御定全唐诗','yuding','','[]','庭陳大樂，坐當太微。凝旒負扆，端拱垂衣。',40,'御定全唐詩/json/016.json','["庭陳大樂，坐當太微。凝旒負扆，端拱垂衣。", "鴛鸞成列，簪組相輝。禦爐香散，鬱鬱霏霏。"]'),
('yuding-64','郊廟歌辭：周朝饗樂章：福順','不詳','唐','御定全唐诗','yuding','','[]','聖皇端拱，多士輸忠。蠻觴共獻，臣心畢同。',40,'御定全唐詩/json/016.json','["聖皇端拱，多士輸忠。蠻觴共獻，臣心畢同。", "聲齊嵩岳，祝比華封。千齡萬祀，常保時雍。"]'),
('yuding-65','郊廟歌辭：周朝饗樂章：康順','不詳','唐','御定全唐诗','yuding','','[]','鴻鈞廣運，嘉節良辰。列辟在位，萬國來賓。',40,'御定全唐詩/json/016.json','["鴻鈞廣運，嘉節良辰。列辟在位，萬國來賓。", "幹旌屢舞，金石咸陳。禮容既備，帝履長春。"]'),
('yuding-66','郊廟歌辭：周朝饗樂章：忠順','不詳','唐','御定全唐诗','yuding','','[]','禮成三爵，樂畢九成。共離金戺，複列彤庭。',20,'御定全唐詩/json/016.json','["禮成三爵，樂畢九成。共離金戺，複列彤庭。"]'),
('yuding-67','郊廟歌辭：周朝饗樂章：忠順','不詳','唐','御定全唐诗','yuding','','[]','明庭展禮，為龍為光。咸韶息韻，鵷鷺歸行。',20,'御定全唐詩/json/016.json','["明庭展禮，為龍為光。咸韶息韻，鵷鷺歸行。"]'),
('yuding-68','郊廟歌辭：晉昭德成功舞歌：昭德舞歌二首','不詳','唐','御定全唐诗','yuding','','[]','聖代修文德，明庭舉舊章。兩階陳羽鑰，萬舞合宮商。',96,'御定全唐詩/json/016.json','["聖代修文德，明庭舉舊章。兩階陳羽鑰，萬舞合宮商。", "劍佩森鴛鷺，簫韶下鳳凰。我朝青史上，千古有輝光。", "淮海干戈戢，朝廷禮樂施。白駒皆就縶，丹鳳複來儀。", "德備三苗格，風行萬國隨。小臣同百獸，率舞賀昌期。"]'),
('yuding-69','郊廟歌辭：晉昭德成功舞歌：武功舞歌二首','不詳','唐','御定全唐诗','yuding','','[]','撥亂資英主，開基自晉陽。一戎成大業，七德煥前王。',96,'御定全唐詩/json/016.json','["撥亂資英主，開基自晉陽。一戎成大業，七德煥前王。", "炎漢提封遠，姬周世祚長。朱幹將玉戚，全象武功揚。", "睿算超前古，神功格上圓。百川留禹跡，萬國戴堯天。", "既已櫜弓矢，誠宜播管弦。蹌蹌隨鳥獸，共樂太平年。"]'),
('yuding-0','樂府雜曲：鼓吹曲辭：朱鷺','張籍','唐','御定全唐诗','yuding','','[]','翩翩兮朱鷺，來泛春塘棲綠樹。',62,'御定全唐詩/json/017.json','["翩翩兮朱鷺，來泛春塘棲綠樹。", "羽毛如翦色如染，遠飛欲下雙翅斂。", "避人引子入深塹，動處水紋開灩灩。", "誰知豪家網爾軀，不如飲啄江海隅。"]'),
('yuding-1','樂府雜曲：鼓吹曲辭：艾如張','李賀','唐','御定全唐诗','yuding','','[]','錦襜褕，繡襠襦，強強飲啄哺爾雛。隴東臥穟滿風雨，',48,'御定全唐詩/json/017.json','["錦襜褕，繡襠襦，強強飲啄哺爾雛。隴東臥穟滿風雨，", "網絲漠漠無形影，誤爾觸之傷首紅。艾葉綠花誰翦刻，"]'),
('yuding-2','樂府雜曲：鼓吹曲辭：上之回','盧照鄰','唐','御定全唐诗','yuding','','[]','回中道路險，蕭關烽候多。五營屯北地，萬乘出西河。',48,'御定全唐詩/json/017.json','["回中道路險，蕭關烽候多。五營屯北地，萬乘出西河。", "單于拜玉璽，天子按雕戈。振旅汾川曲，秋風橫大歌。"]'),
('yuding-3','樂府雜曲：鼓吹曲辭：上之回','李白','唐','御定全唐诗','yuding','','[]','三十六離宮，樓臺與天通。閣道步行月，美人愁煙空。',96,'御定全唐詩/json/017.json','["三十六離宮，樓臺與天通。閣道步行月，美人愁煙空。", "恩疏寵不及，桃李傷春風。淫樂意何極，金輿向回中。", "萬乘出黃道，千旗揚彩虹。前軍細柳北，後騎甘泉東。", "豈問渭川老，寧邀襄野童。秋暮瑤池宴，歸來樂未窮。"]'),
('yuding-4','樂府雜曲：鼓吹曲辭：上之回','李賀','唐','御定全唐诗','yuding','','[]','上之回，大旗喜。懸虹彗，撻鳳尾。劍匣破，舞蛟龍。',48,'御定全唐詩/json/017.json','["上之回，大旗喜。懸虹彗，撻鳳尾。劍匣破，舞蛟龍。", "蚩尤死，鼓逢逢。天高慶雷齊墜地，地無驚煙海千里。"]'),
('yuding-5','樂府雜曲：鼓吹曲辭：戰城南','盧照鄰','唐','御定全唐诗','yuding','','[]','將軍出紫塞，冒頓在烏貪。笳喧雁門北，陣翼龍城南。',48,'御定全唐詩/json/017.json','["將軍出紫塞，冒頓在烏貪。笳喧雁門北，陣翼龍城南。", "雕弓夜宛轉，鐵騎曉參潭。應須駐白日，為待戰方酣。"]'),
('yuding-6','樂府雜曲：鼓吹曲辭：戰城南','李白','唐','御定全唐诗','yuding','','[]','去年戰桑幹源，今年戰蔥河道。洗兵條支海上波，',126,'御定全唐詩/json/017.json','["去年戰桑幹源，今年戰蔥河道。洗兵條支海上波，", "匈奴以殺戮為耕作，古來唯見白骨黃沙田。", "秦家築城備胡處，漢家還有烽火燃。", "烽火燃不息，征戰無已時。野戰格鬥死，敗馬號鳴向天悲。", "烏鳶啄人腸，銜飛上掛枯樹枝。士卒塗草莽，將軍空爾為。", "乃知兵者是凶器，聖人不得已而用之。"]'),
('yuding-7','樂府雜曲：鼓吹曲辭：戰城南','劉駕','唐','御定全唐诗','yuding','','[]','城南征戰多，城北無饑鴉。白骨馬蹄下，誰言皆有家。',48,'御定全唐詩/json/017.json','["城南征戰多，城北無饑鴉。白骨馬蹄下，誰言皆有家。", "城前水聲苦，倏忽流萬古。莫爭城外地，城裏有閑土。"]'),
('yuding-8','樂府雜曲：鼓吹曲辭：戰城南二首','貫休','唐','御定全唐诗','yuding','','[]','萬里桑幹傍，茫茫古蕃壤。將軍貌憔悴，撫劍悲年長。',108,'御定全唐詩/json/017.json','["萬里桑幹傍，茫茫古蕃壤。將軍貌憔悴，撫劍悲年長。", "胡兵尚陵逼，久住亦非強。邯鄲少年輩，個個有伎倆。", "拖槍半夜去，雪片大如掌。", "磧中有陰兵，戰馬時驚蹶。輕猛李陵心，摧殘蘇武節。", "黃金鎖子甲，風吹色如鐵。十載不封侯，茫茫向誰說。"]'),
('yuding-9','樂府雜曲：鼓吹曲辭：巫山高','鄭世翼','唐','御定全唐诗','yuding','','[]','巫山淩太清，岧嶢類削成。霏霏暮雨合，靄靄朝雲生。',48,'御定全唐詩/json/017.json','["巫山淩太清，岧嶢類削成。霏霏暮雨合，靄靄朝雲生。", "危峰入鳥道，深谷瀉猿聲。別有幽棲客，淹留攀桂情。"]'),
('yuding-10','樂府雜曲：鼓吹曲辭：巫山高二首','沈佺期','唐','御定全唐诗','yuding','','[]','巫山峰十二，環合隱昭回。俯眺琵琶峽，平看雲雨台。',96,'御定全唐詩/json/017.json','["巫山峰十二，環合隱昭回。俯眺琵琶峽，平看雲雨台。", "古槎天外倚，瀑水日邊來。何忽啼猿夜，荊王枕席開。", "神女向高唐，巫山下夕陽。裴回作行雨，婉孌逐荊王。", "電影江前落，雷聲峽外長。霽雲無處所，台館曉蒼蒼。"]'),
('yuding-11','樂府雜曲：鼓吹曲辭：巫山高','盧照鄰','唐','御定全唐诗','yuding','','[]','巫山望不極，望望下朝雰。莫辨啼猿樹，徒看神女雲。',48,'御定全唐詩/json/017.json','["巫山望不極，望望下朝雰。莫辨啼猿樹，徒看神女雲。", "驚濤亂水脈，驟雨暗峰文。沾裳即此地，況複遠思君。"]'),
('yuding-12','樂府雜曲：鼓吹曲辭：巫山高','張循之','唐','御定全唐诗','yuding','','[]','巫山高不極，遝遝狀奇新。暗穀疑風雨，幽岩若鬼神。',48,'御定全唐詩/json/017.json','["巫山高不極，遝遝狀奇新。暗穀疑風雨，幽岩若鬼神。", "月明三峽曙，潮滿二江春。為問陽臺夕，應知入夢人。"]'),
('yuding-13','樂府雜曲：鼓吹曲辭：巫山高','劉方平','唐','御定全唐诗','yuding','','[]','楚國巫山秀，清猿日夜啼。萬重春樹合，十二碧峰齊。',48,'御定全唐詩/json/017.json','["楚國巫山秀，清猿日夜啼。萬重春樹合，十二碧峰齊。", "峽出朝雲下，江來暮雨西。陽臺歸路直，不畏向家迷。"]'),
('yuding-14','樂府雜曲：鼓吹曲辭：巫山高','皇甫冉','唐','御定全唐诗','yuding','','[]','巫峽見巴東，迢迢半出空。雲藏神女館，雨到楚王宮。',48,'御定全唐詩/json/017.json','["巫峽見巴東，迢迢半出空。雲藏神女館，雨到楚王宮。", "朝暮泉聲落，寒暄樹色同。清猿不可聽，偏在九秋中。"]'),
('yuding-15','樂府雜曲：鼓吹曲辭：巫山高','李端','唐','御定全唐诗','yuding','','[]','巫山十二峰，皆在碧虛中。回合雲藏日，霏微雨帶風。',48,'御定全唐詩/json/017.json','["巫山十二峰，皆在碧虛中。回合雲藏日，霏微雨帶風。", "猿聲寒過水，樹色暮連空。愁向高唐望，清秋見楚宮。"]'),
('yuding-16','樂府雜曲：鼓吹曲辭：巫山高','于濆','唐','御定全唐诗','yuding','','[]','何山無朝雲，彼雲亦悠揚。何山無暮雨，彼雨亦蒼茫。',60,'御定全唐詩/json/017.json','["何山無朝雲，彼雲亦悠揚。何山無暮雨，彼雨亦蒼茫。", "宋玉恃才者，憑雲構高唐。自重文賦名，荒淫歸楚襄。", "峨峨十二峰，永作妖鬼鄉。"]'),
('yuding-17','樂府雜曲：鼓吹曲辭：巫山高二首','孟郊','唐','御定全唐诗','yuding','','[]','巴山上峽重複重，陽臺碧峭十二峰。荊王獵時逢暮雨，',88,'御定全唐詩/json/017.json','["巴山上峽重複重，陽臺碧峭十二峰。荊王獵時逢暮雨，", "目極魂斷望不見，猿啼三聲淚沾衣。", "見盡數萬里，不聞三聲猿。但飛蕭蕭雨，中有亭亭魂。", "千載楚襄恨，遺文宋玉言。至今青冥裏，雲結深閨門。"]'),
('yuding-18','樂府雜曲：鼓吹曲辭：巫山高','李賀','唐','御定全唐诗','yuding','','[]','碧叢叢，高插天，大江翻瀾神曳煙。楚魂尋夢風颸然，',40,'御定全唐詩/json/017.json','["碧叢叢，高插天，大江翻瀾神曳煙。楚魂尋夢風颸然，", "古祠近月蟾桂寒，椒花墜紅濕雲間。"]'),
('yuding-19','樂府雜曲：鼓吹曲辭：巫山高','齊己','唐','御定全唐诗','yuding','','[]','巫山高，巫女妖，雨為暮兮雲為朝，楚王憔悴魂欲銷。',64,'御定全唐詩/json/017.json','["巫山高，巫女妖，雨為暮兮雲為朝，楚王憔悴魂欲銷。", "秋猿嗥嗥日將夕，紅霞紫煙凝老壁。千岩萬壑花皆坼，", "雲深廟遠不可覓，十二峰頭插天碧。"]'),
('yuding-20','樂府雜曲：鼓吹曲辭：將進酒','李白','唐','御定全唐诗','yuding','','[]','君不見黃河之水天上來，奔流到海不復回。',132,'御定全唐詩/json/017.json','["君不見黃河之水天上來，奔流到海不復回。", "君不見高堂明鏡悲白髮，朝如青絲暮成雪。", "人生得意須盡歡，莫使金尊空對月。天生我材必有用，", "岑夫子，丹丘生，將進酒，杯莫停。與君歌一曲，", "古來聖賢皆寂寞，惟有飲者留其名。陳王昔時宴平樂，", "五花馬，千金裘，呼兒將出換美酒，與爾同銷萬古愁。"]'),
('yuding-21','樂府雜曲：鼓吹曲辭：將進酒','元稹','唐','御定全唐诗','yuding','','[]','將進酒，將進酒，酒中有毒鴆主父，言之主父傷主母。',92,'御定全唐詩/json/017.json','["將進酒，將進酒，酒中有毒鴆主父，言之主父傷主母。", "母為妾地父妾天，仰天俯地不忍言。佯為僵踣主父前，", "推摧主母牽下堂，扶妾遣升堂上床。將進酒，", "妾為此事人偶知，自慚不密方自悲。主今顛倒安置妾，"]'),
('yuding-22','樂府雜曲：鼓吹曲辭：將進酒','李賀','唐','御定全唐诗','yuding','','[]','琉璃鐘，琥珀濃，小槽酒滴真珠紅。烹龍炮鳳玉脂泣，',48,'御定全唐詩/json/017.json','["琉璃鐘，琥珀濃，小槽酒滴真珠紅。烹龍炮鳳玉脂泣，", "況是青春日將暮，桃花亂落如紅雨。勸君終日酩酊醉，"]'),
('yuding-23','樂府雜曲：鼓吹曲辭：君馬黃','李白','唐','御定全唐诗','yuding','','[]','君馬黃，我馬白，馬色雖不同，人心本無隔。',80,'御定全唐詩/json/017.json','["君馬黃，我馬白，馬色雖不同，人心本無隔。", "共作遊冶盤，雙行洛陽陌。長劍既照曜，高冠何赩赫。", "各有千金裘，俱為五侯客。猛虎落陷阱，壯夫時屈厄。", "相知在急難，獨好亦何益。"]'),
('yuding-24','樂府雜曲：鼓吹曲辭：芳樹','沈佺期','唐','御定全唐诗','yuding','','[]','何地早芳菲，宛在長門殿。夭桃色若綬，穠李光如練。',48,'御定全唐詩/json/017.json','["何地早芳菲，宛在長門殿。夭桃色若綬，穠李光如練。", "啼鳥弄花疏，遊蜂飲香遍。歎息春風起，飄零君不見。"]'),
('yuding-25','樂府雜曲：鼓吹曲辭：芳樹','盧照鄰','唐','御定全唐诗','yuding','','[]','芳樹本多奇，年華複在斯。結翠成新幄，開紅滿舊枝。',48,'御定全唐詩/json/017.json','["芳樹本多奇，年華複在斯。結翠成新幄，開紅滿舊枝。", "風歸花曆亂，日度影參差。容色朝朝落，思君君不知。"]'),
('yuding-26','樂府雜曲：鼓吹曲辭：芳樹','徐彥伯','唐','御定全唐诗','yuding','','[]','玉花珍簟上，金縷畫屏開。曉月憐箏柱，春風憶鏡臺。',48,'御定全唐詩/json/017.json','["玉花珍簟上，金縷畫屏開。曉月憐箏柱，春風憶鏡臺。", "箏柱春風吹曉月，芳樹落花朝暝歇。稿砧刀頭未有時，"]'),
('yuding-27','樂府雜曲：鼓吹曲辭：芳樹','韋應物','唐','御定全唐诗','yuding','','[]','迢迢芳園樹，列映清池曲。對此傷人心，還如故時綠。',48,'御定全唐詩/json/017.json','["迢迢芳園樹，列映清池曲。對此傷人心，還如故時綠。", "風條灑餘靄，露葉承新旭。佳人不再攀，下有往來躅。"]'),
('yuding-28','樂府雜曲：鼓吹曲辭：芳樹','元稹','唐','御定全唐诗','yuding','','[]','芳樹已寥落，孤英尤可嘉。可憐團團葉，蓋覆深深花。',96,'御定全唐詩/json/017.json','["芳樹已寥落，孤英尤可嘉。可憐團團葉，蓋覆深深花。", "遊蜂競攢刺，鬥雀亦紛拏。天生細碎物，不愛好光華。", "非無殲殄法，念爾有生涯。春雷一聲發，驚燕亦驚蛇。", "清池養神蔡，已複長蝦蟆。雨露貴平施，吾其春草芽。"]'),
('yuding-29','樂府雜曲：鼓吹曲辭：芳樹','羅隱','唐','御定全唐诗','yuding','','[]','細蕊慢逐風，暖香閑破鼻。青帝固有心，時時動人意。',109,'御定全唐詩/json/017.json','["細蕊慢逐風，暖香閑破鼻。青帝固有心，時時動人意。", "去年高枝猶壓地，今年低枝已憔悴。", "吾所以見造化之權，變通之理。春夏作頭，秋冬為尾。", "迴圈反復無窮已。今生長短同一軌，若使威可以制，", "伊人強猛猶如此，顧我勞生何足恃。但願開素袍，"]'),
('yuding-30','樂府雜曲：鼓吹曲辭：有所思','沈佺期','唐','御定全唐诗','yuding','','[]','君子事行役，再空芳歲期。美人曠延佇，萬里浮雲思。',48,'御定全唐詩/json/017.json','["君子事行役，再空芳歲期。美人曠延佇，萬里浮雲思。", "園槿綻紅豔，郊桑柔綠滋。坐看長夏晚，秋月生羅幃。"]'),
('yuding-31','樂府雜曲：鼓吹曲辭：有所思','李白','唐','御定全唐诗','yuding','','[]','我思仙人，乃在碧海之東隅。',35,'御定全唐詩/json/017.json','["我思仙人，乃在碧海之東隅。", "海寒多天風，白波連山倒蓬壺。長鯨噴湧不可涉，"]'),
('yuding-32','樂府雜曲：鼓吹曲辭：有所思','孟郊','唐','御定全唐诗','yuding','','[]','桔槔烽火晝不滅，客路迢迢信難越。古鎮刀攢萬片霜，',24,'御定全唐詩/json/017.json','["桔槔烽火晝不滅，客路迢迢信難越。古鎮刀攢萬片霜，"]'),
('yuding-33','樂府雜曲：鼓吹曲辭：有所思','盧仝','唐','御定全唐诗','yuding','','[]','當時我醉美人家，美人顏色嬌如花。今日美人棄我去，',72,'御定全唐詩/json/017.json','["當時我醉美人家，美人顏色嬌如花。今日美人棄我去，", "翠眉蟬鬢生別離，一望不見心斷絕。心斷絕，幾千里，", "美人兮美人，不知為暮雨兮為朝雲，相思一夜梅花發，"]'),
('yuding-34','樂府雜曲：鼓吹曲辭：有所思','韋應物','唐','御定全唐诗','yuding','','[]','借問江上柳，青青為誰春。空遊昨日地，不見昨日人。',48,'御定全唐詩/json/017.json','["借問江上柳，青青為誰春。空遊昨日地，不見昨日人。", "繚繞萬家井，往來車馬塵。莫道無相識，要非心所親。"]'),
('yuding-35','樂府雜曲：鼓吹曲辭：有所思','劉氏雲','唐','御定全唐诗','yuding','','[]','朝亦有所思，暮亦有所思。登樓望君處，藹藹浮雲飛。',48,'御定全唐詩/json/017.json','["朝亦有所思，暮亦有所思。登樓望君處，藹藹浮雲飛。", "浮雲遮卻陽關道，向晚誰知妾懷抱。玉井蒼苔春院深，"]'),
('yuding-36','樂府雜曲：鼓吹曲辭：雉子班','李白','唐','御定全唐诗','yuding','','[]','辟邪伎作鼓吹驚，雉子班之奏曲成，喔咿振迅欲飛鳴。',96,'御定全唐詩/json/017.json','["辟邪伎作鼓吹驚，雉子班之奏曲成，喔咿振迅欲飛鳴。", "扇錦翼，雄風生，雙雌同飲啄，趫悍誰能爭。", "乍向草中耿介死，不求黃金籠下生。", "天地至廣大，何惜遂物情。善卷讓天子，務光亦逃名。", "所貴曠士懷，朗然合太清。"]'),
('yuding-37','樂府雜曲：鼓吹曲辭：臨高臺','褚亮','唐','御定全唐诗','yuding','','[]','高臺暫俯臨，飛翼聳輕音。浮光隨日度，漾影逐波深。',48,'御定全唐詩/json/017.json','["高臺暫俯臨，飛翼聳輕音。浮光隨日度，漾影逐波深。", "迥瞰周平野，開懷暢遠襟。獨此三休上，還傷千歲心。"]'),
('yuding-38','樂府雜曲：鼓吹曲辭：臨高臺','王勃','唐','御定全唐诗','yuding','','[]','臨高臺，高臺迢遞絕浮埃，瑤軒綺構何崔嵬，',148,'御定全唐詩/json/017.json','["臨高臺，高臺迢遞絕浮埃，瑤軒綺構何崔嵬，", "東彌長樂觀，西指未央宮。赤城映朝日，綠樹搖春風。", "旗亭百隊開新市，甲第千甍分戚裏。朱輪翠蓋不勝春，", "錦衣晝不襞，羅幃夕未空。歌屏朝掩翠，妝鏡晚窺紅。", "為吾安寶髻，蛾眉罷花叢。狹路塵間黯將暮，", "物色正如此，佳期那不顧。銀鞍繡轂盛繁華，", "君看舊日高臺處，柏梁銅雀生黃塵。"]'),
('yuding-39','樂府雜曲：鼓吹曲辭：臨高臺','貫休','唐','御定全唐诗','yuding','','[]','涼風吹遠念，使我升高台。寧知數片雲，不是舊山來。',48,'御定全唐詩/json/017.json','["涼風吹遠念，使我升高台。寧知數片雲，不是舊山來。", "故人天一涯，久客殊未回。雁來不得書，空寄聲哀哀。"]'),
('yuding-40','樂府雜曲：鼓吹曲辭：黃雀行','莊南傑','唐','御定全唐诗','yuding','','[]','穿屋穿牆不知止，爭樹爭巢入營死。林間公子挾彈弓，',40,'御定全唐詩/json/017.json','["穿屋穿牆不知止，爭樹爭巢入營死。林間公子挾彈弓，", "虞人設網當要路，白日啾嘲禍萬機。"]'),
('yuding-41','樂府雜曲：鼓吹曲辭：釣竿篇','沈佺期','唐','御定全唐诗','yuding','','[]','朝日斂紅煙，垂竿向綠川。人疑天上坐，魚似鏡中懸。',72,'御定全唐詩/json/017.json','["朝日斂紅煙，垂竿向綠川。人疑天上坐，魚似鏡中懸。", "避楫時驚透，猜鉤每誤牽。湍危不理轄，潭靜欲留船。", "釣玉君徒尚，征金我未賢。為看芳餌下，貪得會無全。"]'),
('yuding-42','樂府雜曲：鼓吹曲辭：凱歌六首','岑參','唐','御定全唐诗','yuding','','[]','漢將承恩西破戎，捷書先奏未央宮。',192,'御定全唐詩/json/017.json','["漢將承恩西破戎，捷書先奏未央宮。", "天子預開麟閣待，只今誰數貳師功。", "官軍西出過樓蘭，營幕傍臨月窟寒。", "蒲海曉霜凝劍尾，蔥山夜雪撲旌竿。", "鳴笳擂鼓擁回軍，破國平蕃昔未聞。", "大夫鵲印搖邊月，天將龍旗掣海雲。", "月落轅門鼓角鳴，千群面縛出蕃城。", "洗兵魚海雲迎陣，秣馬龍堆月照營。", "蕃軍遙見漢家營，滿谷連山遍哭聲。", "萬箭千刀一夜殺，平明流血浸空城。", "暮雨旌旗濕未幹，胡塵白草日光寒。", "昨夜將軍連曉戰，蕃軍只見馬空鞍。"]'),
('yuding-43','樂府雜曲：鼓吹鐃歌：晉陽武','柳宗元','唐','御定全唐诗','yuding','','[]','晉陽武，奮義威。煬之渝，德焉歸。氓畢屠，綏者誰。',104,'御定全唐詩/json/017.json','["晉陽武，奮義威。煬之渝，德焉歸。氓畢屠，綏者誰。", "皇烈烈，專天機。號以仁，揚其旗。日之升，九土晞。", "斥田圻，流洪輝。有其二，翼餘隋。斫梟驁，連熊螭。", "枯以肉，勍者羸。後土蕩，玄穹彌。合之育，莽然施。", "惟德輔，慶無期。"]'),
('yuding-44','樂府雜曲：鼓吹鐃歌：獸之窮','柳宗元','唐','御定全唐诗','yuding','','[]','獸之窮，奔大麓。天厚黃德，狙獷服。',93,'御定全唐詩/json/017.json','["獸之窮，奔大麓。天厚黃德，狙獷服。", "甲之櫜弓，弭矢箙。皇旅靖，敵逾蹙。", "自亡其徒，匪予戮。屈rH猛，虔栗栗。", "縻以尺組，啖以秩。黎之陽，土茫茫。", "富兵戎，盈倉箱。乏者德，莫能享。驅豺兕，授我疆。"]'),
('yuding-45','樂府雜曲：鼓吹鐃歌：戰武牢','柳宗元','唐','御定全唐诗','yuding','','[]','戰武牢，動河朔。逆之助，圖掎角。怒鷇麛，抗喬嶽。',46,'御定全唐詩/json/017.json','["戰武牢，動河朔。逆之助，圖掎角。怒鷇麛，抗喬嶽。", "翹萌牙，傲霜雹。王謀內定，申掌握。鋪施芟夷，"]'),
('yuding-46','樂府雜曲：鼓吹鐃歌：涇水黃','柳宗元','唐','御定全唐诗','yuding','','[]','涇水黃，隴野茫。負太白，騰天狼。有鳥鷙立，羽翼張。',72,'御定全唐詩/json/017.json','["涇水黃，隴野茫。負太白，騰天狼。有鳥鷙立，羽翼張。", "鉤喙決前，鉅趯傍；怒飛饑嘯，翾不可當。老雄死，", "列缺掉幟，招搖耀鋩。鬼神來助，夢嘉祥。腦塗原野，"]'),
('yuding-47','樂府雜曲：鼓吹鐃歌：奔鯨沛','柳宗元','唐','御定全唐诗','yuding','','[]','奔鯨沛，蕩海垠。吐霓翳日，腥浮雲。帝怒下顧，',45,'御定全唐詩/json/017.json','["奔鯨沛，蕩海垠。吐霓翳日，腥浮雲。帝怒下顧，", "披攘蒙霿，開海門。地平水靜，浮天垠。羲和顯耀，"]'),
('yuding-48','樂府雜曲：鼓吹鐃歌：苞枿','柳宗元','唐','御定全唐诗','yuding','','[]','苞枿𪒶矣，惟根之蟠。彌巴蔽荊，負南極以安。',89,'御定全唐詩/json/017.json','["苞枿𪒶矣，惟根之蟠。彌巴蔽荊，負南極以安。", "曰我舊梁氏，輯綏艱難。江漢之阻，都邑固以完。", "聖人作，神武用，有臣勇智，奮不以眾。投跡死地，", "系縲降王，定厥功。澶漫萬里，宣唐風。蠻夷九譯，"]'),
('yuding-49','樂府雜曲：鼓吹鐃歌：河右平','柳宗元','唐','御定全唐诗','yuding','','[]','河右澶漫，頑為之魁。王師如雷震，昆侖以頹。',87,'御定全唐詩/json/017.json','["河右澶漫，頑為之魁。王師如雷震，昆侖以頹。", "上聾下聰，驁不可回。助仇抗有德，惟人之災。", "乃潰乃奮，執縛歸厥命。萬室蒙其仁，一夫則病。", "濡以鴻澤，皇之聖。威畏德懷，功以定。順之於理，"]'),
('yuding-50','樂府雜曲：鼓吹鐃歌：鐵山碎','柳宗元','唐','御定全唐诗','yuding','','[]','鐵山碎，大漠舒。二虜勁，連穹廬。背北海，專坤隅。',77,'御定全唐詩/json/017.json','["鐵山碎，大漠舒。二虜勁，連穹廬。背北海，專坤隅。", "歲來侵邊，或傅於都。天子命元帥，奮其雄圖。", "破定襄，降魁渠。窮竟窟宅，斥餘吾。百蠻破膽，", "官臣拜手，惟帝之謨。"]'),
('yuding-51','樂府雜曲：鼓吹鐃歌：靖本邦','柳宗元','唐','御定全唐诗','yuding','','[]','本邦伊晉，惟時不靖。根柢之搖，枝葉攸病。',70,'御定全唐詩/json/017.json','["本邦伊晉，惟時不靖。根柢之搖，枝葉攸病。", "守臣不任，勩於神聖。惟鉞之興，翦焉則定。", "洪惟我理，式和以敬。群頑既夷，庶績咸正。", "皇謨載大，惟人之慶。"]'),
('yuding-52','樂府雜曲：鼓吹鐃歌：吐谷渾','柳宗元','唐','御定全唐诗','yuding','','[]','吐谷渾盛強，背西海以誇。歲侵擾我疆，退匿險且遐。',156,'御定全唐詩/json/017.json','["吐谷渾盛強，背西海以誇。歲侵擾我疆，退匿險且遐。", "帝謂神武師，往征靖皇家。烈烈旆其旗，熊虎雜龍蛇。", "王旅千萬人，銜枚默無嘩。束刃逾山徼，張翼縱漠沙。", "一舉刈膻腥，屍骸積如麻。除惡務本根，況敢遺萌芽。", "洋洋西海水，威命窮天涯。系虜來王都，犒樂窮休嘉。", "登高望還師，竟野如春華。行者靡不歸，親戚讙要遮。", "凱旋獻清廟，萬國思無邪。"]'),
('yuding-53','樂府雜曲：鼓吹鐃歌：高昌','柳宗元','唐','御定全唐诗','yuding','','[]','麹氏雄西北，別絕臣外區。既恃遠且險，縱傲不我虞。',132,'御定全唐詩/json/017.json','["麹氏雄西北，別絕臣外區。既恃遠且險，縱傲不我虞。", "烈烈王者師，熊螭以為徒。龍旗翻海浪，馹騎馳坤隅。", "賁育搏嬰兒，一掃不復餘。平沙際天極，但見黃雲驅。", "臣靖執長纓，智勇伏囚拘。文皇南面坐，夷狄千群趨。", "咸稱天子神，往古不得俱。獻號天可汗，以覆我國都。", "兵戎不交害，各保性與軀。"]'),
('yuding-54','樂府雜曲：鼓吹鐃歌：東蠻','柳宗元','唐','御定全唐诗','yuding','','[]','東蠻有謝氏，冠帶理海中。已言我異世，雖聖莫能通。',132,'御定全唐詩/json/017.json','["東蠻有謝氏，冠帶理海中。已言我異世，雖聖莫能通。", "王卒如飛翰，鵬鶱駭群龍。轟然自天墜，乃信神武功。", "系虜君臣人，累累來自東。無思不服從，唐業如山崇。", "百辟拜稽首，咸願圖形容。如周王會書，永永傳無窮。", "睢盱萬狀乖，咿嗢九譯重。廣輪撫四海，浩浩知皇風。", "歌詩鐃鼓間，以壯我元戎。"]'),
('yuding-0','橫吹曲辭：隴頭','張籍','唐','御定全唐诗','yuding','','[]','隴頭已斷人不行，胡騎夜入涼州城。漢家處處格鬥死，',48,'御定全唐詩/json/018.json','["隴頭已斷人不行，胡騎夜入涼州城。漢家處處格鬥死，", "去年中國養子孫，今著氈裘學胡語。誰能更使李輕車，"]'),
('yuding-1','橫吹曲辭：隴頭吟','王維','唐','御定全唐诗','yuding','','[]','長安少年游俠客，夜上戍樓看太白。隴頭明月迥臨關，',48,'御定全唐詩/json/018.json','["長安少年游俠客，夜上戍樓看太白。隴頭明月迥臨關，", "身經大小百餘戰，麾下偏裨萬戶侯。蘇武才為典屬國，"]'),
('yuding-2','橫吹曲辭：隴頭吟','翁綬','唐','御定全唐诗','yuding','','[]','隴水潺湲隴樹黃，征人隴上盡思鄉。馬嘶斜日朔風急，',40,'御定全唐詩/json/018.json','["隴水潺湲隴樹黃，征人隴上盡思鄉。馬嘶斜日朔風急，", "橫行俱足封侯者，誰斬樓蘭獻未央。"]'),
('yuding-3','橫吹曲辭：隴頭水','楊師道','唐','御定全唐诗','yuding','','[]','隴頭秋月明，隴水帶關城。笳添離別曲，風送斷腸聲。',84,'御定全唐詩/json/018.json','["隴頭秋月明，隴水帶關城。笳添離別曲，風送斷腸聲。", "映雪峰猶暗，乘冰馬屢驚。霧中寒雁至，沙上轉蓬輕。", "天山傳羽檄，漢地急徵兵。陣開都護道，劍聚伏波營。", "于茲覺無度，方共濯胡纓。"]'),
('yuding-4','橫吹曲辭：隴頭水','盧照鄰','唐','御定全唐诗','yuding','','[]','隴阪高無極，征人一望鄉。關河別去水，沙塞斷歸腸。',48,'御定全唐詩/json/018.json','["隴阪高無極，征人一望鄉。關河別去水，沙塞斷歸腸。", "馬系千年樹，旌懸九月霜。從來共嗚咽，皆是為勤王。"]'),
('yuding-5','橫吹曲辭：隴頭水','王建','唐','御定全唐诗','yuding','','[]','隴水何年隴頭別，不在山中亦嗚咽。征人塞耳馬不行，',48,'御定全唐詩/json/018.json','["隴水何年隴頭別，不在山中亦嗚咽。征人塞耳馬不行，", "隴東隴西多屈曲，野麋飲水長簇簇。胡兵夜回水傍住，"]'),
('yuding-6','橫吹曲辭：隴頭水','於濆','唐','御定全唐诗','yuding','','[]','借問隴頭水，終年恨何事。深疑嗚咽聲，中有征人淚。',48,'御定全唐詩/json/018.json','["借問隴頭水，終年恨何事。深疑嗚咽聲，中有征人淚。", "昨日上山下，達曙不能寐。何處接長波，東流入清渭。"]'),
('yuding-7','橫吹曲辭：隴頭水','皎然','唐','御定全唐诗','yuding','','[]','隴頭心欲絕，隴水不堪聞。碎影搖槍壘，寒聲咽帳軍。',96,'御定全唐詩/json/018.json','["隴頭心欲絕，隴水不堪聞。碎影搖槍壘，寒聲咽帳軍。", "素從鹽海積，綠帶柳城分。日落天邊望，逶迤入塞雲。", "秦隴逼氐羌，征人去未央。如何幽咽水，並欲斷君腸。", "西注悲窮漠，東分憶故鄉。旅魂聲攪亂，無夢到遼陽。"]'),
('yuding-8','橫吹曲辭：隴頭水','鮑溶','唐','御定全唐诗','yuding','','[]','隴頭水，千古不堪聞。生歸蘇屬國，死別李將軍。',34,'御定全唐詩/json/018.json','["隴頭水，千古不堪聞。生歸蘇屬國，死別李將軍。", "細響風凋草，清哀雁落雲。"]'),
('yuding-9','橫吹曲辭：隴頭水','羅隱','唐','御定全唐诗','yuding','','[]','借問隴頭水，年年恨何事。全疑嗚咽聲，中有征人淚。',48,'御定全唐詩/json/018.json','["借問隴頭水，年年恨何事。全疑嗚咽聲，中有征人淚。", "自古無長策，況我非深智。何計謝潺湲，一宵空不寐。"]'),
('yuding-10','橫吹曲辭：出關','魏征','唐','御定全唐诗','yuding','','[]','中原還逐鹿，投筆事戎軒。縱橫計不就，慷慨志猶存。',120,'御定全唐詩/json/018.json','["中原還逐鹿，投筆事戎軒。縱橫計不就，慷慨志猶存。", "策杖謁天子，驅馬出關門。請纓羈南越，憑軾下東藩。", "郁紆陟高岫，出沒望平原。古木吟寒鳥，空山啼夜猿。", "既傷千里目，還驚九折魂。豈不憚艱險，深懷國士恩。", "季布無二諾，侯嬴重一言。人生感意氣，功名誰複論。"]'),
('yuding-11','橫吹曲辭：入關','賈馳','唐','御定全唐诗','yuding','','[]','河上微風來，關頭樹初濕。今朝關城吏，又見孤客入。',36,'御定全唐詩/json/018.json','["河上微風來，關頭樹初濕。今朝關城吏，又見孤客入。", "上國誰與期，西來徒自急。"]'),
('yuding-12','橫吹曲辭：入關','張祜','唐','御定全唐诗','yuding','','[]','都城連百二，雄險北回環。地勢遙尊嶽，河流側讓關。',48,'御定全唐詩/json/018.json','["都城連百二，雄險北回環。地勢遙尊嶽，河流側讓關。", "秦皇曾虎視，漢祖亦龍顏。何事梟凶輩，干戈自不閑。"]'),
('yuding-13','橫吹曲辭：出塞','竇威','唐','御定全唐诗','yuding','','[]','匈奴屢不平，漢將欲縱橫。看雲方結陣，卻月始連營。',48,'御定全唐詩/json/018.json','["匈奴屢不平，漢將欲縱橫。看雲方結陣，卻月始連營。", "潛軍渡馬邑，揚旆掩龍城。會勒燕然石，方傳車騎名。"]'),
('yuding-14','橫吹曲辭：出塞','陳子昂','唐','御定全唐诗','yuding','','[]','忽聞天上將，關塞重橫行。始返樓蘭國，還向朔方城。',72,'御定全唐詩/json/018.json','["忽聞天上將，關塞重橫行。始返樓蘭國，還向朔方城。", "黃金裝戰馬，白羽集神兵。星月開天陣，山川列地營。", "晚風吹畫角，春色耀飛旌。甯知班定遠，獨是一書生。"]'),
('yuding-15','橫吹曲辭：出塞','張易之','唐','御定全唐诗','yuding','','[]','俠客重恩光，驄馬飾金裝。瞥聞傳羽檄，馳突救邊荒。',84,'御定全唐詩/json/018.json','["俠客重恩光，驄馬飾金裝。瞥聞傳羽檄，馳突救邊荒。", "轉戰磨笄地，橫行戴鬥鄉。將軍占太白，小婦怨流黃。", "騕褭青絲騎，娉婷紅粉妝。一春鶯度曲，八月雁成行。", "誰堪坐秋思，羅袖拂空床。"]'),
('yuding-16','橫吹曲辭：出塞','沈佺期','唐','御定全唐诗','yuding','','[]','十年通大漠，萬里出長平。寒日生戈劍，陰雲搖旆旌。',48,'御定全唐詩/json/018.json','["十年通大漠，萬里出長平。寒日生戈劍，陰雲搖旆旌。", "饑烏啼舊壘，疲馬戀空城。辛苦皋蘭北，胡霜損漢兵。"]'),
('yuding-17','橫吹曲辭：出塞','王維','唐','御定全唐诗','yuding','','[]','居延城外獵天驕，白草連天野火燒。暮雲空磧時驅馬，',40,'御定全唐詩/json/018.json','["居延城外獵天驕，白草連天野火燒。暮雲空磧時驅馬，", "玉靶角弓珠勒馬，漢家將賜霍嫖姚。"]'),
('yuding-18','橫吹曲辭：出塞','王昌齡','唐','御定全唐诗','yuding','','[]','秦時明月漢時關，萬里長征人未還。',64,'御定全唐詩/json/018.json','["秦時明月漢時關，萬里長征人未還。", "但使龍城飛將在，不教胡馬度陰山。", "白花垣上望京師，黃河水流無盡時。", "窮秋曠野行人絕，馬首東來知是誰。"]'),
('yuding-19','橫吹曲辭：出塞','馬戴','唐','御定全唐诗','yuding','','[]','金帶連環束戰袍，馬頭沖雪度臨洮。',32,'御定全唐詩/json/018.json','["金帶連環束戰袍，馬頭沖雪度臨洮。", "卷旗夜劫單于帳，亂斫胡兵缺寶刀。"]'),
('yuding-20','橫吹曲辭：前出塞九首','杜甫','唐','御定全唐诗','yuding','','[]','戚戚去故里，悠悠赴交河。公家有程期，亡命嬰禍羅。',432,'御定全唐詩/json/018.json','["戚戚去故里，悠悠赴交河。公家有程期，亡命嬰禍羅。", "君已富土境，開邊一何多。棄絕父母恩，吞聲行負戈。", "出門日已遠，不受徒旅欺。骨肉恩豈斷，男兒死無時。", "走馬脫轡頭，手中挑青絲。捷下萬仞岡，俯身試搴旗。", "磨刀嗚咽水，水赤刃傷手。欲輕腸斷聲，心緒亂已久。", "丈夫誓許國，憤惋複何有。功名圖麒麟，戰骨當速朽。", "送徒既有長，遠戍亦有身。生死向前去，不勞吏怒嗔。", "路逢相識人，附書與六親。哀哉兩決絕，不復同苦辛。", "迢迢萬餘裏，領我赴三軍。軍中異苦樂，主將甯盡聞。", "隔河見胡騎，倏忽數百群。我始為奴僕，幾時樹功勳。", "挽弓當挽強，用箭當用長。射人先射馬，擒賊先擒王。", "殺人亦有限，列國自有疆。苟能制侵陵，豈在多殺傷。", "驅馬天雨雪，軍行入高山。徑危抱寒石，指落曾冰間。", "已去漢月遠，何時築城還。浮雲暮南征，可望不可攀。", "單于寇我壘，百里風塵昏。雄劍四五動，彼軍為我奔。", "虜其名王歸，系頸授轅門。潛身備行列，一勝何足論。", "從軍十年餘，能無分寸功。眾人貴苟得，欲語羞雷同。", "中原有鬥爭，況在狄與戎。丈夫四方志，安可辭固窮。"]'),
('yuding-21','橫吹曲辭：後出塞五首','杜甫','唐','御定全唐诗','yuding','','[]','男兒生世間，及壯當封侯。戰伐有功業，焉能守舊丘。',372,'御定全唐詩/json/018.json','["男兒生世間，及壯當封侯。戰伐有功業，焉能守舊丘。", "召募赴薊門，軍動不可留。千金買馬鞭，百金裝刀頭。", "閭裏送我行，親戚擁道周。斑白居上列，酒酣進庶羞。", "少年別有贈，含笑看吳鉤。", "朝進東門營，暮上河陽橋。落日照大旗，馬鳴風蕭蕭。", "平沙列萬幕，部伍各見招。中天懸明月，令嚴夜寂寥。", "悲笳數聲動，壯士慘不驕。借問大將誰，恐是霍嫖姚。", "古人重守邊，今人重高勳。豈知英雄主，出師亙長雲。", "六合已一家，四夷且孤軍。遂使貔虎士，奮身勇所聞。", "拔劍擊大荒，日牧胡馬群。誓開玄冥北，持以奉吾君。", "獻凱日繼踵，兩蕃靜無虞。漁陽豪俠地，擊鼓吹笙竽。", "雲帆轉遼海，粳稻來東吳。越羅與楚練，照耀輿台軀。", "主將位益崇，氣驕陵上都。邊人不敢議，議者死路衢。", "我本良家子，出師亦多門。將驕益愁思，身貴不足論。", "躍馬二十年，恐辜明主恩。坐見幽州騎，長驅河洛昏。", "中夜間道歸，故里但空村。惡名幸脫免，窮老無兒孫。"]'),
('yuding-22','橫吹曲辭：出塞','皇甫冉','唐','御定全唐诗','yuding','','[]','吹角出塞門，前瞻即胡地。三軍盡回首，皆灑望鄉淚。',48,'御定全唐詩/json/018.json','["吹角出塞門，前瞻即胡地。三軍盡回首，皆灑望鄉淚。", "轉念關山長，行看風景異。由來征戍客，各負輕生義。"]'),
('yuding-23','橫吹曲辭：出塞','王之渙','唐','御定全唐诗','yuding','','[]','黃砂直上白雲間，一片孤城萬仞山。',32,'御定全唐詩/json/018.json','["黃砂直上白雲間，一片孤城萬仞山。", "羌笛何須怨楊柳，春光不度玉門關。"]'),
('yuding-24','橫吹曲辭：出塞','耿湋','唐','御定全唐诗','yuding','','[]','漢家邊事重，竇憲出臨戎。絕漠秋山在，陽關舊路通。',48,'御定全唐詩/json/018.json','["漢家邊事重，竇憲出臨戎。絕漠秋山在，陽關舊路通。", "列營依茂草，吹角向高風。更就燕然石，看銘破虜功。"]'),
('yuding-25','橫吹曲辭：出塞','張籍','唐','御定全唐诗','yuding','','[]','秋塞雪初下，將軍遠出師。分營長記火，放馬不收旗。',48,'御定全唐詩/json/018.json','["秋塞雪初下，將軍遠出師。分營長記火，放馬不收旗。", "月冷邊帳濕，沙昏夜探遲。征人皆白首，誰見滅胡時。"]'),
('yuding-26','橫吹曲辭：出塞','劉駕','唐','御定全唐诗','yuding','','[]','胡風不開花，四氣多作雪。北人尚凍死，況我本南越。',72,'御定全唐詩/json/018.json','["胡風不開花，四氣多作雪。北人尚凍死，況我本南越。", "古來犬羊地，巡狩無遺轍。九土耕不盡，武皇猶征伐。", "中天有高閣，圖畫何時歇。坐恐塞上山，低於砂中骨。"]'),
('yuding-27','橫吹曲辭：出塞曲','劉濟','唐','御定全唐诗','yuding','','[]','將軍在重圍，音信絕不通。羽書如流星，飛入甘泉宮。',96,'御定全唐詩/json/018.json','["將軍在重圍，音信絕不通。羽書如流星，飛入甘泉宮。", "倚是並州兒，少年心膽雄。一朝隨召募，百戰爭王公。", "去年桑幹北，今年桑幹東。死是征人死，功是將軍功。", "汗馬牧秋月，疲兵臥霜風。仍聞左賢王，更欲圖雲中。"]'),
('yuding-28','橫吹曲辭：出塞曲','於鵠','唐','御定全唐诗','yuding','','[]','微雪將軍出，吹笳天未明。觀兵登古戍，斬將對雙旌。',96,'御定全唐詩/json/018.json','["微雪將軍出，吹笳天未明。觀兵登古戍，斬將對雙旌。", "分陣瞻山勢，潛軍制馬鳴。如今新史上，已有滅胡名。", "單于驕愛獵，放火到軍城。待月調新弩，防秋置遠營。", "空山朱戟影，寒磧鐵衣聲。逢著降胡說，陰山有伏兵。"]'),
('yuding-29','橫吹曲辭：出塞曲','貫休','唐','御定全唐诗','yuding','','[]','掃盡狂胡跡，回戈望故關。相逢唯死鬥，豈易得生還。',144,'御定全唐詩/json/018.json','["掃盡狂胡跡，回戈望故關。相逢唯死鬥，豈易得生還。", "縱宴參胡樂，收兵過雪山。不封十萬戶，此事亦應閑。", "玉帳將軍意，殷勤把酒論。功高寧在我，陣沒與招魂。", "塞色干戈束，軍容喜氣屯。男兒今始是，敢出玉關門。", "回首隴山頭，連天草木秋。聖君應入夢，半路遣封侯。", "水不擔陰雪，柴令倒戍樓。歸來麟閣上，春色滿皇州。"]'),
('yuding-30','橫吹曲辭：入塞','劉希夷','唐','御定全唐诗','yuding','','[]','將軍陷虜圍，邊務息戎機。霜雪交河盡，旌旗入塞飛。',48,'御定全唐詩/json/018.json','["將軍陷虜圍，邊務息戎機。霜雪交河盡，旌旗入塞飛。", "曉光隨馬度，春色伴人歸。課績朝明主，臨軒拜武威。"]'),
('yuding-31','橫吹曲辭：入塞曲','耿湋','唐','御定全唐诗','yuding','','[]','將軍帶十圍，重錦制戎衣。猿臂銷弓力，虯須長劍威。',72,'御定全唐詩/json/018.json','["將軍帶十圍，重錦制戎衣。猿臂銷弓力，虯須長劍威。", "首登平樂宴，新破大宛歸。樓上姝姬笑，門前問客稀。", "暮烽玄菟急，秋草紫騮肥。未奉君王詔，高槐晝掩扉。"]'),
('yuding-32','橫吹曲辭：入塞曲','貫休','唐','御定全唐诗','yuding','','[]','單于烽火動，都護去天涯。別賜黃金甲，親臨白玉墀。',144,'御定全唐詩/json/018.json','["單于烽火動，都護去天涯。別賜黃金甲，親臨白玉墀。", "塞垣須靜謐，師旅審安危。定遠條支寵，如今勝古時。", "方見將軍貴，分明對冕旒。聖恩如遠被，狂虜不難收。", "臣節唯期死，功勳敢望侯。終辭修裏第，從此出皇州。", "百里精兵動，參差便渡遼。如何好白日，亦照此天驕。", "遠樹深疑賊，驚蓬迥似雕。凱歌何日唱，磧路共天遙。"]'),
('yuding-33','橫吹曲辭：入塞曲','沈彬','唐','御定全唐诗','yuding','','[]','欲為皇王服遠戎，萬人金甲鼓鼙中。陣雲暗塞三邊黑，',80,'御定全唐詩/json/018.json','["欲為皇王服遠戎，萬人金甲鼓鼙中。陣雲暗塞三邊黑，", "謗書未及明君爇，臥骨將軍已歿功。", "苦戰沙間臥箭痕，戍樓閑上望星文。生希國澤分偏將，", "功多地遠無人紀，漢閣笙歌日又曛。"]'),
('yuding-34','橫吹曲辭：折楊柳','盧照鄰','唐','御定全唐诗','yuding','','[]','倡樓啟曙扉，園柳正依依。鳥鳴知歲隔，條變識春歸。',48,'御定全唐詩/json/018.json','["倡樓啟曙扉，園柳正依依。鳥鳴知歲隔，條變識春歸。", "露葉疑啼臉，風花亂舞衣。攀折聊將寄，軍中書信稀。"]'),
('yuding-35','橫吹曲辭：折楊柳','沈佺期','唐','御定全唐诗','yuding','','[]','玉窗朝日映，羅帳春風吹。拭淚攀楊柳，長條宛地垂。',48,'御定全唐詩/json/018.json','["玉窗朝日映，羅帳春風吹。拭淚攀楊柳，長條宛地垂。", "白花飛曆亂，黃鳥思參差。妾自肝腸斷，旁人那得知。"]'),
('yuding-36','橫吹曲辭：折楊柳','喬知之','唐','御定全唐诗','yuding','','[]','可憐濯濯春楊柳，攀折將來就纖手。',32,'御定全唐詩/json/018.json','["可憐濯濯春楊柳，攀折將來就纖手。", "妾容與此同盛衰，何必君恩獨能久。"]'),
('yuding-37','橫吹曲辭：折楊柳','劉憲','唐','御定全唐诗','yuding','','[]','沙塞三河道，金閨二月春。碧煙楊柳色，紅粉綺羅人。',48,'御定全唐詩/json/018.json','["沙塞三河道，金閨二月春。碧煙楊柳色，紅粉綺羅人。", "露葉憐啼臉，風花思舞巾。攀持君不見，為聽曲中新。"]'),
('yuding-38','橫吹曲辭：折楊柳','崔湜','唐','御定全唐诗','yuding','','[]','二月風光半，三邊戍不還。年華妾自惜，楊柳為君攀。',48,'御定全唐詩/json/018.json','["二月風光半，三邊戍不還。年華妾自惜，楊柳為君攀。", "落絮緣衫袖，垂條拂髻鬟。那堪音信斷，流涕望陽關。"]'),
('yuding-39','橫吹曲辭：折楊柳','韋承慶','唐','御定全唐诗','yuding','','[]','萬里邊城地，三春楊柳節。葉似鏡中眉，花如關外雪。',48,'御定全唐詩/json/018.json','["萬里邊城地，三春楊柳節。葉似鏡中眉，花如關外雪。", "征人遠鄉思，倡婦高樓別。不忍擲年華，含情寄攀折。"]'),
('yuding-40','橫吹曲辭：折楊柳','歐陽瑾','唐','御定全唐诗','yuding','','[]','垂柳拂妝台，葳蕤葉半開。年華枝上見，邊思曲中來。',48,'御定全唐詩/json/018.json','["垂柳拂妝台，葳蕤葉半開。年華枝上見，邊思曲中來。", "嫩色宜新雨，輕花伴落梅。朝朝倦攀折，征戍幾時回。"]'),
('yuding-41','橫吹曲辭：折楊柳','張祜','唐','御定全唐诗','yuding','','[]','紅粉青樓曙，垂楊仲月春。懷君重攀折，非妾妒腰身。',48,'御定全唐詩/json/018.json','["紅粉青樓曙，垂楊仲月春。懷君重攀折，非妾妒腰身。", "舞帶縈絲斷，嬌娥向葉嚬。橫吹凡幾曲，獨自最愁人。"]'),
('yuding-42','橫吹曲辭：折楊柳','張九齡','唐','御定全唐诗','yuding','','[]','纖纖折楊柳，持此寄情人。一枝何足貴，憐是故園春。',48,'御定全唐詩/json/018.json','["纖纖折楊柳，持此寄情人。一枝何足貴，憐是故園春。", "遲景那能久，流芳不及新。更愁征戍客，鬢老邊城塵。"]'),
('yuding-43','橫吹曲辭：折楊柳','余延壽','唐','御定全唐诗','yuding','','[]','大道連國門，東西種楊柳。葳蕤君不見，嫋娜垂來久。',96,'御定全唐詩/json/018.json','["大道連國門，東西種楊柳。葳蕤君不見，嫋娜垂來久。", "緣枝棲暝禽，雄去雌獨吟。餘花怨春盡，微月起秋陰。", "坐望窗中蝶，起攀枝上葉。好風吹長條，婀娜何如妾。", "妾見柳園新，高樓四五春。莫吹胡塞曲，愁殺隴頭人。"]'),
('yuding-44','橫吹曲辭：折楊柳','李白','唐','御定全唐诗','yuding','','[]','垂楊拂綠水，搖豔東風年。花明玉關雪，葉暖金窗煙。',48,'御定全唐詩/json/018.json','["垂楊拂綠水，搖豔東風年。花明玉關雪，葉暖金窗煙。", "美人結長恨，想對心淒然。攀條折春色，遠寄龍庭前。"]'),
('yuding-45','橫吹曲辭：折楊柳','孟郊','唐','御定全唐诗','yuding','','[]','楊柳多短枝，短枝多別離。贈遠累攀折，柔條安得垂。',120,'御定全唐詩/json/018.json','["楊柳多短枝，短枝多別離。贈遠累攀折，柔條安得垂。", "青春有定節，離別無定時。但恐人別促，不怨來遲遲。", "莫言短枝條，中有長相思。朱顏與綠楊，並在別離期。", "樓上春風過，風前楊柳歌。枝疏緣別苦，曲怨為年多。", "花驚燕地雪，葉映楚池波。誰堪別離此，征戍在交河。"]'),
('yuding-46','橫吹曲辭：折楊柳','李端','唐','御定全唐诗','yuding','','[]','東城攀柳葉，柳葉低著草。少壯莫輕年，輕年有人老。',120,'御定全唐詩/json/018.json','["東城攀柳葉，柳葉低著草。少壯莫輕年，輕年有人老。", "柳發遍川崗，登高堪斷腸。雨煙輕漠漠，何樹近君鄉。", "贈君折楊柳，顏色豈能久。上客莫沾巾，佳人正回首。", "新柳送君行，古柳傷君情。突兀臨荒渡，婆娑出舊營。", "隋家兩岸盡，陶宅五株平。日暮偏愁望，春山有鳥聲。"]'),
('yuding-47','橫吹曲辭：折楊柳','翁綬','唐','御定全唐诗','yuding','','[]','紫陌金堤映綺羅，遊人處處動離歌。陰移古戍迷荒草，',40,'御定全唐詩/json/018.json','["紫陌金堤映綺羅，遊人處處動離歌。陰移古戍迷荒草，", "殷勤攀折贈行客，此去關山雨雪多。"]'),
('yuding-48','橫吹曲辭：望行人','王建','唐','御定全唐诗','yuding','','[]','自從江樹秋，日日上江樓。夢見離珠浦，書來在桂州。',48,'御定全唐詩/json/018.json','["自從江樹秋，日日上江樓。夢見離珠浦，書來在桂州。", "不同魚比目，終恨水分流。久不開明鏡，多應是白頭。"]'),
('yuding-49','橫吹曲辭：望行人','張籍','唐','御定全唐诗','yuding','','[]','秋風窗下起，旅雁向南飛。日日出門望，家家行客歸。',48,'御定全唐詩/json/018.json','["秋風窗下起，旅雁向南飛。日日出門望，家家行客歸。", "無因見邊使，空待寄寒衣。獨閉青樓暮，煙深鳥雀稀。"]'),
('yuding-50','橫吹曲辭：關山月','盧照鄰','唐','御定全唐诗','yuding','','[]','塞垣通碣石，虜障抵祁連。相思在萬里，明月正孤懸。',48,'御定全唐詩/json/018.json','["塞垣通碣石，虜障抵祁連。相思在萬里，明月正孤懸。", "影移金岫北，光斷玉門前。寄書謝中婦，時看鴻雁天。"]'),
('yuding-51','橫吹曲辭：關山月','沈佺期','唐','御定全唐诗','yuding','','[]','漢月生遼海，曈曨出半暉。合昏玄兔郡，中夜白登圍。',48,'御定全唐詩/json/018.json','["漢月生遼海，曈曨出半暉。合昏玄兔郡，中夜白登圍。", "暈落關山迥，光含霜霰微。將軍聽曉角，戰馬欲南歸。"]'),
('yuding-52','橫吹曲辭：關山月','李白','唐','御定全唐诗','yuding','','[]','明月出天山，蒼茫雲海間。長風幾萬里，吹度玉門關。',72,'御定全唐詩/json/018.json','["明月出天山，蒼茫雲海間。長風幾萬里，吹度玉門關。", "漢下白登道，胡窺青海灣。由來征戰地，不見有人還。", "戍客望邊色，思歸多苦顏。高樓當此夜，歎息未應閑。"]'),
('yuding-53','橫吹曲辭：關山月','長孫佐輔','唐','御定全唐诗','yuding','','[]','淒淒還切切，戍客多離別。何處最傷心，關山見秋月。',144,'御定全唐詩/json/018.json','["淒淒還切切，戍客多離別。何處最傷心，關山見秋月。", "關月竟如何，由來遠近過。始經玄兔塞，終繞白狼河。", "忽憶秦樓婦，流光應共有。已得並蛾眉，還知攬纖手。", "去歲照同行，比翼複連形。今宵照獨立，顧影自煢煢。", "餘暉漸西落，夜夜看如昨。借問映旌旗，何如鑒帷幕。", "拂曉朔風悲，蓬驚雁不飛。幾時征戍罷，還向月中歸。"]'),
('yuding-54','橫吹曲辭：關山月','耿湋','唐','御定全唐诗','yuding','','[]','月明邊徼靜，戍客望鄉時。塞古柳衰盡，關寒榆發遲。',48,'御定全唐詩/json/018.json','["月明邊徼靜，戍客望鄉時。塞古柳衰盡，關寒榆發遲。", "蒼蒼萬里道，戚戚十年悲。今夜青樓上，還應照所思。"]'),
('yuding-55','橫吹曲辭：關山月二首','戴叔倫','唐','御定全唐诗','yuding','','[]','月出照關山，秋風人未還。清光無遠近，鄉淚半書間。',48,'御定全唐詩/json/018.json','["月出照關山，秋風人未還。清光無遠近，鄉淚半書間。", "一雁過連營，繁霜覆古城。胡笳在何處，半夜起邊聲。"]'),
('yuding-56','橫吹曲辭：關山月','崔融','唐','御定全唐诗','yuding','','[]','月生西海上，氣逐邊風壯。萬里度關山，蒼茫非一狀。',48,'御定全唐詩/json/018.json','["月生西海上，氣逐邊風壯。萬里度關山，蒼茫非一狀。", "漢兵開郡國，胡馬窺亭障。夜夜聞悲笳，征人起南望。"]'),
('yuding-57','橫吹曲辭：關山月','李端','唐','御定全唐诗','yuding','','[]','露濕月蒼蒼，關頭榆葉黃。回輪照海遠，分彩上樓長。',48,'御定全唐詩/json/018.json','["露濕月蒼蒼，關頭榆葉黃。回輪照海遠，分彩上樓長。", "水凍頻移幕，兵疲數望鄉。只應城影外，萬里共如霜。"]'),
('yuding-58','橫吹曲辭：關山月','王建','唐','御定全唐诗','yuding','','[]','關山月，營開道白前軍發。凍輪當磧光悠悠，',20,'御定全唐詩/json/018.json','["關山月，營開道白前軍發。凍輪當磧光悠悠，"]'),
('yuding-59','橫吹曲辭：關山月','張籍','唐','御定全唐诗','yuding','','[]','秋月朗朗關山上，山中行人馬蹄響。關山秋來雨雪多，',64,'御定全唐詩/json/018.json','["秋月朗朗關山上，山中行人馬蹄響。關山秋來雨雪多，", "軍中探騎暮出城，伏兵暗處低旌戟。溪水連地霜草平，", "可憐萬國關山道，年年戰骨多秋草。"]'),
('yuding-60','橫吹曲辭：關山月','翁綬','唐','御定全唐诗','yuding','','[]','裴回漢月滿邊州，照盡天涯到隴頭。影轉銀河寰海靜，',40,'御定全唐詩/json/018.json','["裴回漢月滿邊州，照盡天涯到隴頭。影轉銀河寰海靜，", "況是故園搖落夜，那堪少婦獨登樓。"]'),
('yuding-61','橫吹曲辭：關山月','鮑氏君徽','唐','御定全唐诗','yuding','','[]','高高秋月明，北照遼陽城。塞迥光初滿，風多暈更生。',72,'御定全唐詩/json/018.json','["高高秋月明，北照遼陽城。塞迥光初滿，風多暈更生。", "征人望鄉思，戰馬聞鞞驚。朔風悲邊草，胡沙昏虜營。", "霜疑匣中劍，風憊原上旌。早晚謁金闕，不聞刁鬥聲。"]'),
('yuding-62','橫吹曲辭：洛陽道','于武陵','唐','御定全唐诗','yuding','','[]','浮世若浮雲，千回故複新。旋添青草塚，更有白頭人。',48,'御定全唐詩/json/018.json','["浮世若浮雲，千回故複新。旋添青草塚，更有白頭人。", "歲暮客將老，雪晴山欲春。行行車與馬，不盡洛陽塵。"]'),
('yuding-63','橫吹曲辭：洛陽道','鄭渥','唐','御定全唐诗','yuding','','[]','客亭門外路東西，多少喧騰事不齊。楊柳惹鞭公子醉，',40,'御定全唐詩/json/018.json','["客亭門外路東西，多少喧騰事不齊。楊柳惹鞭公子醉，", "頃刻知音幾存歿，半回依約認輪蹄。"]'),
('yuding-64','橫吹曲辭：洛陽陌','李白','唐','御定全唐诗','yuding','','[]','白玉誰家郎，回車渡天津。看花東上陌，驚動洛陽人。',24,'御定全唐詩/json/018.json','["白玉誰家郎，回車渡天津。看花東上陌，驚動洛陽人。"]'),
('yuding-65','橫吹曲辭：長安道','崔顥','唐','御定全唐诗','yuding','','[]','長安甲第高入雲，誰家居住霍將軍。日晚朝回擁賓從，',48,'御定全唐詩/json/018.json','["長安甲第高入雲，誰家居住霍將軍。日晚朝回擁賓從，", "莫言貧賤即可欺，人生富貴自有時。一朝天子賜顏色，"]'),
('yuding-66','橫吹曲辭：長安道','孟郊','唐','御定全唐诗','yuding','','[]','胡風激秦樹，賤子風中泣。家家朱門開，得見不可入。',48,'御定全唐詩/json/018.json','["胡風激秦樹，賤子風中泣。家家朱門開，得見不可入。", "長安十二衢，投樹鳥亦急。高閣何人家，笙簧正喧吸。"]'),
('yuding-67','橫吹曲辭：長安道','顧況','唐','御定全唐诗','yuding','','[]','長安道，人無衣，馬無草，何不歸來山中老。',20,'御定全唐詩/json/018.json','["長安道，人無衣，馬無草，何不歸來山中老。"]'),
('yuding-68','橫吹曲辭：長安道','聶夷中','唐','御定全唐诗','yuding','','[]','此地無駐馬，夜中猶走輪。所以路旁草，少於衣上塵。',24,'御定全唐詩/json/018.json','["此地無駐馬，夜中猶走輪。所以路旁草，少於衣上塵。"]'),
('yuding-69','橫吹曲辭：長安道','韋應物','唐','御定全唐诗','yuding','','[]','漢家宮殿含雲煙，兩宮十裏相連延。晨霞出沒弄丹闕，',146,'御定全唐詩/json/018.json','["漢家宮殿含雲煙，兩宮十裏相連延。晨霞出沒弄丹闕，", "寶馬橫來下建章，香車卻轉避馳道。", "貴遊誰最貴，衛霍世難比。何能蒙主恩，幸遇邊塵起。", "歸來甲第拱皇居。朱門峨峨臨九衢，", "下有錦鋪翠被之粲爛，博山吐香五雲散。", "麗人綺閣情飄颻，頭上鴛釵雙翠翹，低鬟曳袖回春雪，", "既請列侯封部曲，還將金印授廬兒。歡榮若此何所苦，"]'),
('yuding-70','橫吹曲辭：長安道','白居易','唐','御定全唐诗','yuding','','[]','花枝缺處青樓開，豔歌一曲酒一杯。美人勸我急行樂，',24,'御定全唐詩/json/018.json','["花枝缺處青樓開，豔歌一曲酒一杯。美人勸我急行樂，"]'),
('yuding-71','橫吹曲辭：長安道','薛能','唐','御定全唐诗','yuding','','[]','汲汲複營營，東西連兩京。關繻古若在，山嶽累應成。',72,'御定全唐詩/json/018.json','["汲汲複營營，東西連兩京。關繻古若在，山嶽累應成。", "各自有身事，不相知姓名。交馳喧眾類，分散入重城。", "此路去無盡，萬方人始生。空餘片言苦，來往覓劉楨。"]'),
('yuding-72','橫吹曲辭：長安道','貫休','唐','御定全唐诗','yuding','','[]','憧憧合合，八表一轍。黃塵霧合，車馬火熱。名湯風雨，',61,'御定全唐詩/json/018.json','["憧憧合合，八表一轍。黃塵霧合，車馬火熱。名湯風雨，", "紫氣銀輪兮常覆金闕，仙掌捧日兮濁河澄澈。", "愚將草木兮有言，與華封人兮不別。"]'),
('yuding-73','橫吹曲辭：長安道','沈佺期','唐','御定全唐诗','yuding','','[]','秦地平如掌，層城出雲漢。樓閣九衢春，車馬千門旦。',48,'御定全唐詩/json/018.json','["秦地平如掌，層城出雲漢。樓閣九衢春，車馬千門旦。", "綠柳開複合，紅塵聚還散。日晚鬥雞回，經過狹斜看。"]'),
('yuding-74','橫吹曲辭：梅花落','盧照鄰','唐','御定全唐诗','yuding','','[]','梅嶺花初發，天山雪未開。雪處疑花滿，花邊似雪回。',48,'御定全唐詩/json/018.json','["梅嶺花初發，天山雪未開。雪處疑花滿，花邊似雪回。", "因風入舞袖，雜粉向妝台。匈奴幾萬里，春至不知來。"]'),
('yuding-75','橫吹曲辭：梅花落','沈佺期','唐','御定全唐诗','yuding','','[]','鐵騎幾時回，金閨怨早梅。雪中花已落，風暖葉應開。',48,'御定全唐詩/json/018.json','["鐵騎幾時回，金閨怨早梅。雪中花已落，風暖葉應開。", "夕逐新春管，香迎小歲杯。感時何足貴，書裏報輪台。"]'),
('yuding-76','橫吹曲辭：梅花落','劉方平','唐','御定全唐诗','yuding','','[]','新歲芳梅樹，繁苞四面同。春風吹漸落，一夜幾枝空。',48,'御定全唐詩/json/018.json','["新歲芳梅樹，繁苞四面同。春風吹漸落，一夜幾枝空。", "小婦今如此，長城恨不窮。莫將遼海雪，來比後庭中。"]'),
('yuding-77','橫吹曲辭：紫騮馬','盧照鄰','唐','御定全唐诗','yuding','','[]','騮馬照金鞍，轉戰入皋蘭。塞門風稍急，長城水正寒。',48,'御定全唐詩/json/018.json','["騮馬照金鞍，轉戰入皋蘭。塞門風稍急，長城水正寒。", "雪暗鳴珂重，山長噴玉難。不辭橫絕漠，流血幾時幹。"]'),
('yuding-78','橫吹曲辭：紫騮馬','李白','唐','御定全唐诗','yuding','','[]','紫騮行且嘶，雙翻碧玉蹄。臨流不肯渡，似惜錦障泥。',48,'御定全唐詩/json/018.json','["紫騮行且嘶，雙翻碧玉蹄。臨流不肯渡，似惜錦障泥。", "白雪關山遠，黃雲海樹迷。揮鞭萬里去，安得念春閨。"]'),
('yuding-79','橫吹曲辭：紫騮馬','李益','唐','御定全唐诗','yuding','','[]','爭場看鬥雞，白鼻紫騧嘶。漳水春歸晚，叢台日向低。',48,'御定全唐詩/json/018.json','["爭場看鬥雞，白鼻紫騧嘶。漳水春歸晚，叢台日向低。", "歇鞍珠作汗，試劍玉如泥。為謝紅梁燕，年年妾獨棲。"]'),
('yuding-80','橫吹曲辭：紫騮馬','秦韜玉','唐','御定全唐诗','yuding','','[]','渥窪奇骨本難求，況是豪家重紫騮。膘大宜懸銀壓銙。',64,'御定全唐詩/json/018.json','["渥窪奇骨本難求，況是豪家重紫騮。膘大宜懸銀壓銙。", "力渾欺卻玉銜頭。生獰弄影風隨起，躞蹀沖塵汗滿溝。", "若遇丈夫皆調禦，任從騎取覓封侯。"]'),
('yuding-81','橫吹曲辭：驄馬','李群玉','唐','御定全唐诗','yuding','','[]','浮雲何權奇，絕足勢未知。長嘶青海風，躞蹀振雲絲。',96,'御定全唐詩/json/018.json','["浮雲何權奇，絕足勢未知。長嘶青海風，躞蹀振雲絲。", "由來渥窪種，本是蒼龍兒。穆滿不再活，無人昆閬騎。", "君識躍嶠怯，甯勞耀金羈。青芻與白水，空笑駑駘肥。", "伯樂儻一見，應驚耳長垂。當思八荒外，逐日向瑤池。"]'),
('yuding-82','橫吹曲辭：驄馬曲','紀唐夫','唐','御定全唐诗','yuding','','[]','連錢出塞蹋沙蓬，豈比當時禦史驄。逐北自諳深磧路，',40,'御定全唐詩/json/018.json','["連錢出塞蹋沙蓬，豈比當時禦史驄。逐北自諳深磧路，", "今日虜平將換妾，不如羅袖舞春風。"]'),
('yuding-83','橫吹曲辭：雨雪曲','李端','唐','御定全唐诗','yuding','','[]','天山一丈雪，雜雨夜霏霏。濕馬胡歌亂，經烽漢火微。',48,'御定全唐詩/json/018.json','["天山一丈雪，雜雨夜霏霏。濕馬胡歌亂，經烽漢火微。", "丁零蘇武別，疏勒範羌歸。若著關頭過，長榆葉定稀。"]'),
('yuding-84','橫吹曲辭：雨雪曲','翁綬','唐','御定全唐诗','yuding','','[]','邊聲四合殷河流，雨雪飛來遍隴頭。鐵嶺探人迷鳥道，',40,'御定全唐詩/json/018.json','["邊聲四合殷河流，雨雪飛來遍隴頭。鐵嶺探人迷鳥道，", "一自塞垣無李蔡，何人為解北門憂。"]'),
('yuding-85','橫吹曲辭：劉生','盧照鄰','唐','御定全唐诗','yuding','','[]','劉生氣不平，抱劍欲專征。報恩為豪俠，死難在橫行。',48,'御定全唐詩/json/018.json','["劉生氣不平，抱劍欲專征。報恩為豪俠，死難在橫行。", "翠羽裝劍鞘，黃金飾馬纓。但令一顧重，不吝百身輕。"]'),
('yuding-86','橫吹曲辭：雍台歌','溫庭筠','唐','御定全唐诗','yuding','','[]','太子池南樓百尺，八窗新樹疏簾隔。黃金鋪首畫鉤陳，',40,'御定全唐詩/json/018.json','["太子池南樓百尺，八窗新樹疏簾隔。黃金鋪首畫鉤陳，", "早雁聲鳴細波起，映花鹵簿龍飛回。"]'),
('yuding-87','橫吹曲辭：捉搦歌','張祜','唐','御定全唐诗','yuding','','[]','門上關，牆上棘，窗中女子聲唧唧，洛陽大道徒自直。',60,'御定全唐詩/json/018.json','["門上關，牆上棘，窗中女子聲唧唧，洛陽大道徒自直。", "女子心在婆舍側，嗚嗚籠鳥觸四隅。", "養男男娶婦，養女女嫁夫。阿婆六十翁七十，"]'),
('yuding-88','橫吹曲辭：幽州胡馬客歌','李白','唐','御定全唐诗','yuding','','[]','幽州胡馬客，綠眼虎皮冠。笑拂兩隻箭，萬人不可幹。',168,'御定全唐詩/json/018.json','["幽州胡馬客，綠眼虎皮冠。笑拂兩隻箭，萬人不可幹。", "彎弓若轉月，白雁落雲端。雙雙掉鞭行，游獵向樓蘭。", "出門不顧後，報國死何難。天驕五單于，狼戾好兇殘。", "牛馬散北海，割鮮若虎餐。雖居燕支山，不道朔雪寒。", "婦女馬上笑，顏如赬玉盤。翻入射鳥獸，花月醉雕鞍。", "旄頭四光芒，爭戰若蜂攢。白刃灑赤血，流沙為之丹。", "名將古誰是，疲兵良可歎。何時天狼滅，父子得閒安。"]'),
('yuding-89','橫吹曲辭：白鼻騧','李白','唐','御定全唐诗','yuding','','[]','銀鞍白鼻騧，綠地障泥錦。',28,'御定全唐詩/json/018.json','["銀鞍白鼻騧，綠地障泥錦。", "細雨春風花落時，揮鞭且就胡姬飲。"]'),
('yuding-90','橫吹曲辭：白鼻騧','張祜','唐','御定全唐诗','yuding','','[]','為底胡姬酒，長來白鼻騧。摘蓮拋水上，郎意在浮花。',24,'御定全唐詩/json/018.json','["為底胡姬酒，長來白鼻騧。摘蓮拋水上，郎意在浮花。"]'),
('yuding-0','相和歌辭：箜篌引','李賀','唐','御定全唐诗','yuding','','[]','公乎公乎，提壺將焉如。屈平沉湘不足慕，',19,'御定全唐詩/json/019.json','["公乎公乎，提壺將焉如。屈平沉湘不足慕，"]'),
('yuding-1','相和歌辭：公無渡河','李白','唐','御定全唐诗','yuding','','[]','黃河西來決昆侖，咆吼萬里觸龍門。波滔天，堯咨嗟，',110,'御定全唐詩/json/019.json','["黃河西來決昆侖，咆吼萬里觸龍門。波滔天，堯咨嗟，", "其害乃去。茫然風沙，被發之叟狂而癡。", "清晨徑流欲奚為，旁人不惜妻止之，公無渡河苦渡之。", "虎可搏，河難憑，公果溺死流海湄，有長鯨白齒若雪山。", "公乎公乎，掛骨於其間，箜篌所悲竟不還。"]'),
('yuding-2','相和歌辭：公無渡河','王建','唐','御定全唐诗','yuding','','[]','渡頭惡天兩岸遠，波濤塞川如疊阪。幸無白刃驅向前，',48,'御定全唐詩/json/019.json','["渡頭惡天兩岸遠，波濤塞川如疊阪。幸無白刃驅向前，", "男兒縱輕婦人語，惜君性命還須取。婦人無力挽斷衣，"]'),
('yuding-3','相和歌辭：公無渡河','溫庭筠','唐','御定全唐诗','yuding','','[]','黃河怒浪連天來，大響谹谹如殷雷。龍伯驅風不敢上，',48,'御定全唐詩/json/019.json','["黃河怒浪連天來，大響谹谹如殷雷。龍伯驅風不敢上，", "下有狂蛟鋸為尾，裂帆截棹磨霜齒。神錐鑿石塞神潭，"]'),
('yuding-4','相和歌辭：公無渡河','不詳','唐','御定全唐诗','yuding','','[]','濁波洋洋兮凝曉霧，公無渡河兮公苦渡。',104,'御定全唐詩/json/019.json','["濁波洋洋兮凝曉霧，公無渡河兮公苦渡。", "風號水激兮呼不聞，提壺看入兮中流去。", "浪擺衣裳兮隨步沒，沉屍深入兮蛟螭窟。", "蛟螭盡醉兮君血幹，推出黃沙兮泛君骨。", "當時君死妾何適，遂就波瀾合魂魄。", "願持精衛銜石心，窮取河源塞泉脈。"]'),
('yuding-5','相和歌辭：江南曲','宋之問','唐','御定全唐诗','yuding','','[]','妾住越城南，離居不自堪。采花驚曙鳥，摘葉喂春蠶。',48,'御定全唐詩/json/019.json','["妾住越城南，離居不自堪。采花驚曙鳥，摘葉喂春蠶。", "懶結茱萸帶，愁安玳瑁簪。侍臣消瘦盡，日暮碧江潭。"]'),
('yuding-6','相和歌辭：江南曲','劉昚虛','唐','御定全唐诗','yuding','','[]','美人何蕩漾，湖上風月長。玉手欲有贈，裴回雙鳴璫。',48,'御定全唐詩/json/019.json','["美人何蕩漾，湖上風月長。玉手欲有贈，裴回雙鳴璫。", "歌聲隨淥水，怨色起朝陽。日暮還家望，雲波橫洞房。"]'),
('yuding-7','相和歌辭：江南曲','丁仙芝','唐','御定全唐诗','yuding','','[]','長幹斜路北，近浦是兒家。有意來相訪，明朝出浣紗。',120,'御定全唐詩/json/019.json','["長幹斜路北，近浦是兒家。有意來相訪，明朝出浣紗。", "發向橫塘口，船開值急流。知郎舊時意，且請攏船頭。", "昨暝逗南陵，風聲波浪阻。入浦不逢人，歸家誰信汝。", "未曉已成妝，乘潮去茫茫。因從京口渡，使報邵陵王。", "始下芙蓉樓，言發琅邪岸。急為打船開，惡許傍人見。"]'),
('yuding-8','相和歌辭：江南曲八首','劉希夷','唐','御定全唐诗','yuding','','[]','暮宿南洲草，晨行北岸林。日懸滄海闊，水隔洞庭深。',424,'御定全唐詩/json/019.json','["暮宿南洲草，晨行北岸林。日懸滄海闊，水隔洞庭深。", "煙景無留意，風波有異潯。歲遊難極目，春戲易為心。", "朝夕無榮遇，芳菲已滿襟。", "豔唱潮初落，江花露未晞。春洲驚翡翠，朱服弄芳菲。", "畫舫煙中淺，青陽日際微。錦帆衝浪濕，羅袖拂行衣。", "含情罷所采，相嘆惜流暉。", "君為隴西客，妾遇江南春。朝遊含靈果，夕采弄風蘋。", "果氣時不歇，蘋花日自新。以此江南物，持贈隴西人。", "空盈萬里懷，欲贈竟無因。", "皓如楚江月，靄若吳岫雲。波中自皎鏡，山上亦氛氳。", "明月留照妾，輕雲持贈君。山川各離散，光氣乃殊分。", "天涯一為別，江北自相聞。", "艤舟乘潮去，風帆振草涼。潮平見楚甸，天際望維揚。", "洄溯經千里，煙波接兩鄉。雲明江嶼出，日照海流長。", "此中逢歲晏，浦樹落花芳。", "暮春三月晴，維揚吳楚城。城臨大江汜，回映洞浦清。", "晴雲曲金閣，珠樓碧煙裏。月明芳樹群鳥飛，", "北堂紅草盛豐茸，南湖碧水照芙蓉。朝游暮起金花盡，", "人情一去無還日，欲贈懷芳怨不逢。", "憶昔江南年盛時，平生怨在長洲曲。冠蓋星繁湘水上，", "誰言此處嬋娟子，珠玉為心以奉君。"]'),
('yuding-9','相和歌辭：江南曲','於鵠','唐','御定全唐诗','yuding','','[]','偶向江邊采白蘋，還隨女伴賽江神。',32,'御定全唐詩/json/019.json','["偶向江邊采白蘋，還隨女伴賽江神。", "眾中不敢分明語，暗擲金錢蔔遠人。"]'),
('yuding-10','相和歌辭：江南曲','李益','唐','御定全唐诗','yuding','','[]','嫁得瞿塘賈，朝朝誤妾期。早知潮有信，嫁與弄潮兒。',24,'御定全唐詩/json/019.json','["嫁得瞿塘賈，朝朝誤妾期。早知潮有信，嫁與弄潮兒。"]'),
('yuding-11','相和歌辭：江南曲','李賀','唐','御定全唐诗','yuding','','[]','汀洲白蘋草，柳惲乘馬歸。江頭楂樹香，岸上蝴蝶飛。',48,'御定全唐詩/json/019.json','["汀洲白蘋草，柳惲乘馬歸。江頭楂樹香，岸上蝴蝶飛。", "酒杯若葉露，玉軫蜀桐虛。朱樓通水陌，沙暖一雙魚。"]'),
('yuding-12','相和歌辭：江南曲','李商隱','唐','御定全唐诗','yuding','','[]','郎船安兩槳，儂舸動雙橈。掃黛開宮額，裁裙約楚腰。',48,'御定全唐詩/json/019.json','["郎船安兩槳，儂舸動雙橈。掃黛開宮額，裁裙約楚腰。", "乖期方積思，臨醉欲拼嬌。莫以采菱唱，欲羨秦台簫。"]'),
('yuding-13','相和歌辭：江南曲','韓翃','唐','御定全唐诗','yuding','','[]','長樂花枝雨點消，江城日暮好相邀。',32,'御定全唐詩/json/019.json','["長樂花枝雨點消，江城日暮好相邀。", "春樓不閉葳蕤鎖，綠水回通宛轉橋。"]'),
('yuding-14','相和歌辭：江南曲','溫庭筠','唐','御定全唐诗','yuding','','[]','妾家白蘋浦，日上芙蓉楫。軋軋搖槳聲，移舟入茭葉。',240,'御定全唐詩/json/019.json','["妾家白蘋浦，日上芙蓉楫。軋軋搖槳聲，移舟入茭葉。", "溪長茭葉深，作底難相尋。避郎郎不見，鸂鶒自浮沉。", "拾萍萍無根，採蓮蓮有子。不作浮萍生，寧作藕花死。", "岸傍騎馬郎，烏帽紫遊韁。含愁複含笑，回首問橫塘。", "妾住金陵步，門前朱雀航。流蘇持作帳，芙蓉持作梁。", "出入金犢幰，兄弟侍中郎。前年學歌舞，定得郎相許。", "連娟眉繞山，依約腰如杵。鳳管悲若咽，鸞弦嬌欲語。", "扇薄露紅鉛，羅輕壓金縷。明月西南樓，珠簾玳瑁鉤。", "橫波巧能笑，彎蛾不識愁。花開子留樹，草長根依土。", "早聞金溝遠，底事歸郎許。不學楊白花，朝朝淚如雨。"]'),
('yuding-15','相和歌辭：江南曲','張籍','唐','御定全唐诗','yuding','','[]','江南人家多橘樹，吳姬舟上織白紵。土地卑濕饒蟲蛇，',64,'御定全唐詩/json/019.json','["江南人家多橘樹，吳姬舟上織白紵。土地卑濕饒蟲蛇，", "青莎覆城竹為屋，無井家家飲潮水。長江午日酤春酒，", "江南風土歡樂多，悠悠處處盡經過。"]'),
('yuding-16','相和歌辭：江南曲','羅隱','唐','御定全唐诗','yuding','','[]','江煙濕雨鮫綃軟，漠漠遠山眉黛淺。水國多愁又有情，',48,'御定全唐詩/json/019.json','["江煙濕雨鮫綃軟，漠漠遠山眉黛淺。水國多愁又有情，", "鴛鴦鸂鶒喚不起，平鋪淥水眠東風。西陵路邊月悄悄，"]'),
('yuding-17','相和歌辭：江南曲','陸龜蒙','唐','御定全唐诗','yuding','','[]','為愛江南春，涉江聊采蘋。水深煙浩浩，空對雙車輪。',72,'御定全唐詩/json/019.json','["為愛江南春，涉江聊采蘋。水深煙浩浩，空對雙車輪。", "車輪明月團，車蓋浮雲盤。雲月徒自好，水中行路難。", "遙遙洛陽道，夾岸生春草。寄語棹船郎，莫誇風浪好。"]'),
('yuding-18','相和歌辭：江南曲','陸龜蒙','唐','御定全唐诗','yuding','','[]','魚戲蓮葉間，參差隱葉扇。鵁鶄鸀鳿窺，瀲灩無因見。',120,'御定全唐詩/json/019.json','["魚戲蓮葉間，參差隱葉扇。鵁鶄鸀鳿窺，瀲灩無因見。", "魚戲蓮葉東，初霞射紅尾。傍臨謝山側，恰值清風起。", "魚戲蓮葉西，盤盤舞波急。潛依曲岸涼，正對斜光入。", "魚戲蓮葉南，欹危午煙疊。光搖越鳥巢，影亂吳娃楫。", "魚戲蓮葉北，澄陽動微漣。回看帝子渚，稍背鄂君船。"]'),
('yuding-19','相和歌辭：度關山','李端','唐','御定全唐诗','yuding','','[]','雁塞日初晴，胡關雪複平。危竿緣廣漠，古竇傍長城。',48,'御定全唐詩/json/019.json','["雁塞日初晴，胡關雪複平。危竿緣廣漠，古竇傍長城。", "拔劍金星出，彎弧玉羽鳴。誰知系虜者，賈誼是書生。"]'),
('yuding-20','相和歌辭：關山曲','馬戴','唐','御定全唐诗','yuding','','[]','金鎖耀兜鍪，黃雲拂紫騮。叛羌旗下戮，陷壁夜中收。',96,'御定全唐詩/json/019.json','["金鎖耀兜鍪，黃雲拂紫騮。叛羌旗下戮，陷壁夜中收。", "霜霰戎衣故，關河磧氣秋。箭創殊未合，更遣擊蘭州。", "火發龍山北，中宵易左賢。勒兵臨漢水，驚雁散胡天。", "木落防河急，軍孤受敵偏。猶聞漢皇怒，按劍待開邊。"]'),
('yuding-21','相和歌辭：登高丘而望遠','李白','唐','御定全唐诗','yuding','','[]','登高丘而望遠海，六鼇骨已霜，三山流安在？',79,'御定全唐詩/json/019.json','["登高丘而望遠海，六鼇骨已霜，三山流安在？", "扶桑半摧折，白日沉光彩。銀台金闕如夢中，", "君不見驪山茂陵盡灰滅，牧羊之子來攀登。", "盜賊劫寶玉，精靈竟何能。窮兵黷武今如此，"]'),
('yuding-22','相和歌辭：蒿裏','貫休','唐','御定全唐诗','yuding','','[]','兔不遲，烏更急，但恐穆王八駿，著鞭不及。所以蒿裏，',25,'御定全唐詩/json/019.json','["兔不遲，烏更急，但恐穆王八駿，著鞭不及。所以蒿裏，"]'),
('yuding-23','相和歌辭：挽歌','趙微明','唐','御定全唐诗','yuding','','[]','寒日蒿上明，淒淒郭東路。素車誰家子，丹旐引將去。',60,'御定全唐詩/json/019.json','["寒日蒿上明，淒淒郭東路。素車誰家子，丹旐引將去。", "原下荊棘叢，叢邊有新墓。人間痛傷別，此是長別處。", "曠野何蕭條，青松白楊樹。"]'),
('yuding-24','相和歌辭：挽歌二首','於鵠','唐','御定全唐诗','yuding','','[]','陰風吹黃蒿，挽歌渡秋水。車馬卻歸城，孤墳月明裏。',96,'御定全唐詩/json/019.json','["陰風吹黃蒿，挽歌渡秋水。車馬卻歸城，孤墳月明裏。", "雙轍出郭門，綿綿東西道。送死多於生，幾人得終老。", "見人切肺肝，不如歸山好。不聞哀哭聲，默默安懷抱。", "時盡從物化，又免生憂擾。世間壽者稀，盡為悲傷惱。"]'),
('yuding-25','相和歌辭：挽歌','孟雲卿','唐','御定全唐诗','yuding','','[]','草草門巷喧，塗車儼成位。冥寞何所須，盡我生人意。',96,'御定全唐詩/json/019.json','["草草門巷喧，塗車儼成位。冥寞何所須，盡我生人意。", "北邙路非遠，此別終天地。臨穴頻撫棺，至哀反無淚。", "爾形未衰老，爾息猶童稚。骨肉不可離，皇天若容易。", "房帷即虛張，庭宇為哀次。薤露歌若斯，人生盡如寄。"]'),
('yuding-26','相和歌辭：挽歌','白居易','唐','御定全唐诗','yuding','','[]','丹旐何飛揚，素驂亦悲鳴。晨光照閭巷，輀車儼欲行。',100,'御定全唐詩/json/019.json','["丹旐何飛揚，素驂亦悲鳴。晨光照閭巷，輀車儼欲行。", "蕭條九月天，哀挽出重城。借問送者誰，妻子與弟兄。", "蒼蒼上古原，峨峨開新塋。含酸一慟哭，異口同哀聲。", "舊壟轉蕪絕，新墳日羅列。", "春風草綠北邙山，此地年年生死別。"]'),
('yuding-27','相和歌辭：對酒','崔國輔','唐','御定全唐诗','yuding','','[]','行行日將夕，荒村古塚無人跡。朦朧荊棘一鳥飛，',38,'御定全唐詩/json/019.json','["行行日將夕，荒村古塚無人跡。朦朧荊棘一鳥飛，", "寄言當代諸少年，平生且盡杯中淥。"]'),
('yuding-28','相和歌辭：對酒二首','李白','唐','御定全唐诗','yuding','','[]','松子棲金華，安期入蓬海。此人古之仙，羽化竟何在。',144,'御定全唐詩/json/019.json','["松子棲金華，安期入蓬海。此人古之仙，羽化竟何在。", "浮生速流電，倏忽變光彩。天地無凋換，容顏有遷改。", "對酒不肯飲，含情欲誰待。", "勸君莫拒杯，春風笑人來。桃李如舊識，傾花向我開。", "流鶯啼碧樹，明月窺金罍。昨來朱顏子，今日白髮催。", "棘生石虎殿，鹿走姑蘇台。自古帝王宅，城闕閉黃埃。", "君若不飲酒，昔人安在哉。"]'),
('yuding-29','相和歌辭：陌上桑','李白','唐','御定全唐诗','yuding','','[]','美女渭橋東，春還事蠶作。五馬如飛龍，青絲結金絡。',108,'御定全唐詩/json/019.json','["美女渭橋東，春還事蠶作。五馬如飛龍，青絲結金絡。", "不知誰家子，調笑來相謔。妾本秦羅敷，玉顏豔名都。", "綠條映素手，采桑向城隅。使君且不顧，況複論秋胡。", "寒螿愛碧草，鳴鳳棲青梧。托心自有處，但怪傍人愚。", "徒令白日暮，高駕空踟躕。"]'),
('yuding-30','相和歌辭：陌上桑','常建','唐','御定全唐诗','yuding','','[]','翳翳陌上桑，南枝交北堂。美人金梯出，素手自提筐。',36,'御定全唐詩/json/019.json','["翳翳陌上桑，南枝交北堂。美人金梯出，素手自提筐。", "非但畏蠶饑，盈盈嬌路傍。"]'),
('yuding-31','相和歌辭：陌上桑','陸龜蒙','唐','御定全唐诗','yuding','','[]','皓齒還如貝色含，長眉亦似煙華貼。',32,'御定全唐詩/json/019.json','["皓齒還如貝色含，長眉亦似煙華貼。", "鄰娃盡著繡襠襦，獨自提筐采蠶葉。"]'),
('yuding-32','相和歌辭：采桑','郎大家宋氏','唐','御定全唐诗','yuding','','[]','春來南雁歸，日去西蠶遠。妾思紛何極，客遊殊未返。',24,'御定全唐詩/json/019.json','["春來南雁歸，日去西蠶遠。妾思紛何極，客遊殊未返。"]'),
('yuding-33','相和歌辭：采桑','劉希夷','唐','御定全唐诗','yuding','','[]','楊柳送行人，青青西入秦。秦家采桑女，樓上不勝春。',120,'御定全唐詩/json/019.json','["楊柳送行人，青青西入秦。秦家采桑女，樓上不勝春。", "盈盈灞水曲，步步春芳綠。紅臉耀明珠，絳唇含白玉。", "回首渭橋東，遙憐樹色同。青絲嬌落日，緗綺弄春風。", "攜籠長歎息，逶迤戀春色。看花若有情，倚樹疑無力。", "薄暮思悠悠，使君南陌頭。相逢不相識，歸去夢青樓。"]'),
('yuding-34','相和歌辭：采桑','李彥暐','唐','御定全唐诗','yuding','','[]','采桑畏日高，不待春眠足。攀條有餘愁，那矜貌如玉。',48,'御定全唐詩/json/019.json','["采桑畏日高，不待春眠足。攀條有餘愁，那矜貌如玉。", "千金豈不贈，五馬空躑躅。何以變真性，幽篁雪中綠。"]'),
('yuding-35','相和歌辭：采桑','王建','唐','御定全唐诗','yuding','','[]','鳥鳴桑葉間，葉綠條複柔。攀看去手近，放下長長鉤。',48,'御定全唐詩/json/019.json','["鳥鳴桑葉間，葉綠條複柔。攀看去手近，放下長長鉤。", "黃花蓋野田，白馬少年游。所念豈回顧，良人在高樓。"]'),
('yuding-36','相和歌辭：日出行','李白','唐','御定全唐诗','yuding','','[]','日出東方隈，似從地底來。曆天又入海，',88,'御定全唐詩/json/019.json','["日出東方隈，似從地底來。曆天又入海，", "人非元氣安能與之久裴回。草不謝榮于春風，", "羲和羲和，汝奚汩沒於荒淫之波。", "魯陽何德，駐景揮戈，逆道違天，矯誣實多。", "吾將囊括大塊，浩然與溟涬同科。"]'),
('yuding-37','相和歌辭：日出行','李賀','唐','御定全唐诗','yuding','','[]','白日下昆侖，發光如舒絲。徒照葵藿心，不照遊子悲。',67,'御定全唐詩/json/019.json','["白日下昆侖，發光如舒絲。徒照葵藿心，不照遊子悲。", "折折黃河曲，日從中央轉。暘谷耳曾聞，若木眼不見。", "奈何鑠石，胡為銷人。羿彎弓屬矢那不中，"]'),
('yuding-38','相和歌辭：王昭君','崔國輔','唐','御定全唐诗','yuding','','[]','漢使南還盡，胡中妾獨存。紫台綿望絕，秋草不堪論。',24,'御定全唐詩/json/019.json','["漢使南還盡，胡中妾獨存。紫台綿望絕，秋草不堪論。"]'),
('yuding-39','相和歌辭：王昭君','崔國輔','唐','御定全唐诗','yuding','','[]','一回望月一回悲，望月月移人不移。',32,'御定全唐詩/json/019.json','["一回望月一回悲，望月月移人不移。", "何時得見漢朝使，為妾傳書斬畫師。"]'),
('yuding-40','相和歌辭：王昭君','盧照鄰','唐','御定全唐诗','yuding','','[]','合殿恩中絕，交河使漸稀。肝腸辭玉輦，形影向金微。',48,'御定全唐詩/json/019.json','["合殿恩中絕，交河使漸稀。肝腸辭玉輦，形影向金微。", "漢宮草應綠，胡庭沙正飛。願逐三秋雁，年年一度歸。"]'),
('yuding-41','相和歌辭：王昭君','駱賓王','唐','御定全唐诗','yuding','','[]','斂容辭豹尾，緘怨度龍鱗。金鈿明漢月，玉箸染胡塵。',48,'御定全唐詩/json/019.json','["斂容辭豹尾，緘怨度龍鱗。金鈿明漢月，玉箸染胡塵。", "妝鏡菱花暗，愁眉柳葉嚬。惟有清笳曲，時聞芳樹春。"]'),
('yuding-42','相和歌辭：王昭君','沈佺期','唐','御定全唐诗','yuding','','[]','非君惜鸞殿，非妾妒蛾眉。薄命由驕虜，無情是畫師。',48,'御定全唐詩/json/019.json','["非君惜鸞殿，非妾妒蛾眉。薄命由驕虜，無情是畫師。", "嫁來胡地惡，不並漢宮時。心苦無聊賴，何堪上馬辭。"]'),
('yuding-43','相和歌辭：王昭君','梁獻','唐','御定全唐诗','yuding','','[]','圖畫失天真，容華坐誤人。君恩不可再，妾命在和親。',48,'御定全唐詩/json/019.json','["圖畫失天真，容華坐誤人。君恩不可再，妾命在和親。", "淚點關山月，衣銷邊塞塵。一聞陽鳥至，思絕漢宮春。"]'),
('yuding-44','相和歌辭：王昭君','上官儀','唐','御定全唐诗','yuding','','[]','玉關春色晚，金河路幾千。琴悲桂條上，笛怨柳花前。',48,'御定全唐詩/json/019.json','["玉關春色晚，金河路幾千。琴悲桂條上，笛怨柳花前。", "霧掩臨妝月，風驚入鬢蟬。緘書待還使，淚盡白雲天。"]'),
('yuding-45','相和歌辭：王昭君','董思恭','唐','御定全唐诗','yuding','','[]','琵琶馬上彈，行路曲中難。漢月正南遠，燕山直北寒。',48,'御定全唐詩/json/019.json','["琵琶馬上彈，行路曲中難。漢月正南遠，燕山直北寒。", "髻鬟風拂散，眉黛雪沾殘。斟酌紅顏盡，何勞鏡裏看。"]'),
('yuding-46','相和歌辭：王昭君','顧朝陽','唐','御定全唐诗','yuding','','[]','莫將鉛粉匣，不用鏡花光。一去邊城路，何情更畫妝。',48,'御定全唐詩/json/019.json','["莫將鉛粉匣，不用鏡花光。一去邊城路，何情更畫妝。", "影銷胡地月，衣盡漢宮香。妾死非關命，只緣怨斷腸。"]'),
('yuding-47','相和歌辭：王昭君三首','東方虯','唐','御定全唐诗','yuding','','[]','漢道初全盛，朝廷足武臣。何須薄命妾，辛苦遠和親。',72,'御定全唐詩/json/019.json','["漢道初全盛，朝廷足武臣。何須薄命妾，辛苦遠和親。", "掩涕辭丹鳳，銜悲向白龍。單于浪驚喜，無復舊時容。", "胡地無花草，春來不似春。自然衣帶緩，非是為腰身。"]'),
('yuding-48','相和歌辭：王昭君三首','郭元振','唐','御定全唐诗','yuding','','[]','自嫁單于國，長銜漢掖悲。容顏日憔悴，有甚畫圖時。',72,'御定全唐詩/json/019.json','["自嫁單于國，長銜漢掖悲。容顏日憔悴，有甚畫圖時。", "厭踐冰霜域，嗟為邊塞人。思從漢南獵，一見漢家塵。", "聞有南河信，傳聞殺畫師。始知君惠重，更遣畫蛾眉。"]'),
('yuding-49','相和歌辭：王昭君','劉長卿','唐','御定全唐诗','yuding','','[]','自矜妖豔色，不顧丹青人。那知粉繢能相負，',60,'御定全唐詩/json/019.json','["自矜妖豔色，不顧丹青人。那知粉繢能相負，", "北風雁急浮清秋，萬里獨見黃河流。纖腰不復漢宮寵，", "可憐一曲傳樂府，能使千秋傷綺羅。"]'),
('yuding-50','相和歌辭：王昭君二首','李白','唐','御定全唐诗','yuding','','[]','漢家秦地月，流影照明妃。一上玉關道，天涯去不歸。',72,'御定全唐詩/json/019.json','["漢家秦地月，流影照明妃。一上玉關道，天涯去不歸。", "漢月還從東海出，明妃西嫁無來日。燕支長寒雪作花，", "昭君拂玉鞍，上馬啼紅頰。今日漢宮人，明朝胡地妾。"]'),
('yuding-51','相和歌辭：王昭君','儲光羲','唐','御定全唐诗','yuding','','[]','日暮驚沙亂雪飛，傍人相勸易羅衣。',32,'御定全唐詩/json/019.json','["日暮驚沙亂雪飛，傍人相勸易羅衣。", "強來前帳看歌舞，共待單于夜獵歸。"]'),
('yuding-52','相和歌辭：王昭君','皎然','唐','御定全唐诗','yuding','','[]','自倚嬋娟望主恩，誰知美惡忽相翻。',32,'御定全唐詩/json/019.json','["自倚嬋娟望主恩，誰知美惡忽相翻。", "黃金不買漢宮貌，青塚空埋胡地魂。"]'),
('yuding-53','相和歌辭：王昭君二首','白居易','唐','御定全唐诗','yuding','','[]','滿面胡沙滿鬢風，眉銷殘黛臉銷紅。',64,'御定全唐詩/json/019.json','["滿面胡沙滿鬢風，眉銷殘黛臉銷紅。", "愁苦辛勤憔悴盡，如今卻似畫圖中。", "漢使卻回憑寄語，黃金何日贖蛾眉。", "君王若問妾顏色，莫道不如宮裏時。"]'),
('yuding-54','相和歌辭：王昭君','令狐楚','唐','御定全唐诗','yuding','','[]','錦車天外去，毳幕雲中開。魏闕蒼龍遠，蕭關赤雁哀。',24,'御定全唐詩/json/019.json','["錦車天外去，毳幕雲中開。魏闕蒼龍遠，蕭關赤雁哀。"]'),
('yuding-55','相和歌辭：王昭君','張仲素','唐','御定全唐诗','yuding','','[]','仙娥今下嫁，驕子自同和。劍戟歸田盡，牛羊繞塞多。',24,'御定全唐詩/json/019.json','["仙娥今下嫁，驕子自同和。劍戟歸田盡，牛羊繞塞多。"]'),
('yuding-56','相和歌辭：王昭君','李商隱','唐','御定全唐诗','yuding','','[]','毛延壽畫欲通神，忍為黃金不為人。',32,'御定全唐詩/json/019.json','["毛延壽畫欲通神，忍為黃金不為人。", "馬上琵琶行萬里，漢宮長有隔生春。"]'),
('yuding-57','相和歌辭：明妃曲','王偃','唐','御定全唐诗','yuding','','[]','北望單于日半斜，明君馬上泣胡沙。',32,'御定全唐詩/json/019.json','["北望單于日半斜，明君馬上泣胡沙。", "一雙淚滴黃河水，應得東流入漢家。"]'),
('yuding-58','相和歌辭：昭君詞','張文琮','唐','御定全唐诗','yuding','','[]','戒途飛萬里，回首望三秦。忽見天山雪，還疑上苑春。',48,'御定全唐詩/json/019.json','["戒途飛萬里，回首望三秦。忽見天山雪，還疑上苑春。", "玉痕垂淚粉，羅袂拂胡塵。為得胡中曲，還悲遠嫁人。"]'),
('yuding-59','相和歌辭：昭君詞','陳昭','唐','御定全唐诗','yuding','','[]','跨鞍今永訣，垂淚別親賓。漢地行將遠，胡關逐望新。',48,'御定全唐詩/json/019.json','["跨鞍今永訣，垂淚別親賓。漢地行將遠，胡關逐望新。", "交河擁塞路，隴首暗沙塵。唯有孤明月，猶能遠送人。"]'),
('yuding-60','相和歌辭：昭君詞','戴叔倫','唐','御定全唐诗','yuding','','[]','漢宮若遠近，路在沙塞上。到死不得歸，何人共南望。',24,'御定全唐詩/json/019.json','["漢宮若遠近，路在沙塞上。到死不得歸，何人共南望。"]'),
('yuding-61','相和歌辭：昭君詞','李端','唐','御定全唐诗','yuding','','[]','李陵初送子卿回，漢月明明照帳來。',32,'御定全唐詩/json/019.json','["李陵初送子卿回，漢月明明照帳來。", "憶著長安舊遊處，千門萬戶玉樓臺。"]'),
('yuding-62','相和歌辭：楚妃歎','張籍','唐','御定全唐诗','yuding','','[]','湘雲初起江沉沉，君王遙在雲夢林。江南雨多旌旗暗，',48,'御定全唐詩/json/019.json','["湘雲初起江沉沉，君王遙在雲夢林。江南雨多旌旗暗，", "楚兵滿地能逐禽，誰用一身繼筋力。西江若翻雲夢中，"]'),
('yuding-63','相和歌辭：楚妃怨','張籍','唐','御定全唐诗','yuding','','[]','梧桐葉下黃金井，橫架轆轤牽素綆。',32,'御定全唐詩/json/019.json','["梧桐葉下黃金井，橫架轆轤牽素綆。", "美人初起天未明，手拂銀瓶秋水冷。"]'),
('yuding-64','相和歌辭：王子喬','宋之問','唐','御定全唐诗','yuding','','[]','王子喬，愛神仙，七月七日上賓天。白虎搖瑟鳳吹笙，',36,'御定全唐詩/json/019.json','["王子喬，愛神仙，七月七日上賓天。白虎搖瑟鳳吹笙，", "空望山頭草，草露濕君衣。"]'),
('yuding-65','相和歌辭：蜀國弦','李賀','唐','御定全唐诗','yuding','','[]','楓香晚華靜，錦水南山影。驚石墜猿哀，竹雲愁半嶺。',48,'御定全唐詩/json/019.json','["楓香晚華靜，錦水南山影。驚石墜猿哀，竹雲愁半嶺。", "涼月生秋浦，玉沙鱗鱗光。誰家紅淚客，不忍過瞿塘。"]'),
('yuding-66','相和歌辭：長歌行','李白','唐','御定全唐诗','yuding','','[]','桃李得日開，榮華照當年。東風動百物，草木盡欲言。',120,'御定全唐詩/json/019.json','["桃李得日開，榮華照當年。東風動百物，草木盡欲言。", "枯枝無醜葉，涸水吐清泉。大力運天地，羲和無停鞭。", "功名不早著，竹帛將何宣。桃李務青春，誰能貫白日。", "富貴與神仙，蹉跎成兩失。金石猶銷鑠，風霜無久質。", "畏落日月後，強歡歌與酒。秋霜不惜人，倏忽侵蒲柳。"]'),
('yuding-67','相和歌辭：長歌行','王昌齡','唐','御定全唐诗','yuding','','[]','曠野饒悲風，颼颼黃蒿草。系馬停白楊，誰知我懷抱。',96,'御定全唐詩/json/019.json','["曠野饒悲風，颼颼黃蒿草。系馬停白楊，誰知我懷抱。", "所是同袍者，相逢盡衰老。況登漢家陵，南望長安道。", "下有枯樹根，上有鼷鼠窠。高皇子孫盡，千古無人過。", "寶玉頻發掘，精靈其奈何。人生須達命，有酒且長歌。"]'),
('yuding-68','相和歌辭：短歌行','聶夷中','唐','御定全唐诗','yuding','','[]','八月木蔭薄，十葉三墮枝。人生過五十，亦已同此時。',120,'御定全唐詩/json/019.json','["八月木蔭薄，十葉三墮枝。人生過五十，亦已同此時。", "朝出東郭門，嘉樹鬱參差。暮出西郭門，原草已離披。", "南鄰好台榭，北鄰善歌吹。榮華忽消歇，四顧令人悲。", "生死與榮辱，四者乃常期。古人恥其名，沒世無人知。", "無言鬢似霜，勿謂發如絲。耆年無一善，何殊食乳兒。"]'),
('yuding-69','相和歌辭：短歌行','李白','唐','御定全唐诗','yuding','','[]','白日何短短，百年苦易滿。蒼穹浩茫茫，萬劫太極長。',84,'御定全唐詩/json/019.json','["白日何短短，百年苦易滿。蒼穹浩茫茫，萬劫太極長。", "麻姑垂兩鬢，一半已成霜。天公見玉女，大笑億千場。", "吾欲攬六龍，回車掛扶桑。北斗酌美酒，勸龍各一觴。", "富貴非所願，為人駐頹光。"]'),
('yuding-70','相和歌辭：短歌行六首','顧況','唐','御定全唐诗','yuding','','[]','城邊路，今人犁田昔人墓。岸上沙，昔時江水今人家。',200,'御定全唐詩/json/019.json','["城邊路，今人犁田昔人墓。岸上沙，昔時江水今人家。", "今人昔人共長歎，四氣相催節回換。明月皎皎入華池，", "我欲升天天隔霄，我思渡水水無橋，我欲上山山路險，", "紫燕西飛欲寄書，白雲何處逢來客。", "新系青絲百尺繩，心在君家轆轤上。", "我心皎潔君不知，轆轤一轉一惆悵。", "何處春風吹曉幕，江南綠水通朱閣。", "美人二八面如花，泣向東風畏花落。", "臨春風，聽春鳥。別時多，見時少。愁人夜永不得眠，", "軒轅皇帝初得仙，鼎湖一去三千年。周流三十六洞天，"]'),
('yuding-71','相和歌辭：短歌行','王建','唐','御定全唐诗','yuding','','[]','人初生，日初出，上山遲，下山疾。百年三萬六千朝，',48,'御定全唐詩/json/019.json','["人初生，日初出，上山遲，下山疾。百年三萬六千朝，", "人家見生男女好，不知男女催人老。短歌行，無樂聲。"]'),
('yuding-72','相和歌辭：短歌行','張籍','唐','御定全唐诗','yuding','','[]','青天蕩蕩高且虛，上有白日無根株。流光暫出還入地，',40,'御定全唐詩/json/019.json','["青天蕩蕩高且虛，上有白日無根株。流光暫出還入地，", "玉卮盛酒置君前，再拜願君千萬年。"]'),
('yuding-73','相和歌辭：短歌行二首','白居易','唐','御定全唐诗','yuding','','[]','曈曈太陽如火色，上行千里下一刻。出為白晝入為夜，',240,'御定全唐詩/json/019.json','["曈曈太陽如火色，上行千里下一刻。出為白晝入為夜，", "歌聲苦，詞亦苦，四座少年君聽取。今夕未竟明夕催，", "勸君且強笑一面，勸君複強飲一杯。人生不得長歡樂，", "世人求富貴，多為身嗜欲。盛衰不自由，得失常相逐。", "問君少年日，苦學將幹祿。負笈塵中游，抱書雪前宿。", "布衾不周體，藜茄才充腹。三十登宦途，五十被朝服。", "奴溫已挾纊，馬肥初食粟。未敢議歡游，尚為名檢束。", "耳目聾暗後，堂上調絲竹。牙齒缺落時，盤中堆酒肉。", "彼來此已去，外餘中不足。少壯與榮華，相避如寒燠。", "青雲去地遠，白日終天速。從古無奈何，短歌聽一曲。"]'),
('yuding-74','相和歌辭：短歌行','陸龜蒙','唐','御定全唐诗','yuding','','[]','爪牙在身上，陷阱猶可制。爪牙在胸中，劍戟無所畏。',48,'御定全唐詩/json/019.json','["爪牙在身上，陷阱猶可制。爪牙在胸中，劍戟無所畏。", "人言畏猛虎，誰是撩頭斃。只見古來心，奸雄暗相噬。"]'),
('yuding-75','相和歌辭：短歌行','皎然','唐','御定全唐诗','yuding','','[]','古人若不死，吾亦何所悲。蕭蕭煙雨九原上，',56,'御定全唐詩/json/019.json','["古人若不死，吾亦何所悲。蕭蕭煙雨九原上，", "人生在世共如此，何異浮雲與流水。", "短歌行，短歌無窮日已傾。鄴宮梁苑徒有名，"]'),
('yuding-76','相和歌辭：銅雀台','王無競','唐','御定全唐诗','yuding','','[]','北登銅雀上，西望青松郭。繐帳空蒼蒼，陵田紛漠漠。',72,'御定全唐詩/json/019.json','["北登銅雀上，西望青松郭。繐帳空蒼蒼，陵田紛漠漠。", "平生事已變，歌吹宛猶昨。長袖拂玉塵，遺情結羅幕。", "妾怨在朝露，君恩豈中薄。高臺奏曲終，曲終淚橫落。"]'),
('yuding-77','相和歌辭：銅雀台','鄭愔','唐','御定全唐诗','yuding','','[]','日斜漳浦望，風起鄴台寒。玉座平生晚，金尊妓吹闌。',48,'御定全唐詩/json/019.json','["日斜漳浦望，風起鄴台寒。玉座平生晚，金尊妓吹闌。", "舞餘依帳泣，歌罷向陵看。蕭索松風暮，愁煙入井闌。"]'),
('yuding-78','相和歌辭：銅雀台','劉長卿','唐','御定全唐诗','yuding','','[]','嬌愛更何日，高臺空數層。含啼映雙袖，不忍看西陵。',64,'御定全唐詩/json/019.json','["嬌愛更何日，高臺空數層。含啼映雙袖，不忍看西陵。", "漳河東流無複來，百花輦路為蒼苔。青樓月夜長寂寞，", "宮中歌舞已浮雲，空指行人往來處。"]'),
('yuding-79','相和歌辭：銅雀台','賈至','唐','御定全唐诗','yuding','','[]','日暮銅雀靜，西陵鳥雀歸。撫弦心斷絕，聽管淚霏霏。',48,'御定全唐詩/json/019.json','["日暮銅雀靜，西陵鳥雀歸。撫弦心斷絕，聽管淚霏霏。", "靈幾臨朝奠，空床卷夜衣。蒼蒼川上月，應照妾魂飛。"]'),
('yuding-80','相和歌辭：銅雀台','羅隱','唐','御定全唐诗','yuding','','[]','強歌強舞竟難勝，花落花開淚滿繒。',32,'御定全唐詩/json/019.json','["強歌強舞竟難勝，花落花開淚滿繒。", "只合當年伴君死，免教憔悴望西陵。"]'),
('yuding-81','相和歌辭：銅雀台','薛能','唐','御定全唐诗','yuding','','[]','魏帝當時銅雀台，黃花深映棘叢開。',32,'御定全唐詩/json/019.json','["魏帝當時銅雀台，黃花深映棘叢開。", "人生富貴須回首，此地豈無歌舞來。"]'),
('yuding-82','相和歌辭：銅雀台','張氏琰','唐','御定全唐诗','yuding','','[]','君王冥寞不可見，銅雀歌舞空裴回。西陵嘖嘖悲宿鳥，',24,'御定全唐詩/json/019.json','["君王冥寞不可見，銅雀歌舞空裴回。西陵嘖嘖悲宿鳥，"]'),
('yuding-83','相和歌辭：銅雀台','梁氏瓊','唐','御定全唐诗','yuding','','[]','歌扇向陵開，齊行奠玉杯。舞時飛燕列，夢裏片雲來。',48,'御定全唐詩/json/019.json','["歌扇向陵開，齊行奠玉杯。舞時飛燕列，夢裏片雲來。", "月色空餘恨，松聲暮更哀。誰憐未死妾，掩袂下銅台。"]'),
('yuding-84','相和歌辭：銅雀妓','王勃','唐','御定全唐诗','yuding','','[]','妾本深宮妓，曾城閉九重。君王歡愛盡，歌舞為誰容。',96,'御定全唐詩/json/019.json','["妾本深宮妓，曾城閉九重。君王歡愛盡，歌舞為誰容。", "錦衾不復襞，羅衣誰再縫。高臺西北望，流涕向青松。", "金鳳鄰銅雀，漳河望鄴城。君王無處所，台榭若平生。", "舞筵紛可就，歌梁儼未傾。西陵松檟冷，誰見綺羅情。"]'),
('yuding-85','相和歌辭：銅雀妓','沈佺期','唐','御定全唐诗','yuding','','[]','昔年分鼎地，今日望陵台。一旦雄圖盡，千秋遺令開。',48,'御定全唐詩/json/019.json','["昔年分鼎地，今日望陵台。一旦雄圖盡，千秋遺令開。", "綺羅君不見，歌舞妾空來。恩共漳河水，東流無重回。"]'),
('yuding-86','相和歌辭：銅雀妓','喬知之','唐','御定全唐诗','yuding','','[]','金閣惜分香，鉛華不重妝。空餘歌舞地，猶是為君王。',48,'御定全唐詩/json/019.json','["金閣惜分香，鉛華不重妝。空餘歌舞地，猶是為君王。", "哀弦調已絕，豔曲不須長。共看西陵暮，秋煙生白楊。"]'),
('yuding-87','相和歌辭：銅雀妓','王適','唐','御定全唐诗','yuding','','[]','日暮銅雀迥，幽聲玉座清。蕭森松柏望，委郁綺羅情。',36,'御定全唐詩/json/019.json','["日暮銅雀迥，幽聲玉座清。蕭森松柏望，委郁綺羅情。", "君恩不再重，妾舞為誰輕。"]'),
('yuding-88','相和歌辭：銅雀妓','歐陽詹','唐','御定全唐诗','yuding','','[]','蕭條登古台，回首黃金屋。落葉不歸林，高陵永為穀。',48,'御定全唐詩/json/019.json','["蕭條登古台，回首黃金屋。落葉不歸林，高陵永為穀。", "妝容徒自麗，舞態閱誰目。惆悵繐帷前，歌聲苦於哭。"]'),
('yuding-89','相和歌辭：銅雀妓','袁暉','唐','御定全唐诗','yuding','','[]','君愛本相饒，從來事舞腰。那堪攀玉座，腸斷望陵朝。',48,'御定全唐詩/json/019.json','["君愛本相饒，從來事舞腰。那堪攀玉座，腸斷望陵朝。", "怨著情無主，哀凝曲不調。況臨松日暮，悲吹坐蕭蕭。"]'),
('yuding-90','相和歌辭：銅雀妓','劉商','唐','御定全唐诗','yuding','','[]','魏主矜蛾眉，美人美于玉。高臺無晝夜，歌舞竟未足。',132,'御定全唐詩/json/019.json','["魏主矜蛾眉，美人美于玉。高臺無晝夜，歌舞竟未足。", "盛色如轉圜，夕陽落深谷。仍令身歿後，尚足平生欲。", "紅粉橫淚痕，調弦空向屋。舉頭君不在，唯見西陵木。", "玉輦豈再來，嬌鬟為誰綠。那堪秋風裏，更舞陽春曲。", "曲終情不勝，闌幹向西哭。台邊生野草，來去罥羅縠。", "況複陵寢間，雙雙見麋鹿。"]'),
('yuding-91','相和歌辭：銅雀妓','李賀','唐','御定全唐诗','yuding','','[]','佳人一壺酒，秋容滿千里。石馬臥新煙，憂來何所似。',48,'御定全唐詩/json/019.json','["佳人一壺酒，秋容滿千里。石馬臥新煙，憂來何所似。", "歌聲且潛弄，陵樹風自起。長裾壓高臺，淚眼看花機。"]'),
('yuding-92','相和歌辭：銅雀妓','吳燭','唐','御定全唐诗','yuding','','[]','秋色西陵滿綠蕪，繁弦急管強歡娛。',32,'御定全唐詩/json/019.json','["秋色西陵滿綠蕪，繁弦急管強歡娛。", "長舒羅袖不成舞，卻向風前承淚珠。"]'),
('yuding-93','相和歌辭：銅雀妓','朱光弼','唐','御定全唐诗','yuding','','[]','魏王銅雀妓，日暮管弦清。一見西陵樹，悲心舞不成。',24,'御定全唐詩/json/019.json','["魏王銅雀妓，日暮管弦清。一見西陵樹，悲心舞不成。"]');
